INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (109, 3, 'На рынке (торг)', 'Ситуация: на рынке (торг).', '[{"speaker": "א", "text_he": "שלום, אני צריך עזרה בנושא של На рынке (торг).", "text_ru": "Здравствуйте, мне нужна помощь по теме: На рынке (торг)."}, {"speaker": "ב", "text_he": "בטח, אני כאן לעזור. ספר לי מה אתה צריך.", "text_ru": "Конечно, я здесь помочь. Расскажите, что нужно."}, {"speaker": "א", "text_he": "אני רוצה לברר כמה דברים.", "text_ru": "Я хочу уточнить несколько вещей."}, {"speaker": "ב", "text_he": "בבקשה, שאל מה שתרצה.", "text_ru": "Пожалуйста, спрашивайте."}, {"speaker": "א", "text_he": "מה התהליך? כמה זמן זה לוקח?", "text_ru": "Какова процедура? Сколько времени это занимает?"}, {"speaker": "ב", "text_he": "התהליך פשוט. זה לוקח כשעה.", "text_ru": "Процедура простая. Занимает около часа."}, {"speaker": "א", "text_he": "מצוין. אפשר להתחיל עכשיו?", "text_ru": "Отлично. Можно начать сейчас?"}, {"speaker": "ב", "text_he": "כן, בוא נתחיל.", "text_ru": "Да, давайте начнём."}]', '[{"word": "עזרה", "translation": "помощь", "transliteration": "эзрА"}, {"word": "תהליך", "translation": "процесс", "transliteration": "таhалИх"}, {"word": "לברר", "translation": "уточнить", "transliteration": "леварЕр"}]', NULL);
