INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (113, 3, 'Жалоба в магазине', 'Ситуация: жалоба в магазине.', '[{"speaker": "א", "text_he": "שלום, אני צריך עזרה בנושא של Жалоба в магазине.", "text_ru": "Здравствуйте, мне нужна помощь по теме: Жалоба в магазине."}, {"speaker": "ב", "text_he": "בטח, אני כאן לעזור. ספר לי מה אתה צריך.", "text_ru": "Конечно, я здесь помочь. Расскажите, что нужно."}, {"speaker": "א", "text_he": "אני רוצה לברר כמה דברים.", "text_ru": "Я хочу уточнить несколько вещей."}, {"speaker": "ב", "text_he": "בבקשה, שאל מה שתרצה.", "text_ru": "Пожалуйста, спрашивайте."}, {"speaker": "א", "text_he": "מה התהליך? כמה זמן זה לוקח?", "text_ru": "Какова процедура? Сколько времени это занимает?"}, {"speaker": "ב", "text_he": "התהליך פשוט. זה לוקח כשעה.", "text_ru": "Процедура простая. Занимает около часа."}, {"speaker": "א", "text_he": "מצוין. אפשר להתחיל עכשיו?", "text_ru": "Отлично. Можно начать сейчас?"}, {"speaker": "ב", "text_he": "כן, בוא נתחיל.", "text_ru": "Да, давайте начнём."}]', '[{"word": "עזרה", "translation": "помощь", "transliteration": "эзрА"}, {"word": "תהליך", "translation": "процесс", "transliteration": "таhалИх"}, {"word": "לברר", "translation": "уточнить", "transliteration": "леварЕр"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (54, 6, 'Литературный анализ: обсуждение романа', 'Вы участвуете в литературном клубе, обсуждая роман Амоса Оза «Повесть о любви и тьме».', '[{"is_user": false, "speaker": "א", "text_he": "הספר שבחרנו החודש הוא \"סיפור על אהבה וחושך\" של עמוס עוז. זהו יצירה אוטוביוגרפית שמשלבת סיפור אישי עם ההיסטוריה הלאומית. מה עמדתכם על הרב-קוליות הנרטיבית ביצירה?", "text_ru": "Книга, которую мы выбрали на этот месяц, — «Повесть о любви и тьме» Амоса Оза. Это автобиографическое произведение, сочетающее личную историю с национальной. Каково ваше мнение о повествовательной полифонии в произведении?", "speaker_name": "Ведущая клуба"}, {"is_user": true, "options": ["הספר מאוד יפה.", "אני אהבתי את הסיפור על הילדות.", "מה שמדהים ברומן הזה הוא המיומנות שבה עוז שוזר את האינטימי עם ההיסטורי. קולו של הילד הנזכר בירושלים של שלהי המנדט יוצר טקסט רב-שכבתי, שבו הזיכרון הסובייקטיבי הופך לכלי של הכרה היסטורית."], "speaker": "ב", "text_he": "מה שמדהים ברומן הזה הוא המיומנות שבה עוז שוזר את האינטימי עם ההיסטורי. קולו של הילד הנזכר בירושלים של שלהי המנדט יוצר טקסט רב-שכבתי, שבו הזיכרון הסובייקטיבי הופך לכלי של הכרה היסטורית.", "text_ru": "Что поражает в этом романе — это мастерство, с которым Оз переплетает интимное с историческим. Голос ребёнка, вспоминающего Иерусалим конца Мандата, создаёт многослойный текст, где субъективная память становится инструментом исторического познания.", "speaker_name": "Вы", "correct_option": 2}, {"is_user": false, "speaker": "א", "text_he": "יפה מאוד. ומה לגבי הדמות של האם? ביקורת ספרותית טענה שהטרגדיה שלה מסמלת את הפער בין החלום הציוני לבין המציאות. האם אתם מסכימים עם הקריאה הזו?", "text_ru": "Прекрасно. А что насчёт образа матери? Литературная критика утверждала, что её трагедия символизирует разрыв между сионистской мечтой и реальностью. Вы согласны с такой интерпретацией?", "speaker_name": "Ведущая клуба"}, {"is_user": true, "options": ["אני מסכים לגמרי.", "אני לא חושב שהאם דמות חשובה.", "זו פרשנות משכנעת, אך הייתי מרחיב אותה. האם אינה רק אלגוריה של אכזבה לאומית. היא מגלמת קונפליקט אוניברסלי בין עולמו הפנימי של האינטלקטואל לבין אכזריות המציאות. העידון האירופי שלה מתנפץ אל מול קשיחותה של המדינה הצעירה."], "speaker": "ב", "text_he": "זו פרשנות משכנעת, אך הייתי מרחיב אותה. האם אינה רק אלגוריה של אכזבה לאומית. היא מגלמת קונפליקט אוניברסלי בין עולמו הפנימי של האינטלקטואל לבין אכזריות המציאות. העידון האירופי שלה מתנפץ אל מול קשיחותה של המדינה הצעירה.", "text_ru": "Это убедительная интерпретация, но я бы её расширил. Мать — это не только аллегория национального разочарования. Она воплощает универсальный конфликт между внутренним миром интеллектуала и жестокостью реальности. Её европейская утончённость разбивается о суровость молодого государства.", "speaker_name": "Вы", "correct_option": 2}, {"is_user": false, "speaker": "א", "text_he": "ניתוח מעולה. עוז עצמו אמר בראיון שהכתיבה הייתה ניסיון להבין את מה שלעולם לא ניתן להבנה מלאה. יש בכך משהו סיזיפי ויחד עם זה — נחמה.", "text_ru": "Превосходный анализ. Сам Оз говорил в интервью, что писательство было попыткой понять то, что никогда невозможно понять до конца. В этом есть нечто сизифово и в то же время — утешение.", "speaker_name": "Ведущая клуба"}, {"is_user": true, "options": ["בדיוק. ובפרדוקס הזה, אולי, טמון מהותה של כל הספרות — השאיפה לתת שפה לבלתי-ניתן-לביטוי, מתוך ידיעה מראש שהמשימה בלתי-אפשרית, אך מבלי לוותר עליה.", "הספר הזה שינה את החיים שלי.", "אני רוצה לקרוא עוד ספרים של עוז."], "speaker": "ב", "text_he": "בדיוק. ובפרדוקס הזה, אולי, טמון מהותה של כל הספרות — השאיפה לתת שפה לבלתי-ניתן-לביטוי, מתוך ידיעה מראש שהמשימה בלתי-אפשרית, אך מבלי לוותר עליה.", "text_ru": "Именно. И в этом парадоксе, быть может, заключена суть всей литературы — стремление дать язык невыразимому, зная заранее, что задача невыполнима, но не отказываясь от неё.", "speaker_name": "Вы", "correct_option": 0}]', '[{"he": "רב-קוליות נרטיבית", "ru": "повествовательная полифония", "translit": "рав-колийУт наратИвит"}, {"he": "רב-שכבתי", "ru": "многослойный", "translit": "рав-шихватИ"}, {"he": "פרשנות", "ru": "интерпретация", "translit": "паршанУт"}, {"he": "אלגוריה", "ru": "аллегория", "translit": "алегОрия"}, {"he": "בלתי-ניתן-לביטוי", "ru": "невыразимое", "translit": "бильтИ-нитАн-лебитУй"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (114, 3, 'В спортзале', 'Ситуация: в спортзале.', '[{"speaker": "א", "text_he": "שלום, אני צריך עזרה בנושא של В спортзале.", "text_ru": "Здравствуйте, мне нужна помощь по теме: В спортзале."}, {"speaker": "ב", "text_he": "בטח, אני כאן לעזור. ספר לי מה אתה צריך.", "text_ru": "Конечно, я здесь помочь. Расскажите, что нужно."}, {"speaker": "א", "text_he": "אני רוצה לברר כמה דברים.", "text_ru": "Я хочу уточнить несколько вещей."}, {"speaker": "ב", "text_he": "בבקשה, שאל מה שתרצה.", "text_ru": "Пожалуйста, спрашивайте."}, {"speaker": "א", "text_he": "מה התהליך? כמה זמן זה לוקח?", "text_ru": "Какова процедура? Сколько времени это занимает?"}, {"speaker": "ב", "text_he": "התהליך פשוט. זה לוקח כשעה.", "text_ru": "Процедура простая. Занимает около часа."}, {"speaker": "א", "text_he": "מצוין. אפשר להתחיל עכשיו?", "text_ru": "Отлично. Можно начать сейчас?"}, {"speaker": "ב", "text_he": "כן, בוא נתחיל.", "text_ru": "Да, давайте начнём."}]', '[{"word": "עזרה", "translation": "помощь", "transliteration": "эзрА"}, {"word": "תהליך", "translation": "процесс", "transliteration": "таhалИх"}, {"word": "לברר", "translation": "уточнить", "transliteration": "леварЕр"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (115, 3, 'На дне рождения', 'Ситуация: на дне рождения.', '[{"speaker": "א", "text_he": "שלום, אני צריך עזרה בנושא של На дне рождения.", "text_ru": "Здравствуйте, мне нужна помощь по теме: На дне рождения."}, {"speaker": "ב", "text_he": "בטח, אני כאן לעזור. ספר לי מה אתה צריך.", "text_ru": "Конечно, я здесь помочь. Расскажите, что нужно."}, {"speaker": "א", "text_he": "אני רוצה לברר כמה דברים.", "text_ru": "Я хочу уточнить несколько вещей."}, {"speaker": "ב", "text_he": "בבקשה, שאל מה שתרצה.", "text_ru": "Пожалуйста, спрашивайте."}, {"speaker": "א", "text_he": "מה התהליך? כמה זמן זה לוקח?", "text_ru": "Какова процедура? Сколько времени это занимает?"}, {"speaker": "ב", "text_he": "התהליך פשוט. זה לוקח כשעה.", "text_ru": "Процедура простая. Занимает около часа."}, {"speaker": "א", "text_he": "מצוין. אפשר להתחיל עכשיו?", "text_ru": "Отлично. Можно начать сейчас?"}, {"speaker": "ב", "text_he": "כן, בוא נתחיל.", "text_ru": "Да, давайте начнём."}]', '[{"word": "עזרה", "translation": "помощь", "transliteration": "эзрА"}, {"word": "תהליך", "translation": "процесс", "transliteration": "таhалИх"}, {"word": "לברר", "translation": "уточнить", "transliteration": "леварЕр"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (116, 4, 'У нотариуса', 'Оформление юридического документа у нотариуса.', '[{"speaker": "נוטריון", "text_he": "שלום, מה אני יכול לעשות בשבילכם?", "text_ru": "Здравствуйте, что я могу для вас сделать?"}, {"speaker": "לקוח", "text_he": "אנחנו צריכים לאמת חתימות על חוזה.", "text_ru": "Нам нужно заверить подписи на договоре."}, {"speaker": "נוטריון", "text_he": "הביאו תעודות זהות?", "text_ru": "Вы принесли удостоверения?"}, {"speaker": "לקוח", "text_he": "כן, הנה שני התעודות.", "text_ru": "Да, вот оба удостоверения."}, {"speaker": "נוטריון", "text_he": "אני צריך לקרוא את החוזה ולוודא שהכול תקין.", "text_ru": "Мне нужно прочитать договор и убедиться, что всё в порядке."}, {"speaker": "לקוח", "text_he": "כמה זה עולה?", "text_ru": "Сколько это стоит?"}, {"speaker": "נוטריון", "text_he": "האימות עולה שלוש מאות שקלים.", "text_ru": "Заверение стоит триста шекелей."}, {"speaker": "לקוח", "text_he": "בסדר. נוכל לחתום כאן?", "text_ru": "Хорошо. Мы можем подписать здесь?"}, {"speaker": "נוטריון", "text_he": "כן, חתמו כאן ואני אאשר.", "text_ru": "Да, подпишите здесь и я заверю."}]', '[{"word": "נוטריון", "translation": "нотариус", "transliteration": "нотарьОн"}, {"word": "אימות", "translation": "заверение", "transliteration": "имУт"}, {"word": "חתימות", "translation": "подписи", "transliteration": "хатимОт"}, {"word": "חוזה", "translation": "договор", "transliteration": "хозЕ"}, {"word": "תקין", "translation": "в порядке", "transliteration": "такИн"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (117, 4, 'Страховой случай', 'Ситуация: страховой случай на уровне B2.', '[{"speaker": "א", "text_he": "שלום, אני שמח להיפגש.", "text_ru": "Здравствуйте, рад встрече."}, {"speaker": "ב", "text_he": "גם אני. בוא נתחיל לדון בנושא.", "text_ru": "Я тоже. Давайте начнём обсуждение."}, {"speaker": "א", "text_he": "לדעתי, הנושא הזה מורכב מאוד.", "text_ru": "По-моему, эта тема очень сложная."}, {"speaker": "ב", "text_he": "אני מסכים. יש היבטים רבים שצריך לשקול.", "text_ru": "Согласен. Есть много аспектов, которые нужно учесть."}, {"speaker": "א", "text_he": "מה דעתך על הגישה החדשה?", "text_ru": "Что ты думаешь о новом подходе?"}, {"speaker": "ב", "text_he": "יש בה יתרונות וחסרונות. צריך לבחון.", "text_ru": "Есть плюсы и минусы. Нужно изучить."}, {"speaker": "א", "text_he": "אולי נקבע פגישת המשך?", "text_ru": "Может, назначим ещё одну встречу?"}, {"speaker": "ב", "text_he": "בהחלט. אני פנוי בשבוע הבא.", "text_ru": "Безусловно. Я свободен на следующей неделе."}, {"speaker": "א", "text_he": "מצוין. אני אשלח לך הזמנה.", "text_ru": "Отлично. Я пришлю тебе приглашение."}, {"speaker": "ב", "text_he": "תודה. היה דיון פורה.", "text_ru": "Спасибо. Была продуктивная дискуссия."}]', '[{"word": "מורכב", "translation": "сложный", "transliteration": "муркАв"}, {"word": "היבטים", "translation": "аспекты", "transliteration": "hейбетИм"}, {"word": "גישה", "translation": "подход", "transliteration": "гишА"}, {"word": "יתרונות", "translation": "преимущества", "transliteration": "итронОт"}, {"word": "פורה", "translation": "продуктивный", "transliteration": "порЕ"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (50, 5, 'Академические дебаты: искусственный интеллект', 'Вы участвуете в университетских дебатах о влиянии искусственного интеллекта на рынок труда.', '[{"is_user": false, "speaker": "א", "text_he": "נפתח את הדיון. לפי מחקרים עדכניים, עד שנת 2035 בינה מלאכותית תחליף כשלושים אחוז מהמשרות הקיימות. איך אתם מתייחסים לתחזית הזו?", "text_ru": "Откроем дискуссию. По последним исследованиям, к 2035 году искусственный интеллект заменит около тридцати процентов существующих рабочих мест. Как вы относитесь к этому прогнозу?", "speaker_name": "Профессор"}, {"is_user": true, "options": ["לדעתי, הנתון הזה משקף רק חלק מהתמונה. חשוב להבחין בין אוטומציה של משימות שגרתיות לבין החלפה מלאה של מקצועות. טכנולוגיה, ככלל, יוצרת תחומי תעסוקה חדשים.", "אני מסכים עם הנתונים.", "אני חושב שבינה מלאכותית לא תחליף אנשים."], "speaker": "ב", "text_he": "לדעתי, הנתון הזה משקף רק חלק מהתמונה. חשוב להבחין בין אוטומציה של משימות שגרתיות לבין החלפה מלאה של מקצועות. טכנולוגיה, ככלל, יוצרת תחומי תעסוקה חדשים.", "text_ru": "Я полагаю, что эта статистика отражает лишь часть картины. Важно разграничивать между автоматизацией рутинных задач и полной заменой профессий. Технология, как правило, создаёт новые области занятости.", "speaker_name": "Вы", "correct_option": 0}, {"is_user": false, "speaker": "א", "text_he": "נקודה מעניינת. אבל האם מערכת החינוך מסוגלת להתאים את עצמה מהר מספיק? ההיסטוריה מלמדת שמהפכות טכנולוגיות יוצרות פערים חברתיים משמעותיים בטווח הקצר.", "text_ru": "Интересный аргумент. Но способна ли система образования адаптироваться достаточно быстро? История учит, что технологические революции создают значительное социальное расслоение в краткосрочной перспективе.", "speaker_name": "Профессор"}, {"is_user": true, "options": ["אני לא בטוח מה הפתרון.", "צריך לאסור על בינה מלאכותית.", "זו שאלת מפתח. אני טוען שיש ליישם מדיניות הסבה מקצועית ברמה הממלכתית. מדינות שמשקיעות בלמידה לאורך החיים מתמודדות טוב יותר עם מעברים טכנולוגיים."], "speaker": "ב", "text_he": "זו שאלת מפתח. אני טוען שיש ליישם מדיניות הסבה מקצועית ברמה הממלכתית. מדינות שמשקיעות בלמידה לאורך החיים מתמודדות טוב יותר עם מעברים טכנולוגיים.", "text_ru": "Это ключевой вопрос. Я утверждаю, что необходимо внедрить политику переквалификации на государственном уровне. Страны, которые инвестируют в непрерывное образование, лучше справляются с технологическими переходами.", "speaker_name": "Вы", "correct_option": 2}, {"is_user": false, "speaker": "א", "text_he": "טיעון מבוסס היטב. ואכן, המודל הסקנדינבי מהווה דוגמה חיובית בהקשר הזה.", "text_ru": "Хорошо обоснованный аргумент. И действительно, скандинавская модель является положительным примером в этом контексте.", "speaker_name": "Профессор"}]', '[{"he": "בינה מלאכותית", "ru": "искусственный интеллект", "translit": "бинА мелахутИт"}, {"he": "תחזית", "ru": "прогноз", "translit": "тахазИт"}, {"he": "הסבה מקצועית", "ru": "переквалификация", "translit": "hасбА микцоИт"}, {"he": "פערים חברתיים", "ru": "социальное расслоение", "translit": "пеарИм хевратиИм"}, {"he": "למידה לאורך החיים", "ru": "непрерывное образование", "translit": "лемидА леОрех hахаИм"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (118, 4, 'Собеседование (продвинутое)', 'Ситуация: собеседование (продвинутое) на уровне B2.', '[{"speaker": "א", "text_he": "שלום, אני שמח להיפגש.", "text_ru": "Здравствуйте, рад встрече."}, {"speaker": "ב", "text_he": "גם אני. בוא נתחיל לדון בנושא.", "text_ru": "Я тоже. Давайте начнём обсуждение."}, {"speaker": "א", "text_he": "לדעתי, הנושא הזה מורכב מאוד.", "text_ru": "По-моему, эта тема очень сложная."}, {"speaker": "ב", "text_he": "אני מסכים. יש היבטים רבים שצריך לשקול.", "text_ru": "Согласен. Есть много аспектов, которые нужно учесть."}, {"speaker": "א", "text_he": "מה דעתך על הגישה החדשה?", "text_ru": "Что ты думаешь о новом подходе?"}, {"speaker": "ב", "text_he": "יש בה יתרונות וחסרונות. צריך לבחון.", "text_ru": "Есть плюсы и минусы. Нужно изучить."}, {"speaker": "א", "text_he": "אולי נקבע פגישת המשך?", "text_ru": "Может, назначим ещё одну встречу?"}, {"speaker": "ב", "text_he": "בהחלט. אני פנוי בשבוע הבא.", "text_ru": "Безусловно. Я свободен на следующей неделе."}, {"speaker": "א", "text_he": "מצוין. אני אשלח לך הזמנה.", "text_ru": "Отлично. Я пришлю тебе приглашение."}, {"speaker": "ב", "text_he": "תודה. היה דיון פורה.", "text_ru": "Спасибо. Была продуктивная дискуссия."}]', '[{"word": "מורכב", "translation": "сложный", "transliteration": "муркАв"}, {"word": "היבטים", "translation": "аспекты", "transliteration": "hейбетИм"}, {"word": "גישה", "translation": "подход", "transliteration": "гишА"}, {"word": "יתרונות", "translation": "преимущества", "transliteration": "итронОт"}, {"word": "פורה", "translation": "продуктивный", "transliteration": "порЕ"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (119, 4, 'Деловые переговоры', 'Ситуация: деловые переговоры на уровне B2.', '[{"speaker": "א", "text_he": "שלום, אני שמח להיפגש.", "text_ru": "Здравствуйте, рад встрече."}, {"speaker": "ב", "text_he": "גם אני. בוא נתחיל לדון בנושא.", "text_ru": "Я тоже. Давайте начнём обсуждение."}, {"speaker": "א", "text_he": "לדעתי, הנושא הזה מורכב מאוד.", "text_ru": "По-моему, эта тема очень сложная."}, {"speaker": "ב", "text_he": "אני מסכים. יש היבטים רבים שצריך לשקול.", "text_ru": "Согласен. Есть много аспектов, которые нужно учесть."}, {"speaker": "א", "text_he": "מה דעתך על הגישה החדשה?", "text_ru": "Что ты думаешь о новом подходе?"}, {"speaker": "ב", "text_he": "יש בה יתרונות וחסרונות. צריך לבחון.", "text_ru": "Есть плюсы и минусы. Нужно изучить."}, {"speaker": "א", "text_he": "אולי נקבע פגישת המשך?", "text_ru": "Может, назначим ещё одну встречу?"}, {"speaker": "ב", "text_he": "בהחלט. אני פנוי בשבוע הבא.", "text_ru": "Безусловно. Я свободен на следующей неделе."}, {"speaker": "א", "text_he": "מצוין. אני אשלח לך הזמנה.", "text_ru": "Отлично. Я пришлю тебе приглашение."}, {"speaker": "ב", "text_he": "תודה. היה דיון פורה.", "text_ru": "Спасибо. Была продуктивная дискуссия."}]', '[{"word": "מורכב", "translation": "сложный", "transliteration": "муркАв"}, {"word": "היבטים", "translation": "аспекты", "transliteration": "hейбетИм"}, {"word": "גישה", "translation": "подход", "transliteration": "гишА"}, {"word": "יתרונות", "translation": "преимущества", "transliteration": "итронОт"}, {"word": "פורה", "translation": "продуктивный", "transliteration": "порЕ"}]', NULL);
