INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (52, 5, 'Философская дискуссия: свобода и ответственность', 'Вы участвуете в философском кружке, обсуждающем свободу воли и нравственную ответственность.', '[{"is_user": false, "speaker": "א", "text_he": "הנושא שלנו הערב — חופש הרצון והאחריות המוסרית. האם בני האדם באמת חופשיים לבחור, או שכל מעשינו נקבעים מראש על ידי גורמים ביולוגיים וסביבתיים?", "text_ru": "Наша тема сегодня — свобода воли и нравственная ответственность. Действительно ли люди свободны в выборе, или все наши действия предопределены биологическими и средовыми факторами?", "speaker_name": "Философ"}, {"is_user": true, "options": ["אני נוקט בעמדה של קומפטיביליזם. גם אם מעשינו מותנים בקשרי סיבה ותוצאה, אנחנו עדיין נושאים באחריות, שכן אנו פועלים בהתאם לרצונותינו ולאמונותינו.", "אין לנו בחירה חופשית.", "אני מאמין בבחירה חופשית מוחלטת."], "speaker": "ב", "text_he": "אני נוקט בעמדה של קומפטיביליזם. גם אם מעשינו מותנים בקשרי סיבה ותוצאה, אנחנו עדיין נושאים באחריות, שכן אנו פועלים בהתאם לרצונותינו ולאמונותינו.", "text_ru": "Я придерживаюсь позиции компатибилизма. Даже если наши поступки обусловлены причинно-следственными связями, мы всё равно несём ответственность, поскольку действуем в соответствии со своими желаниями и убеждениями.", "speaker_name": "Вы", "correct_option": 0}, {"is_user": false, "speaker": "א", "text_he": "אבל אם הרצונות עצמם נקבעים על ידי גנטיקה וחינוך — האם זו באמת חירות? קאנט טען שחופש אמיתי מותנה ביכולת לפעול לפי חוק מוסרי אוניברסלי.", "text_ru": "Но если сами желания определяются генетикой и воспитанием — действительно ли это свобода? Кант утверждал, что истинная свобода обусловлена способностью действовать по универсальному нравственному закону.", "speaker_name": "Философ"}, {"is_user": true, "options": ["קאנט צדק.", "נכון, וכאן אנחנו חוזרים להבחנה בין חירות שלילית לחיובית. אני מוסיף שלמעשה כל מערכת אתית מניחה מידה מסוימת של חופש פעולה — אחרת עצם מושג המוסר מאבד את משמעותו.", "אני לא מסכים עם קאנט."], "speaker": "ב", "text_he": "נכון, וכאן אנחנו חוזרים להבחנה בין חירות שלילית לחיובית. אני מוסיף שלמעשה כל מערכת אתית מניחה מידה מסוימת של חופש פעולה — אחרת עצם מושג המוסר מאבד את משמעותו.", "text_ru": "Верно, и здесь мы возвращаемся к различию между отрицательной и положительной свободой. Я бы добавил, что практически любая этическая система предполагает некоторую степень свободы действий — иначе само понятие морали теряет смысл.", "speaker_name": "Вы", "correct_option": 1}, {"is_user": false, "speaker": "א", "text_he": "טיעון מבריק. ואכן, הפרדוקס הזה מלווה את הפילוסופיה המערבית מאז יוון העתיקה. אולי הערך האמיתי של השאלה הוא בעצם ההתלבטות.", "text_ru": "Блестящий аргумент. И действительно, этот парадокс сопровождает западную философию с времён Древней Греции. Быть может, истинная ценность этого вопроса — в самом размышлении.", "speaker_name": "Философ"}]', '[{"he": "חופש הרצון", "ru": "свобода воли", "translit": "хОфеш hарацОн"}, {"he": "אחריות מוסרית", "ru": "нравственная ответственность", "translit": "ахрайУт мусарИт"}, {"he": "סיבה ותוצאה", "ru": "причина и следствие", "translit": "сибА ветоцаА"}, {"he": "חירות", "ru": "свобода (абстр.)", "translit": "херУт"}, {"he": "פרדוקס", "ru": "парадокс", "translit": "парадОкс"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (122, 4, 'Судебное заседание', 'Ситуация: судебное заседание на уровне B2.', '[{"speaker": "א", "text_he": "שלום, אני שמח להיפגש.", "text_ru": "Здравствуйте, рад встрече."}, {"speaker": "ב", "text_he": "גם אני. בוא נתחיל לדון בנושא.", "text_ru": "Я тоже. Давайте начнём обсуждение."}, {"speaker": "א", "text_he": "לדעתי, הנושא הזה מורכב מאוד.", "text_ru": "По-моему, эта тема очень сложная."}, {"speaker": "ב", "text_he": "אני מסכים. יש היבטים רבים שצריך לשקול.", "text_ru": "Согласен. Есть много аспектов, которые нужно учесть."}, {"speaker": "א", "text_he": "מה דעתך על הגישה החדשה?", "text_ru": "Что ты думаешь о новом подходе?"}, {"speaker": "ב", "text_he": "יש בה יתרונות וחסרונות. צריך לבחון.", "text_ru": "Есть плюсы и минусы. Нужно изучить."}, {"speaker": "א", "text_he": "אולי נקבע פגישת המשך?", "text_ru": "Может, назначим ещё одну встречу?"}, {"speaker": "ב", "text_he": "בהחלט. אני פנוי בשבוע הבא.", "text_ru": "Безусловно. Я свободен на следующей неделе."}, {"speaker": "א", "text_he": "מצוין. אני אשלח לך הזמנה.", "text_ru": "Отлично. Я пришлю тебе приглашение."}, {"speaker": "ב", "text_he": "תודה. היה דיון פורה.", "text_ru": "Спасибо. Была продуктивная дискуссия."}]', '[{"word": "מורכב", "translation": "сложный", "transliteration": "муркАв"}, {"word": "היבטים", "translation": "аспекты", "transliteration": "hейбетИм"}, {"word": "גישה", "translation": "подход", "transliteration": "гишА"}, {"word": "יתרונות", "translation": "преимущества", "transliteration": "итронОт"}, {"word": "פורה", "translation": "продуктивный", "transliteration": "порЕ"}]', NULL);
