INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (136, 4, 'Образовательная комиссия', 'Ситуация: образовательная комиссия на уровне B2.', '[{"speaker": "א", "text_he": "שלום, אני שמח להיפגש.", "text_ru": "Здравствуйте, рад встрече."}, {"speaker": "ב", "text_he": "גם אני. בוא נתחיל לדון בנושא.", "text_ru": "Я тоже. Давайте начнём обсуждение."}, {"speaker": "א", "text_he": "לדעתי, הנושא הזה מורכב מאוד.", "text_ru": "По-моему, эта тема очень сложная."}, {"speaker": "ב", "text_he": "אני מסכים. יש היבטים רבים שצריך לשקול.", "text_ru": "Согласен. Есть много аспектов, которые нужно учесть."}, {"speaker": "א", "text_he": "מה דעתך על הגישה החדשה?", "text_ru": "Что ты думаешь о новом подходе?"}, {"speaker": "ב", "text_he": "יש בה יתרונות וחסרונות. צריך לבחון.", "text_ru": "Есть плюсы и минусы. Нужно изучить."}, {"speaker": "א", "text_he": "אולי נקבע פגישת המשך?", "text_ru": "Может, назначим ещё одну встречу?"}, {"speaker": "ב", "text_he": "בהחלט. אני פנוי בשבוע הבא.", "text_ru": "Безусловно. Я свободен на следующей неделе."}, {"speaker": "א", "text_he": "מצוין. אני אשלח לך הזמנה.", "text_ru": "Отлично. Я пришлю тебе приглашение."}, {"speaker": "ב", "text_he": "תודה. היה דיון פורה.", "text_ru": "Спасибо. Была продуктивная дискуссия."}]', '[{"word": "מורכב", "translation": "сложный", "transliteration": "муркАв"}, {"word": "היבטים", "translation": "аспекты", "transliteration": "hейбетИм"}, {"word": "גישה", "translation": "подход", "transliteration": "гишА"}, {"word": "יתרונות", "translation": "преимущества", "transliteration": "итронОт"}, {"word": "פורה", "translation": "продуктивный", "transliteration": "порЕ"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (137, 5, 'Академическая дискуссия', 'Ситуация: академическая дискуссия на уровне C1.', '[{"speaker": "א", "text_he": "שלום לכולם, אני שמח לפתוח את הדיון.", "text_ru": "Здравствуйте все, рад открыть дискуссию."}, {"speaker": "ב", "text_he": "תודה. הנושא שלפנינו חשוב ביותר.", "text_ru": "Спасибо. Тема перед нами крайне важна."}, {"speaker": "א", "text_he": "אני רוצה להציג את עמדתי בנושא.", "text_ru": "Хочу представить свою позицию по вопросу."}, {"speaker": "ב", "text_he": "אני מקשיב. אנא המשך.", "text_ru": "Слушаю. Пожалуйста, продолжайте."}, {"speaker": "א", "text_he": "לדעתי, יש לנקוט גישה מאוזנת.", "text_ru": "По-моему, нужен сбалансированный подход."}, {"speaker": "ב", "text_he": "אני מבין את נקודת המבט שלך, אבל יש שיקולים נוספים.", "text_ru": "Понимаю вашу точку зрения, но есть дополнительные соображения."}, {"speaker": "א", "text_he": "אילו שיקולים?", "text_ru": "Какие соображения?"}, {"speaker": "ב", "text_he": "ראשית, ההיבט הכלכלי. שנית, ההשפעה החברתית.", "text_ru": "Во-первых, экономический аспект. Во-вторых, социальное влияние."}, {"speaker": "א", "text_he": "נקודות חשובות. אציע פשרה.", "text_ru": "Важные моменты. Предложу компромисс."}, {"speaker": "ב", "text_he": "אני מוכן לשמוע. בואו נמצא פתרון משותף.", "text_ru": "Готов выслушать. Давайте найдём общее решение."}]', '[{"word": "דיון", "translation": "дискуссия", "transliteration": "диюн"}, {"word": "עמדה", "translation": "позиция", "transliteration": "эмдА"}, {"word": "גישה", "translation": "подход", "transliteration": "гишА"}, {"word": "שיקולים", "translation": "соображения", "transliteration": "шикулИм"}, {"word": "פשרה", "translation": "компромисс", "transliteration": "пшарА"}]', NULL);
