INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (179, 6, 'Архивное исследование', 'Ситуация: архивное исследование на уровне C2.', '[{"speaker": "א", "text_he": "שלום לכולם, אני שמח לפתוח את הדיון.", "text_ru": "Здравствуйте все, рад открыть дискуссию."}, {"speaker": "ב", "text_he": "תודה. הנושא שלפנינו חשוב ביותר.", "text_ru": "Спасибо. Тема перед нами крайне важна."}, {"speaker": "א", "text_he": "אני רוצה להציג את עמדתי בנושא.", "text_ru": "Хочу представить свою позицию по вопросу."}, {"speaker": "ב", "text_he": "אני מקשיב. אנא המשך.", "text_ru": "Слушаю. Пожалуйста, продолжайте."}, {"speaker": "א", "text_he": "לדעתי, יש לנקוט גישה מאוזנת.", "text_ru": "По-моему, нужен сбалансированный подход."}, {"speaker": "ב", "text_he": "אני מבין את נקודת המבט שלך, אבל יש שיקולים נוספים.", "text_ru": "Понимаю вашу точку зрения, но есть дополнительные соображения."}, {"speaker": "א", "text_he": "אילו שיקולים?", "text_ru": "Какие соображения?"}, {"speaker": "ב", "text_he": "ראשית, ההיבט הכלכלי. שנית, ההשפעה החברתית.", "text_ru": "Во-первых, экономический аспект. Во-вторых, социальное влияние."}, {"speaker": "א", "text_he": "נקודות חשובות. אציע פשרה.", "text_ru": "Важные моменты. Предложу компромисс."}, {"speaker": "ב", "text_he": "אני מוכן לשמוע. בואו נמצא פתרון משותף.", "text_ru": "Готов выслушать. Давайте найдём общее решение."}]', '[{"word": "דיון", "translation": "дискуссия", "transliteration": "диюн"}, {"word": "עמדה", "translation": "позиция", "transliteration": "эмдА"}, {"word": "גישה", "translation": "подход", "transliteration": "гишА"}, {"word": "שיקולים", "translation": "соображения", "transliteration": "шикулИм"}, {"word": "פשרה", "translation": "компромисс", "transliteration": "пшарА"}]', NULL);
