INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (1, 1, 'В ульпане: знакомство', 'Первый день в ульпане. Познакомьтесь с другим студентом.', '[{"is_user": false, "speaker": "א", "text_he": "שלום! אני דן. מה שמך?", "text_ru": "Привет! Я Дан. Как тебя зовут?", "speaker_name": "Дан"}, {"is_user": true, "options": ["שלום! מה שלומך?", "שלום! שמי אלכס.", "שלום! אני סטודנט."], "speaker": "ב", "text_he": "שלום! שמי אלכס.", "text_ru": "Привет! Меня зовут...", "speaker_name": "Вы", "correct_option": 1}, {"is_user": false, "speaker": "א", "text_he": "נעים מאוד! מאיפה אתה?", "text_ru": "Очень приятно! Откуда ты?", "speaker_name": "Дан"}, {"is_user": true, "options": ["אני מרוסיה.", "אני לומד עברית.", "אני גר פה."], "speaker": "ב", "text_he": "אני מרוסיה.", "text_ru": "Я из России.", "speaker_name": "Вы", "correct_option": 0}, {"is_user": false, "speaker": "א", "text_he": "מגניב! גם אני חדש כאן. בהצלחה!", "text_ru": "Здорово! Я тоже тут новый. Удачи!", "speaker_name": "Дан"}]', '[{"he": "מה שמך", "ru": "как тебя зовут", "translit": "ма шимхА"}, {"he": "נעים מאוד", "ru": "очень приятно", "translit": "наИм меОд"}, {"he": "מאיפה", "ru": "откуда", "translit": "меЭйфо"}, {"he": "בהצלחה", "ru": "удачи", "translit": "беhацлахА"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (2, 1, 'В кафе: заказ', 'Вы в кафе. Закажите напиток и еду.', '[{"is_user": false, "speaker": "א", "text_he": "שלום! מה תרצה לשתות?", "text_ru": "Привет! Что хотите выпить?", "speaker_name": "Официант"}, {"is_user": true, "options": ["אני רוצה מים.", "תה, בבקשה.", "קפה, בבקשה."], "speaker": "ב", "text_he": "קפה, בבקשה.", "text_ru": "Кофе, пожалуйста.", "speaker_name": "Вы", "correct_option": 2}, {"is_user": false, "speaker": "א", "text_he": "ועוגה? יש לנו עוגת שוקולד מעולה!", "text_ru": "И пирожное? У нас отличный шоколадный торт!", "speaker_name": "Официант"}, {"is_user": true, "options": ["כמה זה עולה?", "כן, בבקשה!", "לא, תודה."], "speaker": "ב", "text_he": "כן, בבקשה!", "text_ru": "Да, пожалуйста!", "speaker_name": "Вы", "correct_option": 1}, {"is_user": false, "speaker": "א", "text_he": "בסדר! זה יהיה ארבעים שקלים.", "text_ru": "Хорошо! Это будет сорок шекелей.", "speaker_name": "Официант"}]', '[{"he": "קפה", "ru": "кофе", "translit": "кафЕ"}, {"he": "עוגה", "ru": "пирожное/торт", "translit": "угА"}, {"he": "שוקולד", "ru": "шоколад", "translit": "шоколАд"}, {"he": "שקלים", "ru": "шекели", "translit": "шкалИм"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (3, 1, 'На улице: дорога', 'Вы заблудились. Спросите дорогу у прохожего.', '[{"is_user": true, "options": ["סליחה, איך מגיעים לתחנת האוטובוס?", "סליחה, איפה השירותים?", "סליחה, מה השעה?"], "speaker": "ב", "text_he": "סליחה, איך מגיעים לתחנת האוטובוס?", "text_ru": "Извините, как пройти к автобусной остановке?", "speaker_name": "Вы", "correct_option": 0}, {"is_user": false, "speaker": "א", "text_he": "ישר, ואז שמאלה ברמזור.", "text_ru": "Прямо, потом налево на светофоре.", "speaker_name": "Прохожий"}, {"is_user": true, "options": ["תודה רבה!", "בסדר, תודה.", "סליחה, לא הבנתי."], "speaker": "ב", "text_he": "תודה רבה!", "text_ru": "Спасибо большое!", "speaker_name": "Вы", "correct_option": 0}, {"is_user": false, "speaker": "א", "text_he": "בבקשה! בהצלחה!", "text_ru": "Пожалуйста! Удачи!", "speaker_name": "Прохожий"}]', '[{"he": "תחנת האוטובוס", "ru": "автобусная остановка", "translit": "таханАт hа-отобУс"}, {"he": "ישר", "ru": "прямо", "translit": "яшАр"}, {"he": "שמאלה", "ru": "налево", "translit": "смОла"}, {"he": "רמזור", "ru": "светофор", "translit": "рамзОр"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (4, 1, 'В магазине: покупки', 'Вы в продуктовом магазине.', '[{"is_user": false, "speaker": "א", "text_he": "שלום! אפשר לעזור?", "text_ru": "Привет! Могу помочь?", "speaker_name": "Продавец"}, {"is_user": true, "options": ["לא, תודה.", "כן, כמה עולה הלחם?", "כן, איפה החלב?"], "speaker": "ב", "text_he": "כן, איפה החלב?", "text_ru": "Да, где молоко?", "speaker_name": "Вы", "correct_option": 2}, {"is_user": false, "speaker": "א", "text_he": "במקרר, בסוף המעבר.", "text_ru": "В холодильнике, в конце прохода.", "speaker_name": "Продавец"}, {"is_user": true, "options": ["אני לא מבין.", "תודה! וכמה עולה הלחם?", "תודה, להתראות!"], "speaker": "ב", "text_he": "תודה! וכמה עולה הלחם?", "text_ru": "Спасибо! А сколько стоит хлеб?", "speaker_name": "Вы", "correct_option": 1}, {"is_user": false, "speaker": "א", "text_he": "שבעה שקלים.", "text_ru": "Семь шекелей.", "speaker_name": "Продавец"}]', '[{"he": "חלב", "ru": "молоко", "translit": "халАв"}, {"he": "מקרר", "ru": "холодильник", "translit": "мекарЕр"}, {"he": "מעבר", "ru": "проход", "translit": "маавАр"}, {"he": "לחם", "ru": "хлеб", "translit": "лЕхем"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (5, 1, 'У врача: запись', 'Запишитесь на приём к врачу.', '[{"is_user": false, "speaker": "א", "text_he": "שלום, קופת חולים. במה אוכל לעזור?", "text_ru": "Здравствуйте, больничная касса. Чем могу помочь?", "speaker_name": "Регистратор"}, {"is_user": true, "options": ["מה השעה?", "אני חולה.", "אני רוצה לקבוע תור לרופא."], "speaker": "ב", "text_he": "אני רוצה לקבוע תור לרופא.", "text_ru": "Я хочу записаться к врачу.", "speaker_name": "Вы", "correct_option": 2}, {"is_user": false, "speaker": "א", "text_he": "יש תור ביום שלישי בשעה עשר. מתאים?", "text_ru": "Есть запись на вторник в 10. Подходит?", "speaker_name": "Регистратор"}, {"is_user": true, "options": ["אני לא יודע.", "לא, יש משהו אחר?", "כן, מתאים. תודה."], "speaker": "ב", "text_he": "כן, מתאים. תודה.", "text_ru": "Да, подходит. Спасибо.", "speaker_name": "Вы", "correct_option": 2}]', '[{"he": "קופת חולים", "ru": "больничная касса", "translit": "купАт холИм"}, {"he": "תור", "ru": "очередь/запись", "translit": "тор"}, {"he": "רופא", "ru": "врач", "translit": "рофЕ"}, {"he": "מתאים", "ru": "подходит", "translit": "матъИм"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (18, 3, 'На работе: совещание', 'Вы участвуете в рабочем совещании на иврите.', '[{"is_user": false, "speaker": "א", "text_he": "בוקר טוב לכולם! נתחיל את הישיבה. יש לנו כמה נושאים חשובים.", "text_ru": "Доброе утро всем! Начнём совещание. У нас несколько важных тем.", "speaker_name": "Менеджер"}, {"is_user": true, "options": ["אני מוכן.", "יש לי שאלה.", "הכנתי דו\"ח על הפרויקט."], "speaker": "ב", "text_he": "הכנתי דו\"ח על הפרויקט.", "text_ru": "Я подготовил отчёт о проекте.", "speaker_name": "Вы", "correct_option": 2}, {"is_user": false, "speaker": "א", "text_he": "מצוין! תציג בבקשה את העדכונים העיקריים.", "text_ru": "Отлично! Представь основные обновления, пожалуйста.", "speaker_name": "Менеджер"}, {"is_user": true, "options": ["הכול בסדר.", "השלמנו שמונים אחוז מהמשימות. נותרו שתי משימות.", "אנחנו צריכים יותר זמן."], "speaker": "ב", "text_he": "השלמנו שמונים אחוז מהמשימות. נותרו שתי משימות.", "text_ru": "Мы выполнили 80 процентов задач. Остались две задачи.", "speaker_name": "Вы", "correct_option": 1}, {"is_user": false, "speaker": "א", "text_he": "עבודה טובה! מתי תסיימו את המשימות הנותרות?", "text_ru": "Хорошая работа! Когда закончите оставшиеся задачи?", "speaker_name": "Менеджер"}, {"is_user": true, "options": ["בשבוע הבא.", "אני לא בטוח.", "עד סוף השבוע."], "speaker": "ב", "text_he": "עד סוף השבוע.", "text_ru": "До конца недели.", "speaker_name": "Вы", "correct_option": 2}]', '[{"he": "ישיבה", "ru": "совещание", "translit": "йешивА"}, {"he": "דו\"ח", "ru": "отчёт", "translit": "дОх"}, {"he": "משימות", "ru": "задачи", "translit": "месимОт"}, {"he": "נותרו", "ru": "остались", "translit": "нотрУ"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (6, 1, 'По телефону: звонок', 'Вы звоните другу.', '[{"is_user": true, "options": ["הלו, שלום! זה אלכס.", "שלום, מה נשמע?", "הלו?"], "speaker": "ב", "text_he": "הלו, שלום! זה אלכס.", "text_ru": "Алло, привет! Это (ваше имя).", "speaker_name": "Вы", "correct_option": 0}, {"is_user": false, "speaker": "א", "text_he": "היי! מה נשמע? לא דיברנו הרבה זמן!", "text_ru": "Привет! Как дела? Давно не разговаривали!", "speaker_name": "Друг"}, {"is_user": true, "options": ["אני עסוק.", "הכול טוב! רוצה להיפגש?", "מתי אתה פנוי?"], "speaker": "ב", "text_he": "הכול טוב! רוצה להיפגש?", "text_ru": "Всё хорошо! Хочешь встретиться?", "speaker_name": "Вы", "correct_option": 1}, {"is_user": false, "speaker": "א", "text_he": "כן, בטח! מחר בערב?", "text_ru": "Да, конечно! Завтра вечером?", "speaker_name": "Друг"}, {"is_user": true, "options": ["בסדר, נדבר.", "אני לא יכול.", "מצוין! להתראות מחר!"], "speaker": "ב", "text_he": "מצוין! להתראות מחר!", "text_ru": "Отлично! До завтра!", "speaker_name": "Вы", "correct_option": 2}]', '[{"he": "מה נשמע", "ru": "как дела", "translit": "ма нишмА"}, {"he": "להיפגש", "ru": "встретиться", "translit": "леhипагЕш"}, {"he": "מחר", "ru": "завтра", "translit": "махАр"}, {"he": "להתראות", "ru": "до свидания", "translit": "леhитраОт"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (7, 2, 'В банке: открытие счёта', 'Вы открываете счёт в израильском банке.', '[{"is_user": false, "speaker": "א", "text_he": "שלום! במה אני יכול לעזור?", "text_ru": "Здравствуйте! Чем могу помочь?", "speaker_name": "Клерк"}, {"is_user": true, "options": ["כמה הריבית?", "אני רוצה לפתוח חשבון.", "אני רוצה להפקיד כסף."], "speaker": "ב", "text_he": "אני רוצה לפתוח חשבון.", "text_ru": "Я хочу открыть счёт.", "speaker_name": "Вы", "correct_option": 1}, {"is_user": false, "speaker": "א", "text_he": "בוודאי. אני צריך את התעודת זהות שלך ואישור כתובת.", "text_ru": "Конечно. Мне нужно ваше удостоверение личности и подтверждение адреса.", "speaker_name": "Клерк"}, {"is_user": true, "options": ["רגע, אני אחפש.", "אין לי תעודת זהות.", "הנה, בבקשה. הנה הדרכון שלי."], "speaker": "ב", "text_he": "הנה, בבקשה. הנה הדרכון שלי.", "text_ru": "Вот, пожалуйста. Вот мой паспорт.", "speaker_name": "Вы", "correct_option": 2}, {"is_user": false, "speaker": "א", "text_he": "תודה. תמלא את הטופס הזה בבקשה.", "text_ru": "Спасибо. Заполните эту форму, пожалуйста.", "speaker_name": "Клерк"}]', '[{"he": "חשבון", "ru": "счёт", "translit": "хешбОн"}, {"he": "תעודת זהות", "ru": "удостоверение личности", "translit": "теудАт зеhУт"}, {"he": "דרכון", "ru": "паспорт", "translit": "даркОн"}, {"he": "טופס", "ru": "форма/бланк", "translit": "тОфес"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (8, 2, 'На почте', 'Вы отправляете посылку на почте.', '[{"is_user": false, "speaker": "א", "text_he": "שלום! מה ברצונך לשלוח?", "text_ru": "Привет! Что хотите отправить?", "speaker_name": "Работник"}, {"is_user": true, "options": ["אני רוצה לשלוח חבילה לרוסיה.", "יש לי מכתב.", "אני צריך בולים."], "speaker": "ב", "text_he": "אני רוצה לשלוח חבילה לרוסיה.", "text_ru": "Я хочу отправить посылку в Россию.", "speaker_name": "Вы", "correct_option": 0}, {"is_user": false, "speaker": "א", "text_he": "כמה שוקל החבילה?", "text_ru": "Сколько весит посылка?", "speaker_name": "Работник"}, {"is_user": true, "options": ["זה לא כבד.", "אני לא יודע.", "בערך שני קילו."], "speaker": "ב", "text_he": "בערך שני קילו.", "text_ru": "Около двух килограммов.", "speaker_name": "Вы", "correct_option": 2}, {"is_user": false, "speaker": "א", "text_he": "זה יעלה שמונים שקלים. רגיל או מהיר?", "text_ru": "Это будет стоить 80 шекелей. Обычная или быстрая доставка?", "speaker_name": "Работник"}, {"is_user": true, "options": ["מהיר, בבקשה.", "רגיל, בבקשה.", "כמה ההבדל?"], "speaker": "ב", "text_he": "רגיל, בבקשה.", "text_ru": "Обычная, пожалуйста.", "speaker_name": "Вы", "correct_option": 1}]', '[{"he": "חבילה", "ru": "посылка", "translit": "хавилА"}, {"he": "לשלוח", "ru": "отправить", "translit": "лишлОах"}, {"he": "שוקל", "ru": "весит", "translit": "шокЕль"}, {"he": "מהיר", "ru": "быстрый", "translit": "маhИр"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (9, 2, 'В аэропорту: регистрация', 'Вы регистрируетесь на рейс в аэропорту Бен-Гурион.', '[{"is_user": false, "speaker": "א", "text_he": "שלום! הדרכון והכרטיס בבקשה.", "text_ru": "Здравствуйте! Паспорт и билет, пожалуйста.", "speaker_name": "Агент"}, {"is_user": true, "options": ["רגע, אני מחפש.", "איפה הצ''ק-אין?", "הנה, בבקשה."], "speaker": "ב", "text_he": "הנה, בבקשה.", "text_ru": "Вот, пожалуйста.", "speaker_name": "Вы", "correct_option": 2}, {"is_user": false, "speaker": "א", "text_he": "יש לך מזוודות?", "text_ru": "У вас есть чемоданы?", "speaker_name": "Агент"}, {"is_user": true, "options": ["כן, מזוודה אחת.", "שתי מזוודות.", "לא, רק תיק יד."], "speaker": "ב", "text_he": "כן, מזוודה אחת.", "text_ru": "Да, один чемодан.", "speaker_name": "Вы", "correct_option": 0}, {"is_user": false, "speaker": "א", "text_he": "חלון או מעבר?", "text_ru": "Окно или проход?", "speaker_name": "Агент"}, {"is_user": true, "options": ["מעבר, בבקשה.", "לא משנה.", "חלון, בבקשה."], "speaker": "ב", "text_he": "חלון, בבקשה.", "text_ru": "У окна, пожалуйста.", "speaker_name": "Вы", "correct_option": 2}, {"is_user": false, "speaker": "א", "text_he": "הנה כרטיס ההעלייה. שער שלוש. טיסה נעימה!", "text_ru": "Вот посадочный талон. Выход три. Приятного полёта!", "speaker_name": "Агент"}]', '[{"he": "דרכון", "ru": "паспорт", "translit": "даркОн"}, {"he": "מזוודה", "ru": "чемодан", "translit": "мизвадА"}, {"he": "חלון", "ru": "окно", "translit": "халОн"}, {"he": "שער", "ru": "ворота/выход", "translit": "шАар"}, {"he": "טיסה", "ru": "полёт", "translit": "тисА"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (36, 6, 'Юридическая консультация', 'Вы пришли к адвокату за консультацией по поводу спора с арендодателем.', '[{"is_user": false, "speaker": "א", "text_he": "שלום, שבו בבקשה. ספרו לי — מה הבעיה עם המשכיר?", "text_ru": "Здравствуйте, присаживайтесь. Расскажите — в чём проблема с арендодателем?", "speaker_name": "Адвокат"}, {"is_user": true, "options": ["הוא רוצה כסף.", "המשכיר דורש שאשלם על תיקון מבני של הגג, אבל לפי החוזה זו חובה שלו.", "אני לא מבין מה כתוב בחוזה."], "speaker": "ב", "text_he": "המשכיר דורש שאשלם על תיקון מבני של הגג, אבל לפי החוזה זו חובה שלו.", "text_ru": "Арендодатель требует, чтобы я заплатил за капитальный ремонт крыши, но по договору это его обязанность.", "speaker_name": "Вы", "correct_option": 1}, {"is_user": false, "speaker": "א", "text_he": "תראו לי את החוזה. ככל הנראה, סעיף חמש מגדיר במפורש שתיקונים מבניים הם באחריות המשכיר. יש לכם תיעוד של הנזק?", "text_ru": "Покажите мне договор. По всей видимости, пункт пятый ясно определяет, что капитальный ремонт — ответственность арендодателя. У вас есть документация повреждений?", "speaker_name": "Адвокат"}, {"is_user": true, "options": ["אני אתקן לבד.", "כן, צילמתי הכול ושלחתי לו הודעה בדואר רשום, כפי שהמלצתם.", "אין לי תיעוד."], "speaker": "ב", "text_he": "כן, צילמתי הכול ושלחתי לו הודעה בדואר רשום, כפי שהמלצתם.", "text_ru": "Да, я сфотографировал всё и отправил ему уведомление заказным письмом, как вы рекомендовали.", "speaker_name": "Вы", "correct_option": 1}, {"is_user": false, "speaker": "א", "text_he": "מצוין. במידה והוא ימשיך לסרב, נשלח לו מכתב התראה רשמי. אם לא יגיב תוך 14 יום, נגיש תביעה לבית משפט לתביעות קטנות.", "text_ru": "Отлично. В случае если он продолжит отказываться, мы направим ему официальное предупредительное письмо. Если не ответит в течение 14 дней, подадим иск в суд мелких исков.", "speaker_name": "Адвокат"}, {"is_user": true, "options": ["כמה זה יעלה?", "אני מפחד מבית משפט.", "מה הסיכויים שלי להצליח בבית המשפט, להערכתכם?"], "speaker": "ב", "text_he": "מה הסיכויים שלי להצליח בבית המשפט, להערכתכם?", "text_ru": "Каковы мои шансы на успех в суде, по вашей оценке?", "speaker_name": "Вы", "correct_option": 2}]', '[{"he": "תיקון מבני", "ru": "капитальный ремонт", "translit": "тикУн мивнИ"}, {"he": "סעיף", "ru": "пункт / статья (договора)", "translit": "сеИф"}, {"he": "באחריות", "ru": "под ответственностью", "translit": "бе-ахрайУт"}, {"he": "דואר רשום", "ru": "заказное письмо", "translit": "дОар рашУм"}, {"he": "מכתב התראה", "ru": "предупредительное письмо", "translit": "михтАв hатраА"}, {"he": "תביעה", "ru": "иск", "translit": "тавиА"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (10, 2, 'На работе: собеседование', 'Вы на собеседовании на новую работу.', '[{"is_user": false, "speaker": "א", "text_he": "שלום! ספר לי קצת על עצמך.", "text_ru": "Здравствуйте! Расскажите немного о себе.", "speaker_name": "HR"}, {"is_user": true, "options": ["אני מתכנת עם ניסיון של חמש שנים.", "אני אוהב לעבוד.", "אני מחפש עבודה."], "speaker": "ב", "text_he": "אני מתכנת עם ניסיון של חמש שנים.", "text_ru": "Я программист с опытом 5 лет.", "speaker_name": "Вы", "correct_option": 0}, {"is_user": false, "speaker": "א", "text_he": "מעניין! למה אתה רוצה לעבוד אצלנו?", "text_ru": "Интересно! Почему хотите работать у нас?", "speaker_name": "HR"}, {"is_user": true, "options": ["זה קרוב לבית.", "אני אוהב את החברה שלכם.", "המשכורת טובה."], "speaker": "ב", "text_he": "אני אוהב את החברה שלכם.", "text_ru": "Мне нравится ваша компания.", "speaker_name": "Вы", "correct_option": 1}, {"is_user": false, "speaker": "א", "text_he": "מצוין! אנחנו נחזור אליך השבוע.", "text_ru": "Отлично! Мы свяжемся с вами на этой неделе.", "speaker_name": "HR"}]', '[{"he": "מתכנת", "ru": "программист", "translit": "метахнЕт"}, {"he": "ניסיון", "ru": "опыт", "translit": "нисайОн"}, {"he": "חברה", "ru": "компания", "translit": "хеврА"}, {"he": "משכורת", "ru": "зарплата", "translit": "маскОрет"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (11, 2, 'В ресторане: ужин', 'Вы ужинаете в ресторане.', '[{"is_user": false, "speaker": "א", "text_he": "ערב טוב! הנה התפריט.", "text_ru": "Добрый вечер! Вот меню.", "speaker_name": "Официант"}, {"is_user": true, "options": ["תודה. מה אתה ממליץ?", "יש תפריט בערבית?", "אני רוצה סטייק."], "speaker": "ב", "text_he": "תודה. מה אתה ממליץ?", "text_ru": "Спасибо. Что вы порекомендуете?", "speaker_name": "Вы", "correct_option": 0}, {"is_user": false, "speaker": "א", "text_he": "הדג שלנו מצוין! ויש סלט ירושלמי מיוחד.", "text_ru": "Наша рыба отличная! И есть особый иерусалимский салат.", "speaker_name": "Официант"}, {"is_user": true, "options": ["רק מים, תודה.", "אני אקח את הדג ואת הסלט.", "אני צמחוני."], "speaker": "ב", "text_he": "אני אקח את הדג ואת הסלט.", "text_ru": "Я возьму рыбу и салат.", "speaker_name": "Вы", "correct_option": 1}, {"is_user": false, "speaker": "א", "text_he": "ומה לשתות?", "text_ru": "А что пить?", "speaker_name": "Официант"}, {"is_user": true, "options": ["מים, בבקשה.", "בירה, בבקשה.", "יין אדום, בבקשה."], "speaker": "ב", "text_he": "יין אדום, בבקשה.", "text_ru": "Красное вино, пожалуйста.", "speaker_name": "Вы", "correct_option": 2}]', '[{"he": "תפריט", "ru": "меню", "translit": "тафрИт"}, {"he": "ממליץ", "ru": "рекомендует", "translit": "мамлИц"}, {"he": "דג", "ru": "рыба", "translit": "даг"}, {"he": "סלט", "ru": "салат", "translit": "салАт"}, {"he": "יין", "ru": "вино", "translit": "яин"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (12, 2, 'В аптеке', 'У вас болит голова. Вы идёте в аптеку.', '[{"is_user": false, "speaker": "א", "text_he": "שלום! איך אני יכול לעזור?", "text_ru": "Привет! Чем могу помочь?", "speaker_name": "Фармацевт"}, {"is_user": true, "options": ["כואב לי הראש.", "יש לך אקמול?", "אני צריך תרופות."], "speaker": "ב", "text_he": "כואב לי הראש.", "text_ru": "У меня болит голова.", "speaker_name": "Вы", "correct_option": 0}, {"is_user": false, "speaker": "א", "text_he": "יש לנו אקמול ונורופן. מה אתה מעדיף?", "text_ru": "У нас есть акамол и нурофен. Что предпочитаете?", "speaker_name": "Фармацевт"}, {"is_user": true, "options": ["מה ההבדל?", "נורופן, בבקשה.", "אקמול, בבקשה."], "speaker": "ב", "text_he": "אקמול, בבקשה.", "text_ru": "Акамол, пожалуйста.", "speaker_name": "Вы", "correct_option": 2}, {"is_user": false, "speaker": "א", "text_he": "בבקשה. קח כדור כל שש שעות. רפואה שלמה!", "text_ru": "Пожалуйста. Принимай таблетку каждые шесть часов. Выздоравливай!", "speaker_name": "Фармацевт"}]', '[{"he": "כואב", "ru": "болит", "translit": "коЭв"}, {"he": "ראש", "ru": "голова", "translit": "рош"}, {"he": "תרופות", "ru": "лекарства", "translit": "труфОт"}, {"he": "כדור", "ru": "таблетка", "translit": "кадУр"}, {"he": "רפואה שלמה", "ru": "выздоравливай", "translit": "рефуА шлемА"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (13, 2, 'Съём квартиры', 'Вы ищете квартиру для аренды.', '[{"is_user": false, "speaker": "א", "text_he": "שלום! אתה מחפש דירה?", "text_ru": "Привет! Ищете квартиру?", "speaker_name": "Хозяин"}, {"is_user": true, "options": ["כן, דירת שני חדרים.", "כן, דירה גדולה.", "כמה עולה?"], "speaker": "ב", "text_he": "כן, דירת שני חדרים.", "text_ru": "Да, двухкомнатную.", "speaker_name": "Вы", "correct_option": 0}, {"is_user": false, "speaker": "א", "text_he": "יש לי דירה ברחוב הרצל. שלושת אלפים שקלים בחודש.", "text_ru": "У меня есть квартира на улице Герцля. 3000 шекелей в месяц.", "speaker_name": "Хозяин"}, {"is_user": true, "options": ["זה יקר מדי.", "אפשר לראות את הדירה?", "יש מרפסת?"], "speaker": "ב", "text_he": "אפשר לראות את הדירה?", "text_ru": "Можно посмотреть квартиру?", "speaker_name": "Вы", "correct_option": 1}, {"is_user": false, "speaker": "א", "text_he": "כן, בוא מחר בארבע אחרי הצהריים.", "text_ru": "Да, приходи завтра в четыре дня.", "speaker_name": "Хозяин"}]', '[{"he": "דירה", "ru": "квартира", "translit": "дирА"}, {"he": "חדרים", "ru": "комнаты", "translit": "хадарИм"}, {"he": "רחוב", "ru": "улица", "translit": "рехОв"}, {"he": "מרפסת", "ru": "балкон", "translit": "мирпЕсет"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (51, 5, 'Радио-интервью: иммиграция и идентичность', 'Вас пригласили на радио для интервью о жизни репатриантов в Израиле.', '[{"is_user": false, "speaker": "א", "text_he": "ערב טוב, מאזינים יקרים. אתנו באולפן אלכס, עולה חדש מרוסיה שחי בישראל שלוש שנים. אלכס, איך היית מתאר את חוויית העלייה?", "text_ru": "Добрый вечер, дорогие слушатели. С нами в студии Алекс, новый репатриант из России, который живёт в Израиле три года. Алекс, как бы вы описали опыт репатриации?", "speaker_name": "Ведущий"}, {"is_user": true, "options": ["ערב טוב. זה תהליך מורכב ומעשיר בו-זמנית. הדבר הקשה ביותר היה מחסום השפה, אבל אחרי חצי שנה של לימודים אינטנסיביים הרגשתי שאני מסוגל לבטא את עצמי.", "ערב טוב. זה היה קשה.", "ערב טוב. הכול היה קל."], "speaker": "ב", "text_he": "ערב טוב. זה תהליך מורכב ומעשיר בו-זמנית. הדבר הקשה ביותר היה מחסום השפה, אבל אחרי חצי שנה של לימודים אינטנסיביים הרגשתי שאני מסוגל לבטא את עצמי.", "text_ru": "Добрый вечер. Это сложный и обогащающий процесс одновременно. Самым трудным был языковой барьер, но через полгода интенсивного обучения я почувствовал, что могу выражать себя.", "speaker_name": "Вы", "correct_option": 0}, {"is_user": false, "speaker": "א", "text_he": "מעניין. הרבה עולים מדברים על תחושת חיים בין שתי תרבויות. איך אתה מתמודד עם הזהות הכפולה הזו?", "text_ru": "Интересно. Многие репатрианты говорят об ощущении жизни между двумя культурами. Как вы справляетесь с этой двойной идентичностью?", "speaker_name": "Ведущий"}, {"is_user": true, "options": ["אני עדיין מרגיש כמו זר.", "הפסקתי לתפוס את זה כקונפליקט והתחלתי לראות בזה יתרון. דו-לשוניות ודו-תרבותיות הן משאב. אני מביא ניסיון מקצועי רוסי ובמקביל סופג את המנטליות הישראלית.", "אני מרגיש ישראלי לגמרי."], "speaker": "ב", "text_he": "הפסקתי לתפוס את זה כקונפליקט והתחלתי לראות בזה יתרון. דו-לשוניות ודו-תרבותיות הן משאב. אני מביא ניסיון מקצועי רוסי ובמקביל סופג את המנטליות הישראלית.", "text_ru": "Я перестал воспринимать это как конфликт и начал видеть в этом преимущество. Двуязычие и двукультурность — это ресурс. Я привношу российский профессиональный опыт и одновременно впитываю израильский менталитет.", "speaker_name": "Вы", "correct_option": 1}, {"is_user": false, "speaker": "א", "text_he": "מה הייתה המלצתך לעולים חדשים שרק מתחילים את הדרך?", "text_ru": "Какой бы совет вы дали новым репатриантам, которые только начинают свой путь?", "speaker_name": "Ведущий"}, {"is_user": true, "options": ["תלמדו עברית.", "אל תוותרו.", "אל תסתגרו בבועה הרוסית. חפשו חברים ישראלים, השתתפו בחיים הציבוריים. שפה נלמדת בתקשורת חיה, לא רק באולפן."], "speaker": "ב", "text_he": "אל תסתגרו בבועה הרוסית. חפשו חברים ישראלים, השתתפו בחיים הציבוריים. שפה נלמדת בתקשורת חיה, לא רק באולפן.", "text_ru": "Не закрывайтесь в русскоязычном пузыре. Ищите израильских друзей, участвуйте в общественной жизни. Язык учится в живом общении, а не только в ульпане.", "speaker_name": "Вы", "correct_option": 2}]', '[{"he": "עלייה", "ru": "репатриация", "translit": "алийА"}, {"he": "מחסום שפה", "ru": "языковой барьер", "translit": "махсОм сафА"}, {"he": "זהות כפולה", "ru": "двойная идентичность", "translit": "зеhУт кфулА"}, {"he": "דו-תרבותיות", "ru": "двукультурность", "translit": "ду-тарбутиЮт"}, {"he": "להסתגר", "ru": "закрываться/замыкаться", "translit": "леhистагЕр"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (14, 1, 'В автобусе', 'Вы едете на автобусе в первый раз.', '[{"is_user": true, "options": ["כמה עולה כרטיס?", "סליחה, האוטובוס הזה נוסע למרכז?", "סליחה, מתי האוטובוס?"], "speaker": "ב", "text_he": "סליחה, האוטובוס הזה נוסע למרכז?", "text_ru": "Извините, этот автобус едет в центр?", "speaker_name": "Вы", "correct_option": 1}, {"is_user": false, "speaker": "א", "text_he": "כן, הוא עוצר בתחנה המרכזית.", "text_ru": "Да, он останавливается на центральной станции.", "speaker_name": "Пассажир"}, {"is_user": true, "options": ["תודה! כמה עולה נסיעה?", "מתי הוא מגיע?", "תודה רבה!"], "speaker": "ב", "text_he": "תודה! כמה עולה נסיעה?", "text_ru": "Спасибо! Сколько стоит проезд?", "speaker_name": "Вы", "correct_option": 0}, {"is_user": false, "speaker": "א", "text_he": "חמישה שקלים וחמישים אגורות. אתה צריך רב-קו.", "text_ru": "5.50 шекелей. Тебе нужен Рав-Кав.", "speaker_name": "Пассажир"}]', '[{"he": "אוטובוס", "ru": "автобус", "translit": "отобУс"}, {"he": "מרכז", "ru": "центр", "translit": "меркАз"}, {"he": "תחנה", "ru": "станция", "translit": "таханА"}, {"he": "נסיעה", "ru": "поездка", "translit": "несиА"}, {"he": "רב-קו", "ru": "Рав-Кав (проездной)", "translit": "рав-кав"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (15, 2, 'В поликлинике: приём', 'Вы на приёме у врача.', '[{"is_user": false, "speaker": "א", "text_he": "שלום! מה הבעיה?", "text_ru": "Здравствуйте! Что вас беспокоит?", "speaker_name": "Врач"}, {"is_user": true, "options": ["כואב לי הגרון ויש לי חום.", "אני לא מרגיש טוב.", "כואב לי הראש."], "speaker": "ב", "text_he": "כואב לי הגרון ויש לי חום.", "text_ru": "У меня болит горло и температура.", "speaker_name": "Вы", "correct_option": 0}, {"is_user": false, "speaker": "א", "text_he": "מתי זה התחיל?", "text_ru": "Когда это началось?", "speaker_name": "Врач"}, {"is_user": true, "options": ["אתמול.", "לפני יומיים.", "לא זוכר."], "speaker": "ב", "text_he": "לפני יומיים.", "text_ru": "Два дня назад.", "speaker_name": "Вы", "correct_option": 1}, {"is_user": false, "speaker": "א", "text_he": "אני כותב לך מרשם לאנטיביוטיקה. תרגיש יותר טוב בעוד כמה ימים.", "text_ru": "Я выписываю рецепт на антибиотик. Через несколько дней тебе станет лучше.", "speaker_name": "Врач"}]', '[{"he": "גרון", "ru": "горло", "translit": "гарОн"}, {"he": "חום", "ru": "температура/жар", "translit": "хом"}, {"he": "מרשם", "ru": "рецепт", "translit": "миршАм"}, {"he": "אנטיביוטיקה", "ru": "антибиотик", "translit": "антибиОтика"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (16, 1, 'Знакомство на вечеринке', 'Вы на вечеринке и знакомитесь с новыми людьми.', '[{"is_user": false, "speaker": "א", "text_he": "היי! מה שמך? אני לא מכיר אותך.", "text_ru": "Привет! Как тебя зовут? Я тебя не знаю.", "speaker_name": "Гость"}, {"is_user": true, "options": ["שלום! אני חדש פה.", "היי! נעים מאוד.", "שלום! אני אלכס. אני חבר של בעל הבית."], "speaker": "ב", "text_he": "שלום! אני אלכס. אני חבר של בעל הבית.", "text_ru": "Привет! Я (имя). Я друг хозяина.", "speaker_name": "Вы", "correct_option": 2}, {"is_user": false, "speaker": "א", "text_he": "נעים מאוד! מה אתה עושה?", "text_ru": "Очень приятно! Чем ты занимаешься?", "speaker_name": "Гость"}, {"is_user": true, "options": ["אני מתכנת. ואתה?", "אני עובד. ואתה?", "אני לומד עברית."], "speaker": "ב", "text_he": "אני מתכנת. ואתה?", "text_ru": "Я программист. А ты?", "speaker_name": "Вы", "correct_option": 0}]', '[{"he": "מכיר", "ru": "знаю/знаком", "translit": "макИр"}, {"he": "חבר", "ru": "друг", "translit": "хавЕр"}, {"he": "בעל הבית", "ru": "хозяин дома", "translit": "бАаль hа-бАйит"}, {"he": "מה אתה עושה", "ru": "чем занимаешься", "translit": "ма атА осЕ"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (17, 3, 'В университете: регистрация', 'Вы регистрируетесь на курсы в израильском университете.', '[{"is_user": false, "speaker": "א", "text_he": "שלום! ברוכים הבאים לאוניברסיטה. איך אני יכולה לעזור?", "text_ru": "Здравствуйте! Добро пожаловать в университет. Чем могу помочь?", "speaker_name": "Секретарь"}, {"is_user": true, "options": ["אני רוצה להירשם לקורס עברית.", "אני צריך מידע.", "איפה המזכירות?"], "speaker": "ב", "text_he": "אני רוצה להירשם לקורס עברית.", "text_ru": "Я хочу записаться на курс иврита.", "speaker_name": "Вы", "correct_option": 0}, {"is_user": false, "speaker": "א", "text_he": "מצוין! יש לנו קורסים ברמות שונות. מה הרמה שלך?", "text_ru": "Отлично! У нас есть курсы разных уровней. Какой у вас уровень?", "speaker_name": "Секретарь"}, {"is_user": true, "options": ["אני מתחיל.", "אני לא יודע.", "רמה בינונית. סיימתי אולפן בית."], "speaker": "ב", "text_he": "רמה בינונית. סיימתי אולפן בית.", "text_ru": "Средний уровень. Я закончил ульпан Бет.", "speaker_name": "Вы", "correct_option": 2}, {"is_user": false, "speaker": "א", "text_he": "אז אני ממליצה על קורס גימל. הוא מתחיל בשבוע הבא.", "text_ru": "Тогда рекомендую курс Гимель. Он начинается на следующей неделе.", "speaker_name": "Секретарь"}]', '[{"he": "להירשם", "ru": "записаться", "translit": "леhирашЕм"}, {"he": "רמה", "ru": "уровень", "translit": "рамА"}, {"he": "בינונית", "ru": "средняя", "translit": "бейнонИт"}, {"he": "סיימתי", "ru": "я закончил", "translit": "сиЯмти"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (37, 6, 'Заседание правления', 'Вы участвуете в заседании правления некоммерческой организации, помогающей репатриантам.', '[{"is_user": false, "speaker": "א", "text_he": "נפתח את הישיבה. סעיף ראשון — תקציב השנה הבאה. המנכ\"ל, בבקשה.", "text_ru": "Открываю заседание. Первый пункт — бюджет на следующий год. Генеральный директор, пожалуйста.", "speaker_name": "Председатель"}, {"is_user": false, "speaker": "ב", "text_he": "השנה התקציב עמד על שלושה מיליון שקלים. אנחנו מבקשים העלאה של עשרים אחוז לשנה הבאה, בעיקר לתוכניות שילוב תעסוקתי.", "text_ru": "В этом году бюджет составлял три миллиона шекелей. Мы запрашиваем увеличение на двадцать процентов на следующий год, в основном на программы трудоустройства.", "speaker_name": "Генеральный директор"}, {"is_user": false, "speaker": "א", "text_he": "תודה. חבר הנהלה, מה דעתכם?", "text_ru": "Спасибо. Член правления, ваше мнение?", "speaker_name": "Председатель"}, {"is_user": true, "options": ["אני תומך בהגדלת התקציב, אך מציע להקצות חלק מהכספים לתוכנית ללימוד עברית לבעלי מקצוע.", "צריך לחשוב על זה.", "אני נגד."], "speaker": "ג", "text_he": "אני תומך בהגדלת התקציב, אך מציע להקצות חלק מהכספים לתוכנית ללימוד עברית לבעלי מקצוע.", "text_ru": "Я поддерживаю увеличение бюджета, но предлагаю направить часть средств на программу обучения ивриту для профессионалов.", "speaker_name": "Вы", "correct_option": 0}, {"is_user": false, "speaker": "א", "text_he": "הצעה מעניינת. האם תוכלו להכין תוכנית עבודה מפורטת עד הישיבה הבאה?", "text_ru": "Интересное предложение. Сможете подготовить подробный рабочий план к следующему заседанию?", "speaker_name": "Председатель"}, {"is_user": true, "options": ["אני אנסה.", "אין לי זמן.", "בוודאי. אכין הצעה הכוללת פירוט תקציבי ומדדי יעילות צפויים."], "speaker": "ג", "text_he": "בוודאי. אכין הצעה הכוללת פירוט תקציבי ומדדי יעילות צפויים.", "text_ru": "Разумеется. Я подготовлю предложение с разбивкой бюджета и ожидаемыми показателями эффективности.", "speaker_name": "Вы", "correct_option": 2}]', '[{"he": "ישיבה", "ru": "заседание", "translit": "йешивА"}, {"he": "תקציב", "ru": "бюджет", "translit": "такцИв"}, {"he": "הקצאה", "ru": "выделение (средств)", "translit": "hакцаА"}, {"he": "מדדי יעילות", "ru": "показатели эффективности", "translit": "мададЕй йеилУт"}, {"he": "שילוב תעסוקתי", "ru": "трудоустройство / интеграция", "translit": "шилУв таасукатИ"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (28, 4, 'У нотариуса: доверенность', 'Вам нужна нотариальная доверенность для оформления документов.', '[{"is_user": false, "speaker": "א", "text_he": "שלום, מה אני יכול לעשות בשבילך?", "text_ru": "Здравствуйте, чем могу помочь?", "speaker_name": "Нотариус"}, {"is_user": true, "options": ["אני צריך ייפוי כוח לטיפול בדירה.", "אני רוצה לחתום על חוזה.", "אני צריך חותמת."], "speaker": "ב", "text_he": "אני צריך ייפוי כוח לטיפול בדירה.", "text_ru": "Мне нужна доверенность для оформления квартиры.", "speaker_name": "Вы", "correct_option": 0}, {"is_user": false, "speaker": "א", "text_he": "בסדר. ייפוי כוח כללי או ספציפי? צריך להביא תעודת זהות ופרטים של מיופה הכוח.", "text_ru": "Хорошо. Общая или специальная доверенность? Нужно принести удостоверение личности и данные доверенного лица.", "speaker_name": "Нотариус"}, {"is_user": true, "options": ["ספציפי, רק לדירה הזו. כמה זה עולה?", "כללי, בבקשה.", "אני לא יודע."], "speaker": "ב", "text_he": "ספציפי, רק לדירה הזו. כמה זה עולה?", "text_ru": "Специальная, только для этой квартиры. Сколько это стоит?", "speaker_name": "Вы", "correct_option": 0}, {"is_user": false, "speaker": "א", "text_he": "ארבע מאות שקל. אני מכין את המסמך ואתה חותם בפניי.", "text_ru": "Четыреста шекелей. Я подготовлю документ, и вы подпишете в моём присутствии.", "speaker_name": "Нотариус"}]', '[{"he": "ייפוי כוח", "ru": "доверенность", "translit": "йипУй кОах"}, {"he": "נוטריון", "ru": "нотариус", "translit": "нотарийОн"}, {"he": "מסמך", "ru": "документ", "translit": "мисмАх"}, {"he": "לחתום", "ru": "подписать", "translit": "лахтОм"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (19, 3, 'В больнице: визит к специалисту', 'Вы пришли на приём к специалисту.', '[{"is_user": false, "speaker": "א", "text_he": "שלום! אני דוקטור כהן. הרופא המשפחתי שלך הפנה אותך אלי. מה הבעיה?", "text_ru": "Здравствуйте! Я доктор Коэн. Ваш семейный врач направил вас ко мне. Какая проблема?", "speaker_name": "Врач"}, {"is_user": true, "options": ["כואב לי הגב כבר חודש.", "אני לא מרגיש טוב.", "יש לי כאבי ראש."], "speaker": "ב", "text_he": "כואב לי הגב כבר חודש.", "text_ru": "У меня болит спина уже месяц.", "speaker_name": "Вы", "correct_option": 0}, {"is_user": false, "speaker": "א", "text_he": "אני מבין. אני צריך לשלוח אותך לצילום רנטגן. אחרי זה נדבר על הטיפול.", "text_ru": "Понимаю. Мне нужно отправить вас на рентген. После этого поговорим о лечении.", "speaker_name": "Врач"}, {"is_user": true, "options": ["בסדר, תודה.", "אני מפחד.", "בסדר. וכמה זה עולה?"], "speaker": "ב", "text_he": "בסדר. וכמה זה עולה?", "text_ru": "Хорошо. А сколько это стоит?", "speaker_name": "Вы", "correct_option": 2}]', '[{"he": "הפנה", "ru": "направил", "translit": "hифнА"}, {"he": "גב", "ru": "спина", "translit": "гав"}, {"he": "צילום רנטגן", "ru": "рентгеновский снимок", "translit": "цилУм рентгЕн"}, {"he": "טיפול", "ru": "лечение", "translit": "типУль"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (20, 4, 'Собеседование в хай-тек', 'Техническое собеседование в стартапе.', '[{"is_user": false, "speaker": "א", "text_he": "שלום! ספר לי על הניסיון שלך בפיתוח תוכנה.", "text_ru": "Привет! Расскажи о своём опыте в разработке ПО.", "speaker_name": "CTO"}, {"is_user": true, "options": ["יש לי חמש שנות ניסיון. אני מתמחה בצד השרת.", "אני מתכנת.", "אני אוהב לתכנת."], "speaker": "ב", "text_he": "יש לי חמש שנות ניסיון. אני מתמחה בצד השרת.", "text_ru": "У меня пять лет опыта. Я специализируюсь на бэкенде.", "speaker_name": "Вы", "correct_option": 0}, {"is_user": false, "speaker": "א", "text_he": "מעולה. באילו שפות תכנות אתה עובד?", "text_ru": "Отлично. На каких языках программирования ты работаешь?", "speaker_name": "CTO"}, {"is_user": true, "options": ["אני לומד שפות חדשות.", "כל השפות.", "פייתון, גו וטייפסקריפט."], "speaker": "ב", "text_he": "פייתון, גו וטייפסקריפט.", "text_ru": "Python, Go и TypeScript.", "speaker_name": "Вы", "correct_option": 2}, {"is_user": false, "speaker": "א", "text_he": "מצוין. עכשיו ניגש לשאלה טכנית. איך היית מתכנן מערכת עם עומס גבוה?", "text_ru": "Отлично. Теперь перейдём к техническому вопросу. Как бы ты спроектировал систему с высокой нагрузкой?", "speaker_name": "CTO"}, {"is_user": true, "options": ["אני צריך לחשוב על זה.", "זה תלוי בדרישות.", "הייתי משתמש בארכיטקטורת מיקרו-שירותים עם איזון עומסים."], "speaker": "ב", "text_he": "הייתי משתמש בארכיטקטורת מיקרו-שירותים עם איזון עומסים.", "text_ru": "Я бы использовал микросервисную архитектуру с балансировкой нагрузки.", "speaker_name": "Вы", "correct_option": 2}]', '[{"he": "פיתוח תוכנה", "ru": "разработка ПО", "translit": "питУах тохнА"}, {"he": "מתמחה", "ru": "специализируюсь", "translit": "митмахЕ"}, {"he": "שפות תכנות", "ru": "языки программирования", "translit": "сфОт тихнУт"}, {"he": "עומס גבוה", "ru": "высокая нагрузка", "translit": "Омес гавОhа"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (22, 5, 'На конференции', 'Вы выступаете на научной конференции.', '[{"is_user": false, "speaker": "א", "text_he": "ועכשיו נשמע את ההרצאה הבאה. בבקשה.", "text_ru": "А теперь послушаем следующий доклад. Пожалуйста.", "speaker_name": "Модератор"}, {"is_user": true, "options": ["שלום לכולם.", "תודה רבה.", "תודה. נושא ההרצאה שלי הוא השפעת הטכנולוגיה על החינוך."], "speaker": "ב", "text_he": "תודה. נושא ההרצאה שלי הוא השפעת הטכנולוגיה על החינוך.", "text_ru": "Спасибо. Тема моего доклада — влияние технологий на образование.", "speaker_name": "Вы", "correct_option": 2}, {"is_user": false, "speaker": "א", "text_he": "שאלה מעניינת: האם לדעתך הבינה המלאכותית תחליף את המורים?", "text_ru": "Интересный вопрос: по вашему мнению, заменит ли ИИ учителей?", "speaker_name": "Слушатель"}, {"is_user": true, "options": ["זו שאלה מורכבת.", "לדעתי, הבינה המלאכותית תשלים את המורים אבל לא תחליף אותם.", "אני לא בטוח."], "speaker": "ב", "text_he": "לדעתי, הבינה המלאכותית תשלים את המורים אבל לא תחליף אותם.", "text_ru": "Я считаю, что ИИ дополнит учителей, но не заменит их.", "speaker_name": "Вы", "correct_option": 1}]', '[{"he": "הרצאה", "ru": "доклад/лекция", "translit": "hарцаА"}, {"he": "השפעה", "ru": "влияние", "translit": "hашпаА"}, {"he": "בינה מלאכותית", "ru": "искусственный интеллект", "translit": "бинА мелахутИт"}, {"he": "תשלים", "ru": "дополнит", "translit": "ташлИм"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (38, 6, 'Политическая дискуссия', 'Вы участвуете в телевизионной дискуссии о системе образования.', '[{"is_user": false, "speaker": "א", "text_he": "שלום וברוכים הבאים ל\"זירת הדעות\". הנושא הערב — מערכת החינוך. נתחיל עם שאלה ישירה: מה הבעיה המרכזית?", "text_ru": "Здравствуйте, добро пожаловать на «Арену мнений». Тема сегодня — система образования. Начнём с прямого вопроса: в чём главная проблема?", "speaker_name": "Ведущий"}, {"is_user": true, "options": ["אין בעיה.", "הכול בסדר עם החינוך.", "הבעיה המרכזית היא הפער בין מרכז לפריפריה. ילד בדימונה לא מקבל את אותה רמת חינוך כמו ילד בתל אביב."], "speaker": "ב", "text_he": "הבעיה המרכזית היא הפער בין מרכז לפריפריה. ילד בדימונה לא מקבל את אותה רמת חינוך כמו ילד בתל אביב.", "text_ru": "Основная проблема — это разрыв между центром и периферией. Ребёнок в Димоне не получает того же качества образования, что ребёнок в Тель-Авиве.", "speaker_name": "Вы", "correct_option": 2}, {"is_user": false, "speaker": "ג", "text_he": "עם כל הכבוד, הממשלה השקיעה מיליארדים בפריפריה בעשור האחרון. אתם מתעלמים מהתקדמות משמעותית.", "text_ru": "При всём уважении, правительство инвестировало миллиарды в периферию за последнее десятилетие. Вы игнорируете значительный прогресс.", "speaker_name": "Оппонент"}, {"is_user": true, "options": ["אינני מתעלם מההשקעות, אולם התוצאות מדברות בעד עצמן. אחוזי הזכאות לבגרות בפריפריה עדיין נמוכים באופן משמעותי.", "אתה טועה.", "יכול להיות."], "speaker": "ב", "text_he": "אינני מתעלם מההשקעות, אולם התוצאות מדברות בעד עצמן. אחוזי הזכאות לבגרות בפריפריה עדיין נמוכים באופן משמעותי.", "text_ru": "Я не игнорирую вложения, однако результаты говорят сами за себя. Показатели экзаменов на аттестат зрелости на периферии по-прежнему значительно ниже.", "speaker_name": "Вы", "correct_option": 0}, {"is_user": false, "speaker": "א", "text_he": "ומה הפתרון שלכם?", "text_ru": "И каково ваше решение?", "speaker_name": "Ведущий"}, {"is_user": true, "options": ["צריך לחשוב על זה.", "אין לי פתרון.", "יש להעלות את שכר המורים בפריפריה בשלושים אחוז לפחות, כדי למשוך את המורים הטובים ביותר."], "speaker": "ב", "text_he": "יש להעלות את שכר המורים בפריפריה בשלושים אחוז לפחות, כדי למשוך את המורים הטובים ביותר.", "text_ru": "Необходимо повысить зарплату учителям на периферии минимум на тридцать процентов, чтобы привлечь лучших педагогов.", "speaker_name": "Вы", "correct_option": 2}]', '[{"he": "פער", "ru": "разрыв / разница", "translit": "пАар"}, {"he": "פריפריה", "ru": "периферия", "translit": "перифЕрия"}, {"he": "זכאות לבגרות", "ru": "право на аттестат зрелости", "translit": "закаУт ле-багрУт"}, {"he": "השקעה", "ru": "инвестиция", "translit": "hашкаА"}, {"he": "אינני מתעלם", "ru": "я не игнорирую (высокий стиль)", "translit": "эйнЕни мит''алЕм"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (23, 5, 'Дискуссия о политике', 'Вы обсуждаете политическую ситуацию с израильскими друзьями.', '[{"is_user": false, "speaker": "א", "text_he": "מה דעתך על מה שקורה בכנסת?", "text_ru": "Что ты думаешь о том, что происходит в Кнессете?", "speaker_name": "Друг"}, {"is_user": true, "options": ["לדעתי, צריך דיאלוג בין כל הצדדים.", "אני לא מבין בפוליטיקה.", "זה מסובך מדי."], "speaker": "ב", "text_he": "לדעתי, צריך דיאלוג בין כל הצדדים.", "text_ru": "По моему мнению, нужен диалог между всеми сторонами.", "speaker_name": "Вы", "correct_option": 0}, {"is_user": false, "speaker": "א", "text_he": "אני מסכים, אבל למעשה כל צד מאשים את השני.", "text_ru": "Согласен, но на деле каждая сторона обвиняет другую.", "speaker_name": "Друг"}, {"is_user": true, "options": ["בדיוק לכן חשובה עיתונות חופשית.", "אולי אתה צודק.", "אני מעדיף לא לדבר על פוליטיקה."], "speaker": "ב", "text_he": "בדיוק לכן חשובה עיתונות חופשית.", "text_ru": "Именно поэтому важна свободная пресса.", "speaker_name": "Вы", "correct_option": 0}]', '[{"he": "כנסת", "ru": "Кнессет (парламент)", "translit": "кнЕсет"}, {"he": "דיאלוג", "ru": "диалог", "translit": "диалОг"}, {"he": "מאשים", "ru": "обвиняет", "translit": "маашИм"}, {"he": "עיתונות", "ru": "пресса", "translit": "итонУт"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (39, 6, 'Защита диссертации', 'Вы защищаете докторскую диссертацию по лингвистике в Еврейском университете.', '[{"is_user": false, "speaker": "א", "text_he": "אנו פותחים את הדיון בעבודת הדוקטורט של הגב'' / מר ___. בבקשה, הציגו את עבודתכם בקצרה.", "text_ru": "Мы открываем обсуждение докторской диссертации г-жи/г-на ___. Пожалуйста, представьте вашу работу кратко.", "speaker_name": "Председатель комиссии"}, {"is_user": true, "options": ["עבודתי חוקרת את השפעת הערבית על העברית המדוברת בת זמננו, בדגש על מעבר בין רגיסטרים אצל דוברים דו-לשוניים.", "אני חקרתי ערבית ועברית.", "העבודה שלי על שפות."], "speaker": "ב", "text_he": "עבודתי חוקרת את השפעת הערבית על העברית המדוברת בת זמננו, בדגש על מעבר בין רגיסטרים אצל דוברים דו-לשוניים.", "text_ru": "Моя диссертация исследует влияние арабского языка на современный разговорный иврит, с акцентом на переключение регистров у двуязычных носителей.", "speaker_name": "Вы", "correct_option": 0}, {"is_user": false, "speaker": "ג", "text_he": "עבודה מרתקת. שאלתי הראשונה נוגעת למתודולוגיה: כיצד הבחנתם בין הוספת מילים ערביות לבין מעבר קוד אמיתי?", "text_ru": "Увлекательная работа. Мой первый вопрос касается методологии: как вы разграничивали заимствования из арабского и подлинное переключение кодов?", "speaker_name": "Профессор-оппонент"}, {"is_user": true, "options": ["זו שאלה קשה.", "קראתי מאמרים.", "השתמשתי במודל שפת-המטריצה של מאיירס-סקוטן, בתוספת ניתוח פרוזודי. מילים מושאלות משתלבות בפונולוגיה העברית, בעוד מעבר קוד שומר על הפרוזודיה הערבית."], "speaker": "ב", "text_he": "השתמשתי במודל שפת-המטריצה של מאיירס-סקוטן, בתוספת ניתוח פרוזודי. מילים מושאלות משתלבות בפונולוגיה העברית, בעוד מעבר קוד שומר על הפרוזודיה הערבית.", "text_ru": "Я использовал модель Майерс-Скоттон для матричного языка, дополнив её просодическим анализом. Заимствования интегрированы в фонологическую систему иврита, тогда как переключение кодов сохраняет арабскую просодию.", "speaker_name": "Вы", "correct_option": 2}, {"is_user": false, "speaker": "ג", "text_he": "ומה לגבי המגבלות של המחקר? האם אתם מודעים לכך שהמדגם מייצג בעיקר ערבים מצפון הארץ?", "text_ru": "А что насчёт ограничений исследования? Вы осознаёте, что выборка представляет главным образом арабов с севера страны?", "speaker_name": "Профессор-оппонент"}, {"is_user": true, "options": ["לא חשבתי על זה.", "המדגם מספיק.", "אכן, אני דן במגבלה זו בפרק החמישי. מחקר עתידי צריך לכלול את האוכלוסייה הבדואית בנגב ואת הערבים העירוניים במרכז."], "speaker": "ב", "text_he": "אכן, אני דן במגבלה זו בפרק החמישי. מחקר עתידי צריך לכלול את האוכלוסייה הבדואית בנגב ואת הערבים העירוניים במרכז.", "text_ru": "Безусловно. Я обсуждаю это ограничение в пятой главе. Будущее исследование должно включить бедуинское население Негева и городских арабов центра.", "speaker_name": "Вы", "correct_option": 2}]', '[{"he": "דוקטורט", "ru": "докторская диссертация", "translit": "дОкторат"}, {"he": "מתודולוגיה", "ru": "методология", "translit": "методолОгия"}, {"he": "מעבר קוד", "ru": "переключение кодов", "translit": "маавАр код"}, {"he": "דו-לשוני", "ru": "двуязычный", "translit": "ду-лешонИ"}, {"he": "מדגם", "ru": "выборка", "translit": "мидгАм"}, {"he": "מגבלה", "ru": "ограничение", "translit": "магбалА"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (24, 6, 'Деловые переговоры', 'Вы ведёте деловые переговоры с израильской компанией.', '[{"is_user": false, "speaker": "א", "text_he": "נעים מאוד. בואו נדבר תכלס. מה ההצעה שלכם?", "text_ru": "Очень приятно. Давайте поговорим по делу. Какое ваше предложение?", "speaker_name": "Директор"}, {"is_user": true, "options": ["יש לנו הצעה טובה.", "אנחנו מציעים שותפות בתחום פיתוח התוכנה. הנה התנאים.", "אנחנו מעוניינים לעבוד אתכם."], "speaker": "ב", "text_he": "אנחנו מציעים שותפות בתחום פיתוח התוכנה. הנה התנאים.", "text_ru": "Мы предлагаем партнёрство в области разработки ПО. Вот условия.", "speaker_name": "Вы", "correct_option": 1}, {"is_user": false, "speaker": "א", "text_he": "מעניין. לגבי התקציב — מה אתם מוכנים להשקיע?", "text_ru": "Интересно. Что касается бюджета — сколько вы готовы инвестировать?", "speaker_name": "Директор"}, {"is_user": true, "options": ["התקציב שלנו לשנה הראשונה הוא שני מיליון דולר.", "זה גמיש.", "צריך לבדוק."], "speaker": "ב", "text_he": "התקציב שלנו לשנה הראשונה הוא שני מיליון דולר.", "text_ru": "Наш бюджет на первый год — два миллиона долларов.", "speaker_name": "Вы", "correct_option": 0}]', '[{"he": "תכלס", "ru": "конкретно/по делу", "translit": "тахлЕс"}, {"he": "שותפות", "ru": "партнёрство", "translit": "шутафУт"}, {"he": "תנאים", "ru": "условия", "translit": "тнаИм"}, {"he": "תקציב", "ru": "бюджет", "translit": "такцИв"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (25, 3, 'В банке: открываем счёт', 'Вы — новый репатриант (עולה חדש). Пришли в банк открыть счёт.', '[{"is_user": false, "speaker": "א", "text_he": "שלום! במה אוכל לעזור?", "text_ru": "Здравствуйте! Чем могу помочь?", "speaker_name": "Служащий"}, {"is_user": true, "options": ["אני צריך כסף.", "איפה הכספומט?", "אני רוצה לפתוח חשבון בנק."], "speaker": "ב", "text_he": "אני רוצה לפתוח חשבון בנק.", "text_ru": "Я хочу открыть банковский счёт.", "speaker_name": "Вы", "correct_option": 2}, {"is_user": false, "speaker": "א", "text_he": "בשמחה. יש לך תעודת זהות?", "text_ru": "С удовольствием. У вас есть удостоверение личности?", "speaker_name": "Служащий"}, {"is_user": true, "options": ["לא, שכחתי בבית.", "כן. אני עולה חדש, הגעתי לפני חודש.", "מה זה תעודת זהות?"], "speaker": "ב", "text_he": "כן. אני עולה חדש, הגעתי לפני חודש.", "text_ru": "Да. Я новый репатриант, приехал месяц назад.", "speaker_name": "Вы", "correct_option": 1}, {"is_user": false, "speaker": "א", "text_he": "מצוין! לעולים חדשים יש תנאים מיוחדים. אתה רוצה גם כרטיס אשראי?", "text_ru": "Отлично! Для новых репатриантов есть особые условия. Хотите также кредитную карту?", "speaker_name": "Служащий"}, {"is_user": true, "options": ["כמה עולה כרטיס אשראי?", "לא, תודה.", "כן, ואני רוצה לשאול — אפשר להעביר כסף מחוץ לארץ?"], "speaker": "ב", "text_he": "כן, ואני רוצה לשאול — אפשר להעביר כסף מחוץ לארץ?", "text_ru": "Да, и хочу спросить — можно перевести деньги из-за границы?", "speaker_name": "Вы", "correct_option": 2}, {"is_user": false, "speaker": "א", "text_he": "בוודאי. תמלא את הטפסים האלה ונסדר הכול. הסיסמה לאתר תגיע ב-SMS.", "text_ru": "Конечно. Заполните эти бланки, и мы всё оформим. Пароль от сайта придёт по SMS.", "speaker_name": "Служащий"}]', '[{"he": "חשבון בנק", "ru": "банковский счёт", "translit": "хешбОн банк"}, {"he": "תעודת זהות", "ru": "удостоверение личности", "translit": "теудАт зеhУт"}, {"he": "עולה חדש", "ru": "новый репатриант", "translit": "олЕ хадАш"}, {"he": "כרטיס אשראי", "ru": "кредитная карта", "translit": "картИс ашрАй"}, {"he": "טופס", "ru": "бланк / форма", "translit": "тОфес"}, {"he": "להעביר כסף", "ru": "перевести деньги", "translit": "леhаавИр кЕсеф"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (26, 3, 'Снимаем квартиру: осмотр', 'Вы нашли объявление на «Яд 2» и пришли смотреть квартиру.', '[{"is_user": false, "speaker": "א", "text_he": "שלום! בוא, אני אראה לך את הדירה. יש פה שני חדרים, סלון ומרפסת.", "text_ru": "Привет! Заходи, покажу квартиру. Тут две комнаты, гостиная и балкон.", "speaker_name": "Хозяин"}, {"is_user": true, "options": ["גדול מדי.", "יפה. כמה עולה השכירות?", "אני לא בטוח."], "speaker": "ב", "text_he": "יפה. כמה עולה השכירות?", "text_ru": "Красиво. Сколько стоит аренда?", "speaker_name": "Вы", "correct_option": 1}, {"is_user": false, "speaker": "א", "text_he": "ארבעת אלפים שקל לחודש, לא כולל ארנונה וחשבונות.", "text_ru": "Четыре тысячи шекелей в месяц, без арноны и коммунальных.", "speaker_name": "Хозяин"}, {"is_user": true, "options": ["יקר מדי.", "כמה הארנונה? ויש ועד בית?", "מתי אפשר להיכנס?"], "speaker": "ב", "text_he": "כמה הארנונה? ויש ועד בית?", "text_ru": "А сколько арнона? И есть ли домовой комитет?", "speaker_name": "Вы", "correct_option": 1}, {"is_user": false, "speaker": "א", "text_he": "ארנונה — שש מאות לחודשיים. ועד בית — מאה חמישים בחודש.", "text_ru": "Арнона — шестьсот за два месяца. Домовой комитет — сто пятьдесят в месяц.", "speaker_name": "Хозяин"}, {"is_user": true, "options": ["אני רוצה לחתום עכשיו.", "אני צריך לחשוב.", "מה לגבי ערבות ופיקדון?"], "speaker": "ב", "text_he": "מה לגבי ערבות ופיקדון?", "text_ru": "Какой залог нужен?", "speaker_name": "Вы", "correct_option": 2}, {"is_user": false, "speaker": "א", "text_he": "שלושה שיקים לביטחון ופיקדון של חודשיים. אני אשלח לך את החוזה במייל.", "text_ru": "Три чека для обеспечения и залог за два месяца. Пришлю договор на email.", "speaker_name": "Хозяин"}]', '[{"he": "דירה", "ru": "квартира", "translit": "дирА"}, {"he": "שכירות", "ru": "аренда", "translit": "схирУт"}, {"he": "ארנונה", "ru": "муниципальный налог", "translit": "арнонА"}, {"he": "ועד בית", "ru": "домовой комитет", "translit": "ваАд бАйит"}, {"he": "שיק", "ru": "чек", "translit": "шик"}, {"he": "פיקדון", "ru": "залог", "translit": "пикадОн"}, {"he": "חוזה", "ru": "договор", "translit": "хозЕ"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (27, 3, 'На почте: отправляем посылку', 'Вы отправляете посылку с подарками родным за границу.', '[{"is_user": false, "speaker": "א", "text_he": "הבא בתור! שים את החבילה על המשקל, בבקשה. מה יש בפנים?", "text_ru": "Следующий! Поставьте посылку на весы, пожалуйста. Что внутри?", "speaker_name": "Служащий"}, {"is_user": true, "options": ["זה מתנה.", "אני לא יודע מה בפנים.", "ספרים ושוקולד. אני רוצה לשלוח לרוסיה."], "speaker": "ב", "text_he": "ספרים ושוקולד. אני רוצה לשלוח לרוסיה.", "text_ru": "Книги и шоколад. Хочу отправить в Россию.", "speaker_name": "Вы", "correct_option": 2}, {"is_user": false, "speaker": "א", "text_he": "שני קילו. רוצה משלוח רגיל או דואר רשום?", "text_ru": "Два кило. Хотите обычную доставку или заказное?", "speaker_name": "Служащий"}, {"is_user": true, "options": ["הכי זול.", "מה ההבדל במחיר?", "רשום, בבקשה."], "speaker": "ב", "text_he": "מה ההבדל במחיר?", "text_ru": "А какая разница в цене?", "speaker_name": "Вы", "correct_option": 1}, {"is_user": false, "speaker": "א", "text_he": "רגיל — שמונים שקל. רשום — מאה עשרים, אבל מקבלים מספר מעקב.", "text_ru": "Обычная — восемьдесят шекелей. Заказная — сто двадцать, но получите номер отслеживания.", "speaker_name": "Служащий"}, {"is_user": true, "options": ["אני אחשוב על זה.", "רגיל מספיק.", "רשום, בבקשה. כמה זמן לוקח?"], "speaker": "ב", "text_he": "רשום, בבקשה. כמה זמן לוקח?", "text_ru": "Заказное, пожалуйста. Сколько времени идёт?", "speaker_name": "Вы", "correct_option": 2}, {"is_user": false, "speaker": "א", "text_he": "שבועיים עד שלושה. תמלא את הטופס עם הכתובת. אפשר לשלם בכרטיס.", "text_ru": "Две-три недели. Заполните бланк с адресом. Можно оплатить картой.", "speaker_name": "Служащий"}]', '[{"he": "חבילה", "ru": "посылка", "translit": "хавилА"}, {"he": "משקל", "ru": "весы", "translit": "мишкАль"}, {"he": "דואר רשום", "ru": "заказное письмо", "translit": "доАр рашУм"}, {"he": "מספר מעקב", "ru": "номер отслеживания", "translit": "миспАр маакАв"}, {"he": "כתובת", "ru": "адрес", "translit": "ктОвет"}, {"he": "קבלה", "ru": "квитанция", "translit": "кабалА"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (29, 4, 'Страховая компания: оформление полиса', 'Вы оформляете страховку на квартиру.', '[{"is_user": false, "speaker": "א", "text_he": "שלום! אני מבינה שאתה מחפש ביטוח דירה?", "text_ru": "Здравствуйте! Я так понимаю, вы ищете страховку на квартиру?", "speaker_name": "Агент"}, {"is_user": true, "options": ["מה זה ביטוח דירה?", "כן, רק שכרתי דירה ובעל הבית ביקש שאבטח אותה.", "כן, כמה זה עולה?"], "speaker": "ב", "text_he": "כן, רק שכרתי דירה ובעל הבית ביקש שאבטח אותה.", "text_ru": "Да, я только что снял квартиру и хозяин попросил застраховать.", "speaker_name": "Вы", "correct_option": 1}, {"is_user": false, "speaker": "א", "text_he": "הבנתי. יש כמה רמות כיסוי: מבנה בלבד, מבנה ותכולה, או פוליסה מקיפה שכוללת צד שלישי.", "text_ru": "Понятно. Есть несколько уровней покрытия: только здание, здание и содержимое, или полный полис, включающий ответственность перед третьими лицами.", "speaker_name": "Агент"}, {"is_user": true, "options": ["רק מבנה מספיק.", "אני צריך מקיף. כמה זה בחודש?", "אני אחשוב על זה."], "speaker": "ב", "text_he": "אני צריך מקיף. כמה זה בחודש?", "text_ru": "Мне нужен полный. Сколько стоит в месяц?", "speaker_name": "Вы", "correct_option": 1}, {"is_user": false, "speaker": "א", "text_he": "בערך מאה שקל בחודש. אני שולחת הצעה למייל עם כל הפרטים.", "text_ru": "Примерно сто шекелей в месяц. Пришлю предложение на email со всеми деталями.", "speaker_name": "Агент"}]', '[{"he": "ביטוח", "ru": "страховка", "translit": "битУах"}, {"he": "כיסוי", "ru": "покрытие", "translit": "кисУй"}, {"he": "תכולה", "ru": "содержимое", "translit": "тхулА"}, {"he": "פוליסה", "ru": "полис", "translit": "полИса"}, {"he": "צד שלישי", "ru": "третья сторона", "translit": "цад шлишИ"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (30, 4, 'Родительское собрание в школе', 'Вы пришли на родительское собрание в израильской школе.', '[{"is_user": false, "speaker": "א", "text_he": "שלום, ברוכים הבאים לאסיפת הורים. בוא נדבר על ההתקדמות של הילד שלך.", "text_ru": "Добро пожаловать на родительское собрание. Давайте поговорим об успехах вашего ребёнка.", "speaker_name": "Учительница"}, {"is_user": true, "options": ["תודה. איך הוא מסתדר בלימודים?", "הוא מתלונן שקשה.", "הכול בסדר?"], "speaker": "ב", "text_he": "תודה. איך הוא מסתדר בלימודים?", "text_ru": "Спасибо. Как он учится?", "speaker_name": "Вы", "correct_option": 0}, {"is_user": false, "speaker": "א", "text_he": "במתמטיקה ובמדעים הוא מצטיין. בעברית צריך קצת יותר תרגול, במיוחד בכתיבה.", "text_ru": "В математике и естественных науках он отличник. В иврите нужно чуть больше практики, особенно в письме.", "speaker_name": "Учительница"}, {"is_user": true, "options": ["אנחנו נתאמץ.", "זה בגלל שהוא לא קורא מספיק.", "מובן. אנחנו עלינו לא מזמן. מה את ממליצה?"], "speaker": "ב", "text_he": "מובן. אנחנו עלינו לא מזמן. מה את ממליצה?", "text_ru": "Понимаю. Мы недавно приехали. Что вы рекомендуете?", "speaker_name": "Вы", "correct_option": 2}, {"is_user": false, "speaker": "א", "text_he": "אני ממליצה על שיעורי עזר פעמיים בשבוע. גם קריאת ספרים בעברית מאוד עוזרת.", "text_ru": "Рекомендую дополнительные занятия дважды в неделю. Также очень помогает чтение книг на иврите.", "speaker_name": "Учительница"}]', '[{"he": "אסיפת הורים", "ru": "родительское собрание", "translit": "асифАт hорИм"}, {"he": "התקדמות", "ru": "прогресс/успехи", "translit": "hиткадмУт"}, {"he": "מצטיין", "ru": "отличник", "translit": "мицтайЕн"}, {"he": "שיעורי עזר", "ru": "дополнительные занятия", "translit": "шиурЕй Эзер"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (31, 4, 'Продвинутое собеседование: обсуждение условий', 'Вам предложили работу. Обсуждаете условия с HR.', '[{"is_user": false, "speaker": "א", "text_he": "אנחנו שמחים להציע לך את המשרה. בוא נדבר על תנאי ההעסקה.", "text_ru": "Мы рады предложить вам должность. Давайте обсудим условия.", "speaker_name": "HR"}, {"is_user": true, "options": ["תודה, אני מסכים.", "תודה, אני שמח. מה המשכורת המוצעת?", "מתי מתחילים?"], "speaker": "ב", "text_he": "תודה, אני שמח. מה המשכורת המוצעת?", "text_ru": "Спасибо, я рад. Какой предлагается оклад?", "speaker_name": "Вы", "correct_option": 1}, {"is_user": false, "speaker": "א", "text_he": "השכר הבסיסי הוא חמש עשרה אלף שקל ברוטו. בנוסף יש קרן השתלמות, פנסיה וימי חופשה.", "text_ru": "Базовый оклад — пятнадцать тысяч шекелей брутто. Плюс учебный фонд, пенсия и отпускные.", "speaker_name": "HR"}, {"is_user": true, "options": ["אני מסכים לתנאים.", "אני צריך יותר.", "יש אפשרות לעבודה מהבית?"], "speaker": "ב", "text_he": "יש אפשרות לעבודה מהבית?", "text_ru": "Есть ли возможность удалённой работы?", "speaker_name": "Вы", "correct_option": 2}, {"is_user": false, "speaker": "א", "text_he": "כן, המודל שלנו הוא היברידי — שלושה ימים במשרד ושניים מהבית. נשלח לך את החוזה למייל.", "text_ru": "Да, у нас гибридная модель — три дня в офисе и два из дома. Пришлём договор на email.", "speaker_name": "HR"}]', '[{"he": "משרה", "ru": "должность", "translit": "масрА"}, {"he": "תנאי העסקה", "ru": "условия найма", "translit": "тнаЕй hаасакА"}, {"he": "משכורת", "ru": "зарплата", "translit": "маскОрет"}, {"he": "קרן השתלמות", "ru": "учебный фонд", "translit": "кЕрен hиштальмУт"}, {"he": "עבודה מהבית", "ru": "удалённая работа", "translit": "аводА мэ-hа-бАйит"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (32, 5, 'Академическая дискуссия: семинар', 'Вы участвуете в университетском семинаре. Обсуждение научной статьи.', '[{"is_user": false, "speaker": "א", "text_he": "בואו נדון במאמר של פרופסור לוי. מה הטענה המרכזית שלו?", "text_ru": "Давайте обсудим статью профессора Леви. Каков его основной тезис?", "speaker_name": "Профессор"}, {"is_user": true, "options": ["לדעתי, הוא טוען שזהות היא מושג משתנה.", "אני לא מסכים איתו.", "המאמר היה קשה להבנה."], "speaker": "ב", "text_he": "לדעתי, הוא טוען שזהות היא מושג משתנה.", "text_ru": "По моему мнению, он утверждает, что идентичность — понятие изменчивое.", "speaker_name": "Вы", "correct_option": 0}, {"is_user": false, "speaker": "א", "text_he": "נכון. ובנוסף לכך, הוא מצביע על כך שהשפה משפיעה על תפיסת הזהות. מה דעתכם?", "text_ru": "Верно. Кроме того, он указывает, что язык влияет на восприятие идентичности. Что скажете?", "speaker_name": "Профессор"}, {"is_user": true, "options": ["אני חושב שהעברית היא דוגמה מצוינת. תחיית השפה יצרה זהות חדשה.", "זה נושא מורכב מדי.", "אני צריך לקרוא עוד."], "speaker": "ב", "text_he": "אני חושב שהעברית היא דוגמה מצוינת. תחיית השפה יצרה זהות חדשה.", "text_ru": "Я думаю, что иврит — прекрасный пример. Возрождение языка создало новую идентичность.", "speaker_name": "Вы", "correct_option": 0}]', '[{"he": "טענה", "ru": "тезис / утверждение", "translit": "таанА"}, {"he": "מושג", "ru": "понятие", "translit": "мусАг"}, {"he": "משתנה", "ru": "изменчивый", "translit": "миштанЕ"}, {"he": "תחייה", "ru": "возрождение", "translit": "тхийА"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (33, 5, 'Радио-интервью: культура и общество', 'Вас пригласили на радио как эксперта по интеграции репатриантов.', '[{"is_user": false, "speaker": "א", "text_he": "שלום ותודה שבאת. ספר לנו — מה האתגר הגדול ביותר של עולים חדשים?", "text_ru": "Здравствуйте, спасибо что пришли. Расскажите — каков главный вызов для новых репатриантов?", "speaker_name": "Ведущий"}, {"is_user": true, "options": ["האתגר הגדול ביותר הוא השפה. בלי עברית אי אפשר להשתלב באמת.", "הכול קשה.", "המצב משתפר."], "speaker": "ב", "text_he": "האתגר הגדול ביותר הוא השפה. בלי עברית אי אפשר להשתלב באמת.", "text_ru": "Главный вызов — язык. Без иврита невозможно по-настоящему интегрироваться.", "speaker_name": "Вы", "correct_option": 0}, {"is_user": false, "speaker": "א", "text_he": "ומה לגבי התרומה של עולים לחברה הישראלית?", "text_ru": "А что насчёт вклада репатриантов в израильское общество?", "speaker_name": "Ведущий"}, {"is_user": true, "options": ["אני לא בטוח.", "כל עולה תורם בדרכו.", "התרומה עצומה. עולים מברית המועצות לשעבר שינו את ההייטק, הרפואה והתרבות."], "speaker": "ב", "text_he": "התרומה עצומה. עולים מברית המועצות לשעבר שינו את ההייטק, הרפואה והתרבות.", "text_ru": "Вклад огромный. Репатрианты из бывшего СССР изменили хай-тек, медицину и культуру.", "speaker_name": "Вы", "correct_option": 2}]', '[{"he": "עולה חדש", "ru": "новый репатриант", "translit": "олЕ хадАш"}, {"he": "להשתלב", "ru": "интегрироваться", "translit": "леhишталЕв"}, {"he": "תרומה", "ru": "вклад", "translit": "трумА"}, {"he": "עצומה", "ru": "огромная", "translit": "ацумА"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (34, 5, 'Литературный вечер: обсуждение книги', 'На литературном вечере обсуждают книгу Этгара Керета.', '[{"is_user": false, "speaker": "א", "text_he": "הסיפור הזה של כרת — מה הוא אומר לכם?", "text_ru": "Этот рассказ Керета — что он говорит вам?", "speaker_name": "Ведущий"}, {"is_user": true, "options": ["נראה לי שכרת כותב על אנשים פשוטים, אבל נוגע בנושאים עמוקים.", "הסיפור מצחיק.", "לא אהבתי את הסיפור."], "speaker": "ב", "text_he": "נראה לי שכרת כותב על אנשים פשוטים, אבל נוגע בנושאים עמוקים.", "text_ru": "Мне кажется, Керет пишет о простых людях, но касается глубоких тем.", "speaker_name": "Вы", "correct_option": 0}, {"is_user": false, "speaker": "א", "text_he": "יפה מאוד. ומה לגבי השפה שלו — למה הוא בוחר מילים כל כך פשוטות?", "text_ru": "Прекрасно. А что насчёт его языка — почему он выбирает такие простые слова?", "speaker_name": "Ведущий"}, {"is_user": true, "options": ["זה סגנון שלו.", "אולי הוא לא יודע מילים קשות.", "דווקא הפשטות עושה את הפרוזה שלו חזקה. מאחורי הקלילות מסתתר כאב."], "speaker": "ב", "text_he": "דווקא הפשטות עושה את הפרוזה שלו חזקה. מאחורי הקלילות מסתתר כאב.", "text_ru": "Именно простота делает его прозу сильной. За лёгкостью скрывается боль.", "speaker_name": "Вы", "correct_option": 2}]', '[{"he": "סיפור", "ru": "рассказ", "translit": "сипУр"}, {"he": "פרוזה", "ru": "проза", "translit": "прОза"}, {"he": "פשטות", "ru": "простота", "translit": "паштУт"}, {"he": "קלילות", "ru": "лёгкость", "translit": "калилУт"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (53, 6, 'Юридическая консультация: трудовой спор', 'Вы консультируетесь с адвокатом по вопросу незаконного увольнения и нарушения трудового договора.', '[{"is_user": false, "speaker": "א", "text_he": "שלום, ספר לי על המקרה. מתי פוטרת ובאילו נסיבות?", "text_ru": "Здравствуйте, расскажите о вашем деле. Когда вас уволили и при каких обстоятельствах?", "speaker_name": "Адвокат"}, {"is_user": true, "options": ["פיטרו אותי ואני כועס.", "אני רוצה לתבוע את המעסיק.", "פוטרתי לפני שבועיים ללא שימוע מוקדם, למרות שעבדתי בחברה ארבע שנים. לא קיבלתי נימוק בכתב, ותנאי הפיצויים אינם תואמים את המפורט בחוזה."], "speaker": "ב", "text_he": "פוטרתי לפני שבועיים ללא שימוע מוקדם, למרות שעבדתי בחברה ארבע שנים. לא קיבלתי נימוק בכתב, ותנאי הפיצויים אינם תואמים את המפורט בחוזה.", "text_ru": "Меня уволили две недели назад без предварительного слушания, несмотря на то что я работал в компании четыре года. Мне не предоставили обоснования в письменном виде, а условия компенсации не соответствуют тому, что прописано в контракте.", "speaker_name": "Вы", "correct_option": 2}, {"is_user": false, "speaker": "א", "text_he": "זהו מקרה חמור. על פי חוק, עובד שהשלים שנה ומעלה זכאי לשימוע לפני פיטורים. אי-קיום השימוע מהווה עילה לתביעה. האם יש לך עותק מחוזה העבודה ומכתב הפיטורים?", "text_ru": "Это серьёзный случай. По закону, работник, отработавший год и более, имеет право на слушание перед увольнением. Неисполнение слушания является основанием для иска. У вас есть копия трудового договора и уведомление об увольнении?", "speaker_name": "Адвокат"}, {"is_user": true, "options": ["אין לי שום מסמכים.", "יש לי את החוזה אבל לא את המכתב.", "כן, שני המסמכים ברשותי. בנוסף, שמרתי התכתבות בדוא\"ל שבה המנהל הביע שביעות רצון מעבודתי חודש לפני הפיטורים. זה סותר את הנימוק שנטען — ביצועים לא מספקים."], "speaker": "ב", "text_he": "כן, שני המסמכים ברשותי. בנוסף, שמרתי התכתבות בדוא\"ל שבה המנהל הביע שביעות רצון מעבודתי חודש לפני הפיטורים. זה סותר את הנימוק שנטען — ביצועים לא מספקים.", "text_ru": "Да, у меня есть оба документа. Кроме того, у меня сохранилась переписка по электронной почте, в которой руководитель выражал удовлетворённость моей работой ещё за месяц до увольнения. Это противоречит заявленной причине — недостаточная производительность.", "speaker_name": "Вы", "correct_option": 2}, {"is_user": false, "speaker": "א", "text_he": "מצוין, ההתכתבויות האלה הן ראיה חשובה ביותר. אני ממליץ להגיש תביעה לבית הדין לעבודה. נתבע פיצויי פיטורים מלאים בצירוף פיצוי על העדר שימוע ועוגמת נפש. הסיכויים לפסק דין לטובתך גבוהים.", "text_ru": "Отлично, эта переписка — важнейшее доказательство. Я рекомендую подать иск в трудовой суд. Мы потребуем полное выходное пособие плюс компенсацию за отсутствие слушания и моральный ущерб. Шансы на решение в вашу пользу высоки.", "speaker_name": "Адвокат"}, {"is_user": true, "options": ["כמה זה יעלה לי?", "מהם לוחות הזמנים לדיון ומה שכר הטרחה שלך עבור ניהול התיק?", "אני צריך לחשוב על זה."], "speaker": "ב", "text_he": "מהם לוחות הזמנים לדיון ומה שכר הטרחה שלך עבור ניהול התיק?", "text_ru": "Каковы сроки рассмотрения и ваш гонорар за ведение дела?", "speaker_name": "Вы", "correct_option": 1}, {"is_user": false, "speaker": "א", "text_he": "ההליך נמשך בדרך כלל בין ששה חודשים לשנה. שכר הטרחה שלי הוא על בסיס הצלחה — עשרים וחמישה אחוז מסכום הפיצויים שייפסקו. אם לא נזכה — לא תשלם.", "text_ru": "Процесс обычно длится от шести месяцев до года. Мой гонорар — на основе успеха — двадцать пять процентов от присуждённой суммы компенсации. Если проиграем — вы не платите.", "speaker_name": "Адвокат"}]', '[{"he": "שימוע", "ru": "слушание (перед увольнением)", "translit": "шимУа"}, {"he": "פיצויי פיטורים", "ru": "выходное пособие", "translit": "пицуйЕй питурИм"}, {"he": "עילת תביעה", "ru": "основание для иска", "translit": "илАт твиА"}, {"he": "בית הדין לעבודה", "ru": "трудовой суд", "translit": "бейт hа-дИн лааводА"}, {"he": "שכר טרחה", "ru": "гонорар", "translit": "схАр тирхА"}, {"he": "עוגמת נפש", "ru": "моральный ущерб", "translit": "огмАт нЕфеш"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (35, 5, 'Конференция по технологиям: дискуссионная панель', 'Вы участвуете в панельной дискуссии на технологической конференции.', '[{"is_user": false, "speaker": "א", "text_he": "בואו נדבר על העתיד של הבינה המלאכותית. מה דעתכם?", "text_ru": "Давайте поговорим о будущем искусственного интеллекта. Ваше мнение?", "speaker_name": "Модератор"}, {"is_user": true, "options": ["זה נושא מפחיד.", "אני אופטימי.", "לדעתי, הבינה המלאכותית תשנה את כל התחומים. השאלה היא איך נתכונן לזה."], "speaker": "ב", "text_he": "לדעתי, הבינה המלאכותית תשנה את כל התחומים. השאלה היא איך נתכונן לזה.", "text_ru": "На мой взгляд, ИИ изменит все отрасли. Вопрос — как мы к этому подготовимся.", "speaker_name": "Вы", "correct_option": 2}, {"is_user": false, "speaker": "א", "text_he": "ומה התפקיד של ישראל בתחום הזה?", "text_ru": "А какова роль Израиля в этой области?", "speaker_name": "Модератор"}, {"is_user": true, "options": ["ישראל קטנה מדי.", "צריך להשקיע יותר.", "ישראל מובילה בסייבר ובניתוח נתונים. זה בסיס לפיתוח בינה מלאכותית."], "speaker": "ב", "text_he": "ישראל מובילה בסייבר ובניתוח נתונים. זה בסיס לפיתוח בינה מלאכותית.", "text_ru": "Израиль — лидер в кибербезопасности и анализе данных. Это база для развития ИИ.", "speaker_name": "Вы", "correct_option": 2}]', '[{"he": "בינה מלאכותית", "ru": "искусственный интеллект", "translit": "бинА мелахутИт"}, {"he": "סייבר", "ru": "кибербезопасность", "translit": "сАйбер"}, {"he": "ניתוח נתונים", "ru": "анализ данных", "translit": "нитУах нетунИм"}, {"he": "להתכונן", "ru": "подготовиться", "translit": "леhитконЕн"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (40, 1, 'В школе: первый день', 'Первый день в новой школе. Поговорите с учителем.', '[{"is_user": false, "speaker": "א", "text_he": "בוקר טוב! ברוך הבא לכיתה שלנו. מה שמך?", "text_ru": "Доброе утро! Добро пожаловать в наш класс. Как тебя зовут?", "speaker_name": "Учитель"}, {"is_user": true, "options": ["בוקר טוב! שמי אלכס. אני תלמיד חדש.", "שלום! אני רוצה ללכת הביתה.", "בוקר טוב! אני לא יודע."], "speaker": "ב", "text_he": "בוקר טוב! שמי אלכס. אני תלמיד חדש.", "text_ru": "Доброе утро! Меня зовут Алекс. Я новый ученик.", "speaker_name": "Вы", "correct_option": 0}, {"is_user": false, "speaker": "א", "text_he": "נעים מאוד, אלכס! אתה יושב פה, ליד דנה. יש לך מחברת ועט?", "text_ru": "Очень приятно, Алекс! Ты сидишь здесь, рядом с Даной. У тебя есть тетрадь и ручка?", "speaker_name": "Учитель"}, {"is_user": true, "options": ["מה זה מחברת?", "כן, יש לי. תודה!", "לא, אין לי כלום."], "speaker": "ב", "text_he": "כן, יש לי. תודה!", "text_ru": "Да, у меня есть. Спасибо!", "speaker_name": "Вы", "correct_option": 1}, {"is_user": false, "speaker": "א", "text_he": "מצוין! אנחנו לומדים עכשיו עברית. פתח את הספר בעמוד עשר.", "text_ru": "Отлично! Сейчас мы учим иврит. Открой книгу на странице десять.", "speaker_name": "Учитель"}]', '[{"he": "תלמיד", "ru": "ученик", "translit": "талмИд"}, {"he": "כיתה", "ru": "класс", "translit": "китА"}, {"he": "מחברת", "ru": "тетрадь", "translit": "махбЕрет"}, {"he": "עמוד", "ru": "страница", "translit": "амУд"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (41, 1, 'Знакомство с соседом', 'Вы встречаете нового соседа в подъезде.', '[{"is_user": false, "speaker": "א", "text_he": "שלום! אתה גר פה? אני לא מכיר אותך.", "text_ru": "Привет! Ты живёшь здесь? Я тебя не знаю.", "speaker_name": "Сосед"}, {"is_user": true, "options": ["שלום! אני לא גר פה.", "שלום! כן, אני שכן חדש. אני גר בקומה שלוש.", "שלום! אני מחפש את הדואר."], "speaker": "ב", "text_he": "שלום! כן, אני שכן חדש. אני גר בקומה שלוש.", "text_ru": "Привет! Да, я новый сосед. Я живу на третьем этаже.", "speaker_name": "Вы", "correct_option": 1}, {"is_user": false, "speaker": "א", "text_he": "נעים מאוד! אני יוסי. אני גר בקומה שתיים. מאיפה אתה?", "text_ru": "Очень приятно! Я Йоси. Живу на втором этаже. Откуда ты?", "speaker_name": "Сосед"}, {"is_user": true, "options": ["אני מרוסיה. אני פה חודש.", "אני מאמריקה. אני פה שנה.", "אני לא רוצה לספר."], "speaker": "ב", "text_he": "אני מרוסיה. אני פה חודש.", "text_ru": "Я из России. Я здесь месяц.", "speaker_name": "Вы", "correct_option": 0}, {"is_user": false, "speaker": "א", "text_he": "מגניב! אם אתה צריך עזרה — אני פה. בהצלחה!", "text_ru": "Здорово! Если тебе нужна помощь — я здесь. Удачи!", "speaker_name": "Сосед"}]', '[{"he": "שכן", "ru": "сосед", "translit": "шахЕн"}, {"he": "קומה", "ru": "этаж", "translit": "комА"}, {"he": "עזרה", "ru": "помощь", "translit": "эзрА"}, {"he": "חודש", "ru": "месяц", "translit": "хОдеш"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (42, 2, 'На почте: отправка письма', 'Вы пришли на почту отправить письмо и посылку за границу.', '[{"is_user": false, "speaker": "א", "text_he": "שלום, מה אתה צריך?", "text_ru": "Здравствуйте, что вам нужно?", "speaker_name": "Почтовый работник"}, {"is_user": true, "options": ["שלום. אני רוצה לשלוח מכתב לרוסיה וחבילה לאמריקה.", "שלום. כמה עולה בול?", "שלום. אני מחפש את הכתובת שלי."], "speaker": "ב", "text_he": "שלום. אני רוצה לשלוח מכתב לרוסיה וחבילה לאמריקה.", "text_ru": "Здравствуйте. Я хочу отправить письмо в Россию и посылку в Америку.", "speaker_name": "Вы", "correct_option": 0}, {"is_user": false, "speaker": "א", "text_he": "בסדר. המכתב — דואר רגיל או דואר רשום? וכמה שוקלת החבילה?", "text_ru": "Хорошо. Письмо — обычной или заказной почтой? И сколько весит посылка?", "speaker_name": "Почтовый работник"}, {"is_user": true, "options": ["אני לא בטוח. מה ההבדל?", "רגיל, בבקשה. אני לא יודע כמה שוקלת.", "רשום, בבקשה. החבילה שוקלת שני קילו."], "speaker": "ב", "text_he": "רשום, בבקשה. החבילה שוקלת שני קילו.", "text_ru": "Заказное, пожалуйста. Посылка весит два килограмма.", "speaker_name": "Вы", "correct_option": 2}, {"is_user": false, "speaker": "א", "text_he": "המכתב הרשום — עשרים שקל. החבילה — שמונים שקל. תמלא את הטופס הזה עם הכתובת.", "text_ru": "Заказное письмо — двадцать шекелей. Посылка — восемьдесят шекелей. Заполните этот бланк с адресом.", "speaker_name": "Почтовый работник"}, {"is_user": true, "options": ["בסדר. תוך כמה ימים זה מגיע?", "זה יקר מדי.", "אני אחזור מחר."], "speaker": "ב", "text_he": "בסדר. תוך כמה ימים זה מגיע?", "text_ru": "Хорошо. За сколько дней дойдёт?", "speaker_name": "Вы", "correct_option": 0}, {"is_user": false, "speaker": "א", "text_he": "המכתב — שבוע עד שבועיים. החבילה — בערך עשרה ימים.", "text_ru": "Письмо — неделя-две. Посылка — примерно десять дней.", "speaker_name": "Почтовый работник"}]', '[{"he": "מכתב", "ru": "письмо", "translit": "михтАв"}, {"he": "חבילה", "ru": "посылка", "translit": "хавилА"}, {"he": "דואר רשום", "ru": "заказная почта", "translit": "доАр рашУм"}, {"he": "טופס", "ru": "бланк/форма", "translit": "тОфес"}, {"he": "כתובת", "ru": "адрес", "translit": "ктОвет"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (43, 2, 'Спрашиваем дорогу в городе', 'Вы заблудились в центре города и спрашиваете дорогу к рынку.', '[{"is_user": true, "options": ["סליחה, אתה יודע איך מגיעים לשוק הכרמל?", "סליחה, איפה התחנה?", "סליחה, מה השעה?"], "speaker": "ב", "text_he": "סליחה, אתה יודע איך מגיעים לשוק הכרמל?", "text_ru": "Извините, вы знаете, как дойти до рынка Кармель?", "speaker_name": "Вы", "correct_option": 0}, {"is_user": false, "speaker": "א", "text_he": "כן, בטח! תלך ישר ברחוב הזה עד הרמזור. אחרי הרמזור תפנה שמאלה.", "text_ru": "Да, конечно! Иди прямо по этой улице до светофора. После светофора поверни налево.", "speaker_name": "Прохожий"}, {"is_user": true, "options": ["ישר ואז שמאלה. וזה רחוק מפה?", "אני לא מבין. תגיד עוד פעם.", "תודה, שלום."], "speaker": "ב", "text_he": "ישר ואז שמאלה. וזה רחוק מפה?", "text_ru": "Прямо и потом налево. А это далеко отсюда?", "speaker_name": "Вы", "correct_option": 0}, {"is_user": false, "speaker": "א", "text_he": "לא, זה קרוב. חמש דקות הליכה. תראה שלט גדול בצד שמאל.", "text_ru": "Нет, это близко. Пять минут ходьбы. Увидишь большую вывеску слева.", "speaker_name": "Прохожий"}, {"is_user": true, "options": ["אני אקח מונית.", "מעולה, תודה רבה!", "אני עדיין לא מבין."], "speaker": "ב", "text_he": "מעולה, תודה רבה!", "text_ru": "Отлично, большое спасибо!", "speaker_name": "Вы", "correct_option": 1}, {"is_user": false, "speaker": "א", "text_he": "בכיף! בהצלחה!", "text_ru": "С удовольствием! Удачи!", "speaker_name": "Прохожий"}]', '[{"he": "רמזור", "ru": "светофор", "translit": "рамзОр"}, {"he": "שמאלה", "ru": "налево", "translit": "смОла"}, {"he": "ישר", "ru": "прямо", "translit": "яшАр"}, {"he": "שלט", "ru": "вывеска/табличка", "translit": "шЕлет"}, {"he": "הליכה", "ru": "ходьба", "translit": "hалихА"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (44, 3, 'Собеседование: маркетинг', 'Вы пришли на собеседование на должность координатора по маркетингу.', '[{"is_user": false, "speaker": "א", "text_he": "שלום, שבי בבקשה. ספרי לי קצת על עצמך ועל הניסיון שלך.", "text_ru": "Здравствуйте, присаживайтесь. Расскажите немного о себе и о своём опыте.", "speaker_name": "Менеджер"}, {"is_user": true, "options": ["סיימתי תואר בתקשורת. יש לי שנתיים ניסיון בשיווק דיגיטלי.", "אין לי הרבה ניסיון אבל אני לומדת מהר.", "אני רוצה לעבוד פה."], "speaker": "ב", "text_he": "סיימתי תואר בתקשורת. יש לי שנתיים ניסיון בשיווק דיגיטלי.", "text_ru": "Я окончила университет по специальности коммуникация. У меня два года опыта в цифровом маркетинге.", "speaker_name": "Вы", "correct_option": 0}, {"is_user": false, "speaker": "א", "text_he": "מעניין. מה היה התפקיד הקודם שלך? ואיך ניהלת את הרשתות החברתיות?", "text_ru": "Интересно. Какая была ваша предыдущая должность? И как вы вели социальные сети?", "speaker_name": "Менеджер"}, {"is_user": true, "options": ["אני לא זוכרת בדיוק.", "עשיתי הרבה דברים.", "הייתי רכזת תוכן. יצרתי פוסטים, ניתחתי סטטיסטיקות ועבדתי עם בלוגרים."], "speaker": "ב", "text_he": "הייתי רכזת תוכן. יצרתי פוסטים, ניתחתי סטטיסטיקות ועבדתי עם בלוגרים.", "text_ru": "Я была координатором контента. Я создавала посты, анализировала статистику и работала с блогерами.", "speaker_name": "Вы", "correct_option": 2}, {"is_user": false, "speaker": "א", "text_he": "מצוין. המשרה שלנו כוללת ניהול קמפיינים, עבודה מול לקוחות ודיווח שבועי. את מתחילה בתקופת ניסיון של שלושה חודשים.", "text_ru": "Отлично. Наша должность включает управление кампаниями, работу с клиентами и еженедельную отчётность. Вы начинаете с испытательного срока в три месяца.", "speaker_name": "Менеджер"}, {"is_user": true, "options": ["אני מסכימה לכל דבר.", "מתי אני מתחילה?", "נשמע טוב. אפשר לשאול לגבי המשכורת והתנאים?"], "speaker": "ב", "text_he": "נשמע טוב. אפשר לשאול לגבי המשכורת והתנאים?", "text_ru": "Звучит хорошо. Можно спросить про зарплату и условия?", "speaker_name": "Вы", "correct_option": 2}, {"is_user": false, "speaker": "א", "text_he": "בטח. המשכורת ההתחלתית היא שנים-עשר אלף שקל. יש ימי חופשה, קרן השתלמות ואפשרות לעבודה היברידית.", "text_ru": "Конечно. Начальная зарплата — двенадцать тысяч шекелей. Есть отпускные, учебный фонд и возможность гибридной работы.", "speaker_name": "Менеджер"}]', '[{"he": "שיווק דיגיטלי", "ru": "цифровой маркетинг", "translit": "шивУк дигитАли"}, {"he": "ניסיון", "ru": "опыт", "translit": "нисайОн"}, {"he": "קמפיין", "ru": "кампания", "translit": "кампЕйн"}, {"he": "תקופת ניסיון", "ru": "испытательный срок", "translit": "ткуфАт нисайОн"}, {"he": "קרן השתלמות", "ru": "учебный фонд", "translit": "кЕрен hиштальмУт"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (181, 1, 'בבית קפה: הזמנה', 'Вы заказываете кофе и пирожное в кафе.', '[{"speaker": "מלצר", "text_he": "שלום! מה תרצה להזמין?", "text_ru": "Здравствуйте! Что хотите заказать?"}, {"speaker": "לקוח", "text_he": "אני רוצה קפה עם חלב, בבקשה.", "text_ru": "Я хочу кофе с молоком, пожалуйста."}, {"speaker": "מלצר", "text_he": "קפה גדול או קטן?", "text_ru": "Большой кофе или маленький?"}, {"speaker": "לקוח", "text_he": "גדול, בבקשה. ויש לכם עוגה?", "text_ru": "Большой, пожалуйста. А у вас есть торт?"}, {"speaker": "מלצר", "text_he": "כן! יש עוגת שוקולד ועוגת גבינה.", "text_ru": "Да! Есть шоколадный торт и чизкейк."}, {"speaker": "לקוח", "text_he": "עוגת שוקולד, בבקשה.", "text_ru": "Шоколадный, пожалуйста."}, {"speaker": "מלצר", "text_he": "בסדר. זה ארבעים שקלים.", "text_ru": "Хорошо. Это сорок шекелей."}, {"speaker": "לקוח", "text_he": "הנה. תודה רבה!", "text_ru": "Вот. Большое спасибо!"}]', '[{"word": "מלצר", "translation": "официант", "transliteration": "мельцАр"}, {"word": "להזמין", "translation": "заказать", "transliteration": "лехазмИн"}, {"word": "עוגה", "translation": "торт/пирожное", "transliteration": "угА"}, {"word": "שוקולד", "translation": "шоколад", "transliteration": "шоколАд"}, {"word": "גבינה", "translation": "сыр/творог", "transliteration": "гвинА"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (182, 1, 'בדואר: לשלוח חבילה', 'Вы отправляете посылку на почте.', '[{"speaker": "פקיד", "text_he": "שלום, איך אפשר לעזור?", "text_ru": "Здравствуйте, чем могу помочь?"}, {"speaker": "לקוח", "text_he": "אני רוצה לשלוח חבילה.", "text_ru": "Я хочу отправить посылку."}, {"speaker": "פקיד", "text_he": "לאן?", "text_ru": "Куда?"}, {"speaker": "לקוח", "text_he": "לחיפה.", "text_ru": "В Хайфу."}, {"speaker": "פקיד", "text_he": "מה יש בחבילה?", "text_ru": "Что в посылке?"}, {"speaker": "לקוח", "text_he": "ספר ומתנה קטנה.", "text_ru": "Книга и маленький подарок."}, {"speaker": "פקיד", "text_he": "בסדר. זה חמישה עשר שקלים.", "text_ru": "Хорошо. Это пятнадцать шекелей."}, {"speaker": "לקוח", "text_he": "תודה! מתי החבילה מגיעה?", "text_ru": "Спасибо! Когда посылка приедет?"}, {"speaker": "פקיד", "text_he": "בעוד יומיים.", "text_ru": "Через два дня."}]', '[{"word": "דואר", "translation": "почта", "transliteration": "дОар"}, {"word": "חבילה", "translation": "посылка", "transliteration": "хавилА"}, {"word": "לשלוח", "translation": "отправить", "transliteration": "лишлОах"}, {"word": "מתנה", "translation": "подарок", "transliteration": "матанА"}, {"word": "פקיד", "translation": "служащий", "transliteration": "пакИд"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (183, 1, 'בבית מרקחת: כאב ראש', 'Вы покупаете лекарство от головной боли в аптеке.', '[{"speaker": "רוקח", "text_he": "שלום, מה קורה?", "text_ru": "Здравствуйте, что случилось?"}, {"speaker": "לקוח", "text_he": "יש לי כאב ראש חזק.", "text_ru": "У меня сильная головная боль."}, {"speaker": "רוקח", "text_he": "מזה כמה זמן?", "text_ru": "С какого времени?"}, {"speaker": "לקוח", "text_he": "מהבוקר.", "text_ru": "С утра."}, {"speaker": "רוקח", "text_he": "קח אקמול. כדור אחד כל שש שעות.", "text_ru": "Возьмите акамол. Одну таблетку каждые шесть часов."}, {"speaker": "לקוח", "text_he": "כמה זה עולה?", "text_ru": "Сколько это стоит?"}, {"speaker": "רוקח", "text_he": "עשרים שקלים.", "text_ru": "Двадцать шекелей."}, {"speaker": "לקוח", "text_he": "תודה רבה!", "text_ru": "Большое спасибо!"}]', '[{"word": "בית מרקחת", "translation": "аптека", "transliteration": "бейт миркАхат"}, {"word": "כאב ראש", "translation": "головная боль", "transliteration": "кеЭв рош"}, {"word": "כדור", "translation": "таблетка", "transliteration": "кадУр"}, {"word": "רוקח", "translation": "фармацевт", "transliteration": "рокЕах"}, {"word": "חזק", "translation": "сильный", "transliteration": "хазАк"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (184, 1, 'אצל הרופא: בדיקה', 'Вы на приёме у врача — жалуетесь на боль в горле.', '[{"speaker": "רופא", "text_he": "שלום! מה כואב לך?", "text_ru": "Здравствуйте! Что у вас болит?"}, {"speaker": "מטופל", "text_he": "כואב לי הגרון כבר יומיים.", "text_ru": "У меня болит горло уже два дня."}, {"speaker": "רופא", "text_he": "יש לך חום?", "text_ru": "У вас есть температура?"}, {"speaker": "מטופל", "text_he": "כן, קצת. שלושים ושבע וחצי.", "text_ru": "Да, немного. Тридцать семь с половиной."}, {"speaker": "רופא", "text_he": "תפתח את הפה. אני רואה שהגרון אדום.", "text_ru": "Откройте рот. Я вижу, что горло красное."}, {"speaker": "מטופל", "text_he": "מה אני צריך לעשות?", "text_ru": "Что мне нужно делать?"}, {"speaker": "רופא", "text_he": "לשתות הרבה מים ולנוח. אני כותב לך מרשם.", "text_ru": "Пить много воды и отдыхать. Я выпишу вам рецепт."}, {"speaker": "מטופל", "text_he": "תודה, רופא!", "text_ru": "Спасибо, доктор!"}]', '[{"word": "רופא", "translation": "врач", "transliteration": "рофЕ"}, {"word": "גרון", "translation": "горло", "transliteration": "гарОн"}, {"word": "חום", "translation": "температура", "transliteration": "хом"}, {"word": "מרשם", "translation": "рецепт", "transliteration": "миршАм"}, {"word": "לנוח", "translation": "отдыхать", "transliteration": "ланУах"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (185, 1, 'בשוק: ירקות ופירות', 'Вы покупаете овощи и фрукты на рынке.', '[{"speaker": "מוכר", "text_he": "בואו, בואו! ירקות טריים!", "text_ru": "Подходите, подходите! Свежие овощи!"}, {"speaker": "קונה", "text_he": "כמה עולים העגבניות?", "text_ru": "Сколько стоят помидоры?"}, {"speaker": "מוכר", "text_he": "שמונה שקלים לקילו.", "text_ru": "Восемь шекелей за кило."}, {"speaker": "קונה", "text_he": "יקר! אפשר בשבעה?", "text_ru": "Дорого! Можно за семь?"}, {"speaker": "מוכר", "text_he": "בשבילך — שבע וחצי. וקח גם מלפפונים!", "text_ru": "Для тебя — семь с половиной. И возьми ещё огурцы!"}, {"speaker": "קונה", "text_he": "טוב. קילו עגבניות וקילו מלפפונים.", "text_ru": "Хорошо. Кило помидоров и кило огурцов."}, {"speaker": "מוכר", "text_he": "הנה, בבקשה. חמישה עשר שקלים.", "text_ru": "Вот, пожалуйста. Пятнадцать шекелей."}]', '[{"word": "שוק", "translation": "рынок", "transliteration": "шук"}, {"word": "ירקות", "translation": "овощи", "transliteration": "йеракОт"}, {"word": "טרי", "translation": "свежий", "transliteration": "тарИ"}, {"word": "קילו", "translation": "кило", "transliteration": "кИло"}, {"word": "יקר", "translation": "дорогой", "transliteration": "якАр"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (186, 1, 'במונית: נסיעה לתחנה', 'Вы берёте такси до автовокзала.', '[{"speaker": "נוסע", "text_he": "שלום! לתחנה המרכזית, בבקשה.", "text_ru": "Здравствуйте! На центральный автовокзал, пожалуйста."}, {"speaker": "נהג", "text_he": "בסדר. תשים חגורה.", "text_ru": "Хорошо. Пристегните ремень."}, {"speaker": "נוסע", "text_he": "כמה זמן הנסיעה?", "text_ru": "Сколько времени ехать?"}, {"speaker": "נהג", "text_he": "עשר דקות, אם אין פקק.", "text_ru": "Десять минут, если нет пробки."}, {"speaker": "נוסע", "text_he": "כמה זה עולה?", "text_ru": "Сколько это стоит?"}, {"speaker": "נהג", "text_he": "בערך שלושים שקלים. נוסעים עם מונה.", "text_ru": "Примерно тридцать шекелей. Едем по счётчику."}, {"speaker": "נוסע", "text_he": "טוב, יאללה!", "text_ru": "Хорошо, поехали!"}, {"speaker": "נהג", "text_he": "הגענו. שלושים ושניים שקלים.", "text_ru": "Приехали. Тридцать два шекеля."}]', '[{"word": "מונית", "translation": "такси", "transliteration": "монИт"}, {"word": "תחנה מרכזית", "translation": "центральный автовокзал", "transliteration": "таханА мерказИт"}, {"word": "חגורה", "translation": "ремень безопасности", "transliteration": "хагорА"}, {"word": "פקק", "translation": "пробка (дорожная)", "transliteration": "пкАк"}, {"word": "מונה", "translation": "счётчик", "transliteration": "монЕ"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (187, 1, 'במלון: צ''ק-אין', 'Вы заселяетесь в гостиницу.', '[{"speaker": "פקיד", "text_he": "שלום, ברוכים הבאים! שם, בבקשה?", "text_ru": "Здравствуйте, добро пожаловать! Имя, пожалуйста?"}, {"speaker": "אורח", "text_he": "דניאל כהן. יש לי הזמנה לשלושה לילות.", "text_ru": "Даниэль Коэн. У меня бронь на три ночи."}, {"speaker": "פקיד", "text_he": "כן, אני רואה. חדר 205, קומה שנייה.", "text_ru": "Да, вижу. Комната 205, второй этаж."}, {"speaker": "אורח", "text_he": "יש מעלית?", "text_ru": "Есть лифт?"}, {"speaker": "פקיד", "text_he": "כן, שם בצד ימין.", "text_ru": "Да, там справа."}, {"speaker": "אורח", "text_he": "מתי ארוחת הבוקר?", "text_ru": "Когда завтрак?"}, {"speaker": "פקיד", "text_he": "משבע עד עשר. הנה המפתח. נסיעה נעימה!", "text_ru": "С семи до десяти. Вот ключ. Приятного отдыха!"}]', '[{"word": "מלון", "translation": "гостиница", "transliteration": "малОн"}, {"word": "הזמנה", "translation": "бронь", "transliteration": "хазманА"}, {"word": "חדר", "translation": "комната", "transliteration": "хЕдер"}, {"word": "מעלית", "translation": "лифт", "transliteration": "маалИт"}, {"word": "ארוחת בוקר", "translation": "завтрак", "transliteration": "арухАт бОкер"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (188, 1, 'תלונה: השכן רועש', 'Вы жалуетесь соседу на шум.', '[{"speaker": "שכן א", "text_he": "סליחה, אפשר לדבר?", "text_ru": "Извините, можно поговорить?"}, {"speaker": "שכן ב", "text_he": "כן, בטח. מה קרה?", "text_ru": "Да, конечно. Что случилось?"}, {"speaker": "שכן א", "text_he": "המוזיקה מאוד חזקה. אני לא יכול לישון.", "text_ru": "Музыка очень громкая. Я не могу спать."}, {"speaker": "שכן ב", "text_he": "אוי, סליחה! לא ידעתי.", "text_ru": "Ой, простите! Я не знал."}, {"speaker": "שכן א", "text_he": "אפשר להנמיך אחרי עשר בלילה?", "text_ru": "Можно потише после десяти вечера?"}, {"speaker": "שכן ב", "text_he": "בטח! מצטער. זה לא יקרה שוב.", "text_ru": "Конечно! Извините. Это больше не повторится."}, {"speaker": "שכן א", "text_he": "תודה! לילה טוב.", "text_ru": "Спасибо! Спокойной ночи."}]', '[{"word": "שכן", "translation": "сосед", "transliteration": "шахЕн"}, {"word": "רועש", "translation": "шумный", "transliteration": "роЭш"}, {"word": "לישון", "translation": "спать", "transliteration": "лишОн"}, {"word": "להנמיך", "translation": "убавить (звук)", "transliteration": "леханмИх"}, {"word": "מצטער", "translation": "извините", "transliteration": "мицтаЭр"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (189, 1, 'הזמנת פיצה בטלפון', 'Вы заказываете пиццу по телефону.', '[{"speaker": "עובד", "text_he": "פיצה טובה, שלום!", "text_ru": "Пицца Това, здравствуйте!"}, {"speaker": "לקוח", "text_he": "שלום, אני רוצה להזמין פיצה.", "text_ru": "Здравствуйте, я хочу заказать пиццу."}, {"speaker": "עובד", "text_he": "איזה גודל? גדולה או משפחתית?", "text_ru": "Какой размер? Большая или семейная?"}, {"speaker": "לקוח", "text_he": "גדולה. חצי זיתים וחצי פטריות.", "text_ru": "Большую. Половину с оливками, половину с грибами."}, {"speaker": "עובד", "text_he": "עם גבינה נוספת?", "text_ru": "С дополнительным сыром?"}, {"speaker": "לקוח", "text_he": "כן, בבקשה. מה הכתובת שלכם?", "text_ru": "Да, пожалуйста. Какой у вас адрес?"}, {"speaker": "עובד", "text_he": "אנחנו מביאים! מה הכתובת שלך?", "text_ru": "Мы доставляем! Какой у вас адрес?"}, {"speaker": "לקוח", "text_he": "רחוב הרצל 15, דירה 3.", "text_ru": "Улица Герцля 15, квартира 3."}, {"speaker": "עובד", "text_he": "ארבעים וחמישה שקלים. בעוד חצי שעה!", "text_ru": "Сорок пять шекелей. Через полчаса!"}]', '[{"word": "פיצה", "translation": "пицца", "transliteration": "пИца"}, {"word": "זיתים", "translation": "оливки", "transliteration": "зейтИм"}, {"word": "פטריות", "translation": "грибы", "transliteration": "питриЙот"}, {"word": "כתובת", "translation": "адрес", "transliteration": "ктОвет"}, {"word": "משלוח", "translation": "доставка", "transliteration": "мишлОах"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (190, 1, 'בחוף הים: יום חם', 'Вы на пляже в жаркий день.', '[{"speaker": "דנה", "text_he": "איזה חם היום! בוא נלך לים.", "text_ru": "Как жарко сегодня! Пойдём на море."}, {"speaker": "יוסי", "text_he": "רעיון טוב! אתה לוקח מגבת?", "text_ru": "Хорошая идея! Ты берёшь полотенце?"}, {"speaker": "דנה", "text_he": "כן, ובקבוק מים. אל תשכח קרם שמש!", "text_ru": "Да, и бутылку воды. Не забудь крем от солнца!"}, {"speaker": "יוסי", "text_he": "המים נראים יפים. נכנסים?", "text_ru": "Вода выглядит красиво. Заходим?"}, {"speaker": "דנה", "text_he": "רגע, אני שמה את הדברים על החול.", "text_ru": "Секунду, я положу вещи на песок."}, {"speaker": "יוסי", "text_he": "איזה כיף! המים קרירים!", "text_ru": "Как здорово! Вода прохладная!"}, {"speaker": "דנה", "text_he": "בוא נשחה עד שם ובחזרה.", "text_ru": "Давай поплаваем туда и обратно."}, {"speaker": "יוסי", "text_he": "אחר כך נאכל גלידה?", "text_ru": "Потом съедим мороженое?"}]', '[{"word": "חוף", "translation": "пляж", "transliteration": "хоф"}, {"word": "מגבת", "translation": "полотенце", "transliteration": "магЕвет"}, {"word": "קרם שמש", "translation": "солнцезащитный крем", "transliteration": "крем шЕмеш"}, {"word": "חול", "translation": "песок", "transliteration": "хол"}, {"word": "לשחות", "translation": "плавать", "transliteration": "лисхОт"}, {"word": "גלידה", "translation": "мороженое", "transliteration": "глидА"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (191, 2, 'ראיון עבודה: מזכירה', 'Вы пришли на собеседование на должность секретаря в офисе.', '[{"speaker": "מנהל", "text_he": "שלום, שבי בבקשה. ספרי לי קצת על עצמך.", "text_ru": "Здравствуйте, садитесь. Расскажите немного о себе."}, {"speaker": "מועמדת", "text_he": "שמי מיכל. אני בת עשרים ושמונה. גרתי בחיפה.", "text_ru": "Меня зовут Михаль. Мне двадцать восемь. Я жила в Хайфе."}, {"speaker": "מנהל", "text_he": "יש לך ניסיון במשרד?", "text_ru": "У вас есть опыт офисной работы?"}, {"speaker": "מועמדת", "text_he": "כן, עבדתי שנתיים כמזכירה בחברת הייטק.", "text_ru": "Да, я два года работала секретарём в хайтек-компании."}, {"speaker": "מנהל", "text_he": "את יודעת לעבוד עם מחשב?", "text_ru": "Вы умеете работать с компьютером?"}, {"speaker": "מועמדת", "text_he": "בטח, אקסל, וורד ואאוטלוק.", "text_ru": "Конечно, Excel, Word и Outlook."}, {"speaker": "מנהל", "text_he": "מצוין. המשרה היא מתשע עד חמש. המשכורת שמונת אלפים שקלים.", "text_ru": "Отлично. Работа с девяти до пяти. Зарплата восемь тысяч шекелей."}, {"speaker": "מועמדת", "text_he": "נשמע טוב. מתי אני יכולה להתחיל?", "text_ru": "Звучит хорошо. Когда я могу начать?"}, {"speaker": "מנהל", "text_he": "ביום ראשון הבא. ברוכה הבאה!", "text_ru": "В следующее воскресенье. Добро пожаловать!"}]', '[{"word": "ראיון עבודה", "translation": "собеседование", "transliteration": "реайОн аводА"}, {"word": "ניסיון", "translation": "опыт", "transliteration": "нисайОн"}, {"word": "משרד", "translation": "офис", "transliteration": "мисрАд"}, {"word": "משכורת", "translation": "зарплата", "transliteration": "маскОрет"}, {"word": "מועמדת", "translation": "кандидат (ж.)", "transliteration": "моамЕдет"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (192, 2, 'בבנק: פתיחת חשבון', 'Вы открываете банковский счёт.', '[{"speaker": "פקידה", "text_he": "שלום, אני יכולה לעזור?", "text_ru": "Здравствуйте, я могу помочь?"}, {"speaker": "לקוח", "text_he": "כן, אני רוצה לפתוח חשבון בנק.", "text_ru": "Да, я хочу открыть банковский счёт."}, {"speaker": "פקידה", "text_he": "חשבון עובר ושב או חיסכון?", "text_ru": "Текущий счёт или сберегательный?"}, {"speaker": "לקוח", "text_he": "עובר ושב, בבקשה. עם כרטיס אשראי.", "text_ru": "Текущий, пожалуйста. С кредитной картой."}, {"speaker": "פקידה", "text_he": "אני צריכה תעודת זהות ואישור כתובת.", "text_ru": "Мне нужно удостоверение личности и подтверждение адреса."}, {"speaker": "לקוח", "text_he": "הנה התעודה. ואת האישור אני אביא מחר.", "text_ru": "Вот удостоверение. А подтверждение я принесу завтра."}, {"speaker": "פקידה", "text_he": "בסדר. תחתום כאן ופה.", "text_ru": "Хорошо. Подпишите здесь и тут."}, {"speaker": "לקוח", "text_he": "מתי אקבל את הכרטיס?", "text_ru": "Когда я получу карту?"}, {"speaker": "פקידה", "text_he": "בעוד שבוע בדואר.", "text_ru": "Через неделю по почте."}]', '[{"word": "חשבון", "translation": "счёт", "transliteration": "хешбОн"}, {"word": "כרטיס אשראי", "translation": "кредитная карта", "transliteration": "картИс ашрАй"}, {"word": "תעודת זהות", "translation": "удостоверение личности", "transliteration": "теудАт зехУт"}, {"word": "לחתום", "translation": "подписать", "transliteration": "лахтОм"}, {"word": "חיסכון", "translation": "сбережение", "transliteration": "хисахОн"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (193, 2, 'שיפוץ דירה: שרברב', 'Вы вызвали сантехника починить протечку в ванной.', '[{"speaker": "דייר", "text_he": "תודה שבאת. יש בעיה בצינור בחדר האמבטיה.", "text_ru": "Спасибо, что пришли. Проблема с трубой в ванной."}, {"speaker": "שרברב", "text_he": "בוא נראה. כמה זמן זה כבר נוזל?", "text_ru": "Давайте посмотрим. Сколько времени уже течёт?"}, {"speaker": "דייר", "text_he": "מאתמול בלילה. כל הרצפה רטובה.", "text_ru": "Со вчерашнего вечера. Весь пол мокрый."}, {"speaker": "שרברב", "text_he": "אני רואה. צריך להחליף את הברז. זה ישן.", "text_ru": "Вижу. Нужно заменить кран. Он старый."}, {"speaker": "דייר", "text_he": "כמה זה יעלה?", "text_ru": "Сколько это будет стоить?"}, {"speaker": "שרברב", "text_he": "שלוש מאות שקלים עם חומרים.", "text_ru": "Триста шекелей с материалами."}, {"speaker": "דייר", "text_he": "בסדר. כמה זמן לוקח?", "text_ru": "Хорошо. Сколько времени займёт?"}, {"speaker": "שרברב", "text_he": "שעה בערך. אתחיל עכשיו.", "text_ru": "Примерно час. Начну сейчас."}]', '[{"word": "שרברב", "translation": "сантехник", "transliteration": "шравлАв"}, {"word": "צינור", "translation": "труба", "transliteration": "цинОр"}, {"word": "נוזל", "translation": "течёт/жидкость", "transliteration": "нозЕль"}, {"word": "ברז", "translation": "кран", "transliteration": "бЕрез"}, {"word": "להחליף", "translation": "заменить", "transliteration": "лехахлИф"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (194, 2, 'רקלמציה: מוצר פגום', 'Вы возвращаете бракованный товар в магазин.', '[{"speaker": "לקוח", "text_he": "סליחה, קניתי את הטוסטר הזה שלשום והוא לא עובד.", "text_ru": "Извините, я купил этот тостер позавчера, и он не работает."}, {"speaker": "מוכרת", "text_he": "יש לך קבלה?", "text_ru": "У вас есть чек?"}, {"speaker": "לקוח", "text_he": "כן, הנה.", "text_ru": "Да, вот."}, {"speaker": "מוכרת", "text_he": "מה בדיוק הבעיה?", "text_ru": "Какая именно проблема?"}, {"speaker": "לקוח", "text_he": "הוא לא מתחמם. לחצתי על כל הכפתורים.", "text_ru": "Он не нагревается. Я нажимал на все кнопки."}, {"speaker": "מוכרת", "text_he": "אתה רוצה החלפה או החזר כספי?", "text_ru": "Хотите замену или возврат денег?"}, {"speaker": "לקוח", "text_he": "החלפה, בבקשה. אותו דגם.", "text_ru": "Замену, пожалуйста. Ту же модель."}, {"speaker": "מוכרת", "text_he": "בסדר, הנה טוסטר חדש. בדוק אותו בבית.", "text_ru": "Хорошо, вот новый тостер. Проверьте его дома."}]', '[{"word": "קבלה", "translation": "чек/квитанция", "transliteration": "кабалА"}, {"word": "פגום", "translation": "бракованный", "transliteration": "пагУм"}, {"word": "החלפה", "translation": "замена", "transliteration": "хахлафА"}, {"word": "החזר כספי", "translation": "возврат денег", "transliteration": "хехзЕр каспИ"}, {"word": "דגם", "translation": "модель", "transliteration": "дЕгем"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (195, 2, 'הרשמה לקורס עברית', 'Вы записываетесь на курс иврита в ульпане.', '[{"speaker": "מזכירה", "text_he": "שלום! רוצה להירשם לקורס?", "text_ru": "Здравствуйте! Хотите записаться на курс?"}, {"speaker": "תלמיד", "text_he": "כן. אני רוצה ללמוד עברית. אני מתחיל.", "text_ru": "Да. Я хочу учить иврит. Я начинающий."}, {"speaker": "מזכירה", "text_he": "יש לנו קורס לרמה א׳. שלוש פעמים בשבוע.", "text_ru": "У нас есть курс для уровня Алеф. Три раза в неделю."}, {"speaker": "תלמיד", "text_he": "באיזה ימים?", "text_ru": "В какие дни?"}, {"speaker": "מזכירה", "text_he": "ראשון, שלישי וחמישי. מארבע עד שש.", "text_ru": "Воскресенье, вторник и четверг. С четырёх до шести."}, {"speaker": "תלמיד", "text_he": "מתאים לי. כמה עולה?", "text_ru": "Мне подходит. Сколько стоит?"}, {"speaker": "מזכירה", "text_he": "אלף שקלים לשלושה חודשים. כולל ספרים.", "text_ru": "Тысяча шекелей за три месяца. Включая книги."}, {"speaker": "תלמיד", "text_he": "מצוין! אני נרשם.", "text_ru": "Отлично! Я записываюсь."}]', '[{"word": "הרשמה", "translation": "регистрация/запись", "transliteration": "хершамА"}, {"word": "קורס", "translation": "курс", "transliteration": "курс"}, {"word": "רמה", "translation": "уровень", "transliteration": "рамА"}, {"word": "מתחיל", "translation": "начинающий", "transliteration": "матхИль"}, {"word": "כולל", "translation": "включая", "transliteration": "колЕль"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (196, 2, 'ריב עם השכן: חנייה', 'Вы спорите с соседом, который занял ваше парковочное место.', '[{"speaker": "שכן א", "text_he": "סליחה, אתה חונה במקום שלי.", "text_ru": "Извините, вы паркуетесь на моём месте."}, {"speaker": "שכן ב", "text_he": "מה? זה לא שלך. אין פה שם.", "text_ru": "Что? Это не ваше. Тут нет имени."}, {"speaker": "שכן א", "text_he": "יש! תסתכל — כתוב דירה 7. זאת הדירה שלי.", "text_ru": "Есть! Посмотрите — написано квартира 7. Это моя квартира."}, {"speaker": "שכן ב", "text_he": "אה, סליחה. לא שמתי לב.", "text_ru": "А, извините. Не заметил."}, {"speaker": "שכן א", "text_he": "אפשר להזיז את האוטו?", "text_ru": "Можно передвинуть машину?"}, {"speaker": "שכן ב", "text_he": "כן, רגע. אני מזיז עכשיו. באמת סליחה.", "text_ru": "Да, секунду. Передвигаю. Правда, извините."}, {"speaker": "שכן א", "text_he": "תודה. בפעם הבאה תשים לב, בבקשה.", "text_ru": "Спасибо. В следующий раз обратите внимание, пожалуйста."}]', '[{"word": "חנייה", "translation": "парковка", "transliteration": "ханайА"}, {"word": "לחנות", "translation": "парковаться", "transliteration": "лаханОт"}, {"word": "להזיז", "translation": "передвигать", "transliteration": "лехазИз"}, {"word": "לשים לב", "translation": "обратить внимание", "transliteration": "ласИм лев"}, {"word": "מקום", "translation": "место", "transliteration": "макОм"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (197, 2, 'בחתונה: מזל טוב!', 'Вы на свадьбе друга и общаетесь с другими гостями.', '[{"speaker": "אורח א", "text_he": "שלום! את מכירה את החתן או את הכלה?", "text_ru": "Привет! Вы знакомы с женихом или невестой?"}, {"speaker": "אורחת ב", "text_he": "את הכלה. אנחנו חברות מהצבא.", "text_ru": "С невестой. Мы подруги по армии."}, {"speaker": "אורח א", "text_he": "אני חבר של דוד מהעבודה. איזה חתונה יפה!", "text_ru": "Я друг Давида по работе. Какая красивая свадьба!"}, {"speaker": "אורחת ב", "text_he": "כן, המקום נהדר. ואיזה אוכל!", "text_ru": "Да, место великолепное. И какая еда!"}, {"speaker": "אורח א", "text_he": "בוא נלך לאחל מזל טוב.", "text_ru": "Давайте пойдём поздравим."}, {"speaker": "אורחת ב", "text_he": "כן! הם נראים כל כך שמחים!", "text_ru": "Да! Они выглядят такими счастливыми!"}, {"speaker": "אורח א", "text_he": "מזל טוב, דוד ומיכל! שתהיה לכם חיים יפים!", "text_ru": "Мазаль тов, Давид и Михаль! Пусть у вас будет прекрасная жизнь!"}, {"speaker": "חתן", "text_he": "תודה רבה! בואו לרקוד!", "text_ru": "Большое спасибо! Пойдёмте танцевать!"}]', '[{"word": "חתונה", "translation": "свадьба", "transliteration": "хатунА"}, {"word": "חתן", "translation": "жених", "transliteration": "хатАн"}, {"word": "כלה", "translation": "невеста", "transliteration": "калА"}, {"word": "לאחל", "translation": "пожелать", "transliteration": "леахЕль"}, {"word": "לרקוד", "translation": "танцевать", "transliteration": "лиркОд"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (198, 2, 'במוסך: תקלה ברכב', 'Вы привезли машину в автосервис.', '[{"speaker": "מכונאי", "text_he": "שלום, מה הבעיה?", "text_ru": "Здравствуйте, какая проблема?"}, {"speaker": "נהג", "text_he": "המנוע עושה רעש מוזר. ויש אור אדום בלוח.", "text_ru": "Мотор издаёт странный шум. И красная лампочка на панели."}, {"speaker": "מכונאי", "text_he": "מתי התחיל?", "text_ru": "Когда началось?"}, {"speaker": "נהג", "text_he": "לפני יומיים. גם הבלמים לא טובים.", "text_ru": "Два дня назад. И тормоза не в порядке."}, {"speaker": "מכונאי", "text_he": "אני אבדוק. תשאיר את המפתח.", "text_ru": "Я проверю. Оставьте ключ."}, {"speaker": "נהג", "text_he": "כמה זמן ייקח?", "text_ru": "Сколько времени займёт?"}, {"speaker": "מכונאי", "text_he": "אני צריך לבדוק. אתקשר אליך בצהריים.", "text_ru": "Мне нужно проверить. Позвоню вам днём."}, {"speaker": "נהג", "text_he": "בסדר. הנה המספר שלי.", "text_ru": "Хорошо. Вот мой номер."}]', '[{"word": "מוסך", "translation": "автосервис", "transliteration": "мусАх"}, {"word": "מנוע", "translation": "мотор/двигатель", "transliteration": "манОа"}, {"word": "בלמים", "translation": "тормоза", "transliteration": "баламИм"}, {"word": "מכונאי", "translation": "механик", "transliteration": "мехонАй"}, {"word": "לבדוק", "translation": "проверить", "transliteration": "ливдОк"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (199, 2, 'תכנון טיול לאילת', 'Вы с другом планируете поездку в Эйлат.', '[{"speaker": "רונית", "text_he": "בוא נסע לאילת בחופש! מה דעתך?", "text_ru": "Поехали в Эйлат на каникулах! Что думаешь?"}, {"speaker": "אלון", "text_he": "רעיון מעולה! מתי?", "text_ru": "Прекрасная идея! Когда?"}, {"speaker": "רונית", "text_he": "בשבוע הבא? משני עד חמישי.", "text_ru": "На следующей неделе? С понедельника до четверга."}, {"speaker": "אלון", "text_he": "שלושה לילות — מושלם. נוסעים ברכבת או באוטו?", "text_ru": "Три ночи — идеально. Едем на поезде или на машине?"}, {"speaker": "רונית", "text_he": "באוטו. ארבע שעות, אבל יותר נוח.", "text_ru": "На машине. Четыре часа, но удобнее."}, {"speaker": "אלון", "text_he": "צריך להזמין מלון. יש משהו לא יקר?", "text_ru": "Нужно забронировать отель. Есть что-нибудь недорогое?"}, {"speaker": "רונית", "text_he": "מצאתי אכסנייה ב-200 שקלים ללילה.", "text_ru": "Я нашла хостел за 200 шекелей за ночь."}, {"speaker": "אלון", "text_he": "מעולה! מזמינים. אני כל כך רוצה לצלול!", "text_ru": "Отлично! Бронируем. Я так хочу понырять!"}]', '[{"word": "טיול", "translation": "поездка/поход", "transliteration": "тиУль"}, {"word": "חופש", "translation": "каникулы/отпуск", "transliteration": "хОфеш"}, {"word": "להזמין", "translation": "забронировать", "transliteration": "лехазмИн"}, {"word": "אכסנייה", "translation": "хостел", "transliteration": "ахсанийА"}, {"word": "לצלול", "translation": "нырять", "transliteration": "лицлОль"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (200, 2, 'אצל עורך דין: חוזה שכירות', 'Вы у адвоката для подписания договора аренды квартиры.', '[{"speaker": "עו״ד", "text_he": "שלום. אתם מוכנים לחתום על החוזה?", "text_ru": "Здравствуйте. Вы готовы подписать договор?"}, {"speaker": "שוכר", "text_he": "כמעט. יש לי כמה שאלות.", "text_ru": "Почти. У меня несколько вопросов."}, {"speaker": "עו״ד", "text_he": "בבקשה, שאל.", "text_ru": "Пожалуйста, спрашивайте."}, {"speaker": "שוכר", "text_he": "מה קורה אם משהו נשבר בדירה?", "text_ru": "Что будет, если что-то сломается в квартире?"}, {"speaker": "עו״ד", "text_he": "לפי החוזה, תיקונים גדולים — על בעל הדירה. קטנים — עליך.", "text_ru": "По договору, крупный ремонт — за хозяином. Мелкий — за вами."}, {"speaker": "שוכר", "text_he": "ומה לגבי הפיקדון?", "text_ru": "А что насчёт залога?"}, {"speaker": "עו״ד", "text_he": "שלושת אלפים שקלים. מוחזרים בסוף השכירות.", "text_ru": "Три тысячи шекелей. Возвращаются в конце аренды."}, {"speaker": "שוכר", "text_he": "בסדר. אני חותם.", "text_ru": "Хорошо. Подписываю."}]', '[{"word": "חוזה", "translation": "договор", "transliteration": "хозЕ"}, {"word": "שכירות", "translation": "аренда", "transliteration": "схирУт"}, {"word": "פיקדון", "translation": "залог/депозит", "transliteration": "пикадОн"}, {"word": "בעל דירה", "translation": "хозяин квартиры", "transliteration": "бАаль дирА"}, {"word": "תיקון", "translation": "ремонт/починка", "transliteration": "тикУн"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (201, 3, 'ויכוח פוליטי: ימין ושמאל', 'Два друга спорят о политической ситуации за ужином.', '[{"speaker": "יובל", "text_he": "אתה שומע מה קורה בכנסת? זה לא ייאמן.", "text_ru": "Ты слышал, что происходит в Кнессете? Невероятно."}, {"speaker": "שירה", "text_he": "כן, ראיתי. אבל אני חושבת שהממשלה צודקת הפעם.", "text_ru": "Да, видела. Но я думаю, что правительство на этот раз право."}, {"speaker": "יובל", "text_he": "צודקת?! הם פוגעים בדמוקרטיה!", "text_ru": "Право?! Они наносят ущерб демократии!"}, {"speaker": "שירה", "text_he": "אל תגזים. הם נבחרו בבחירות דמוקרטיות.", "text_ru": "Не преувеличивай. Их выбрали на демократических выборах."}, {"speaker": "יובל", "text_he": "דמוקרטיה זה לא רק בחירות. זה גם זכויות.", "text_ru": "Демократия — это не только выборы. Это ещё и права."}, {"speaker": "שירה", "text_he": "אני מסכימה, אבל גם הצד השני צריך לשמוע.", "text_ru": "Согласна, но и другую сторону нужно слушать."}, {"speaker": "יובל", "text_he": "נכון. בוא ננסה להבין אחד את השני.", "text_ru": "Верно. Давай попробуем понять друг друга."}, {"speaker": "שירה", "text_he": "מסכימה. ולפחות על האוכל אנחנו מסכימים — הפיצה מצוינת!", "text_ru": "Согласна. Хотя бы насчёт еды мы согласны — пицца отличная!"}]', '[{"word": "כנסת", "translation": "Кнессет (парламент)", "transliteration": "кнЕсет"}, {"word": "ממשלה", "translation": "правительство", "transliteration": "мемшалА"}, {"word": "דמוקרטיה", "translation": "демократия", "transliteration": "демокрАтия"}, {"word": "בחירות", "translation": "выборы", "transliteration": "бхирОт"}, {"word": "זכויות", "translation": "права", "transliteration": "зхуйОт"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (202, 3, 'אחרי הסרט: מה חשבת?', 'Двое друзей обсуждают фильм после кинотеатра.', '[{"speaker": "נועה", "text_he": "אז מה חשבת על הסרט?", "text_ru": "Ну, что ты думаешь о фильме?"}, {"speaker": "עמית", "text_he": "האמת? קצת מאכזב. ציפיתי ליותר.", "text_ru": "Честно? Немного разочаровывает. Ожидал большего."}, {"speaker": "נועה", "text_he": "באמת? אני דווקא נהניתי. המשחק היה מצוין.", "text_ru": "Правда? А мне как раз понравилось. Актёрская игра была отличной."}, {"speaker": "עמית", "text_he": "המשחק כן, אבל העלילה — חלשה. צפויה מדי.", "text_ru": "Игра да, но сюжет — слабый. Слишком предсказуемый."}, {"speaker": "נועה", "text_he": "אולי, אבל הצילום היה מדהים. כל הסצנות בירושלים...", "text_ru": "Может быть, но съёмка была потрясающей. Все сцены в Иерусалиме..."}, {"speaker": "עמית", "text_he": "זה נכון, ירושלים תמיד יפה על המסך.", "text_ru": "Это верно, Иерусалим всегда красив на экране."}, {"speaker": "נועה", "text_he": "בשבוע הבא יוצא סרט ישראלי חדש. נלך?", "text_ru": "На следующей неделе выходит новый израильский фильм. Пойдём?"}, {"speaker": "עמית", "text_he": "בטח! אני תמיד בעד קולנוע ישראלי.", "text_ru": "Конечно! Я всегда за израильское кино."}]', '[{"word": "סרט", "translation": "фильм", "transliteration": "сЕрет"}, {"word": "עלילה", "translation": "сюжет", "transliteration": "алилА"}, {"word": "צילום", "translation": "съёмка", "transliteration": "цилУм"}, {"word": "מאכזב", "translation": "разочаровывающий", "transliteration": "меахзЕв"}, {"word": "קולנוע", "translation": "кино", "transliteration": "колнОа"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (203, 3, 'שיחה עם בעל הדירה: העלאת שכר דירה', 'Хозяин квартиры уведомляет вас о повышении арендной платы.', '[{"speaker": "בעל דירה", "text_he": "שלום, רציתי לדבר איתך על החוזה החדש.", "text_ru": "Здравствуйте, хотел поговорить с вами о новом договоре."}, {"speaker": "שוכר", "text_he": "כן, בבקשה. מה השינויים?", "text_ru": "Да, пожалуйста. Какие изменения?"}, {"speaker": "בעל דירה", "text_he": "השכירות תעלה בחמש מאות שקלים. המחירים עלו.", "text_ru": "Аренда повысится на пятьсот шекелей. Цены выросли."}, {"speaker": "שוכר", "text_he": "חמש מאות?! זה הרבה. אני משלם כבר ארבעת אלפים.", "text_ru": "Пятьсот?! Это много. Я и так плачу четыре тысячи."}, {"speaker": "בעל דירה", "text_he": "אני מבין, אבל בשכונה הזו השכירות הממוצעת היא חמשת אלפים.", "text_ru": "Понимаю, но в этом районе средняя аренда — пять тысяч."}, {"speaker": "שוכר", "text_he": "אפשר להתפשר על שלוש מאות?", "text_ru": "Можем пойти на компромисс в триста?"}, {"speaker": "בעל דירה", "text_he": "ארבע מאות — ואני גם אתקן את המזגן.", "text_ru": "Четыреста — и я ещё починю кондиционер."}, {"speaker": "שוכר", "text_he": "עסקה! מתי חותמים?", "text_ru": "Договорились! Когда подписываем?"}]', '[{"word": "שכר דירה", "translation": "арендная плата", "transliteration": "схАр дирА"}, {"word": "להתפשר", "translation": "пойти на компромисс", "transliteration": "лехитпашЕр"}, {"word": "ממוצע", "translation": "средний", "transliteration": "мемуцА"}, {"word": "עסקה", "translation": "сделка", "transliteration": "искА"}, {"word": "שינויים", "translation": "изменения", "transliteration": "шинуйИм"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (204, 3, 'בכנס: הרצאה על טכנולוגיה', 'Вы на конференции по технологиям и общаетесь с другим участником.', '[{"speaker": "משתתף א", "text_he": "מה דעתך על ההרצאה האחרונה?", "text_ru": "Что думаете о последней лекции?"}, {"speaker": "משתתף ב", "text_he": "מעניינת, אבל טכנית מדי בשבילי.", "text_ru": "Интересная, но слишком техническая для меня."}, {"speaker": "משתתף א", "text_he": "אני עובד בהייטק, אז זה דווקא רלוונטי.", "text_ru": "Я работаю в хайтеке, так что мне как раз актуально."}, {"speaker": "משתתף ב", "text_he": "מה אתה עושה?", "text_ru": "Чем вы занимаетесь?"}, {"speaker": "משתתף א", "text_he": "אני מפתח אפליקציות. ואת?", "text_ru": "Я разрабатываю приложения. А вы?"}, {"speaker": "משתתף ב", "text_he": "אני מנהלת שיווק בחברת סטארט-אפ.", "text_ru": "Я директор по маркетингу в стартапе."}, {"speaker": "משתתף א", "text_he": "נחמד! הנה הכרטיס שלי. נשמור על קשר?", "text_ru": "Здорово! Вот моя визитка. Будем на связи?"}, {"speaker": "משתתף ב", "text_he": "בטח! אולי נוכל לשתף פעולה.", "text_ru": "Конечно! Может, сможем сотрудничать."}]', '[{"word": "כנס", "translation": "конференция", "transliteration": "кЕнес"}, {"word": "הרצאה", "translation": "лекция/доклад", "transliteration": "харцаА"}, {"word": "שיווק", "translation": "маркетинг", "transliteration": "шивУк"}, {"word": "לשתף פעולה", "translation": "сотрудничать", "transliteration": "лешатЕф пеулА"}, {"word": "רלוונטי", "translation": "актуальный", "transliteration": "релевАнти"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (205, 3, 'תלונה: שירות לקוחות', 'Вы звоните в службу поддержки интернет-провайдера.', '[{"speaker": "נציג", "text_he": "שלום, שירות לקוחות. איך אני יכול לעזור?", "text_ru": "Здравствуйте, служба поддержки. Чем могу помочь?"}, {"speaker": "לקוח", "text_he": "שלום. אין לי אינטרנט כבר יומיים! מתי תתקנו?", "text_ru": "Здравствуйте. У меня нет интернета уже два дня! Когда почините?"}, {"speaker": "נציג", "text_he": "אני מצטער. מה מספר החשבון שלך?", "text_ru": "Извините. Какой у вас номер счёта?"}, {"speaker": "לקוח", "text_he": "123456. וזו כבר התקלה השלישית החודש!", "text_ru": "123456. И это уже третья поломка в этом месяце!"}, {"speaker": "נציג", "text_he": "אני רואה. יש תקלה אזורית. הטכנאי יגיע מחר בין שמונה לשתים עשרה.", "text_ru": "Вижу. Есть региональная поломка. Техник приедет завтра между восемью и двенадцатью."}, {"speaker": "לקוח", "text_he": "מחר?! אני עובד מהבית, אני צריך אינטרנט היום!", "text_ru": "Завтра?! Я работаю из дома, мне нужен интернет сегодня!"}, {"speaker": "נציג", "text_he": "אני מבין את התסכול. אנסה לקדם את הביקור להיום.", "text_ru": "Я понимаю ваше разочарование. Попробую перенести визит на сегодня."}, {"speaker": "לקוח", "text_he": "תודה. וגם אני רוצה פיצוי על הימים בלי שירות.", "text_ru": "Спасибо. И ещё я хочу компенсацию за дни без обслуживания."}, {"speaker": "נציג", "text_he": "בהחלט, אני מזכה אותך על שלושה ימים.", "text_ru": "Безусловно, я зачислю вам компенсацию за три дня."}]', '[{"word": "שירות לקוחות", "translation": "служба поддержки", "transliteration": "шерУт лекохОт"}, {"word": "תקלה", "translation": "поломка/неполадка", "transliteration": "такалА"}, {"word": "טכנאי", "translation": "техник", "transliteration": "технАй"}, {"word": "תסכול", "translation": "разочарование", "transliteration": "тискУль"}, {"word": "פיצוי", "translation": "компенсация", "transliteration": "пицУй"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (206, 3, 'גישור: סכסוך בין שותפים', 'Медиатор помогает разрешить спор двух бизнес-партнёров.', '[{"speaker": "מגשר", "text_he": "בואו ננסה למצוא פתרון שטוב לשניכם.", "text_ru": "Давайте попробуем найти решение, хорошее для обоих."}, {"speaker": "שותף א", "text_he": "אני לא מרוצה מחלוקת הרווחים. אני עושה יותר עבודה.", "text_ru": "Я недоволен распределением прибыли. Я делаю больше работы."}, {"speaker": "שותף ב", "text_he": "זה לא נכון! אני מביא את כל הלקוחות!", "text_ru": "Это неправда! Я привожу всех клиентов!"}, {"speaker": "מגשר", "text_he": "רגע, בלי צעקות. כל אחד יסביר את הצד שלו.", "text_ru": "Подождите, без крика. Каждый объяснит свою сторону."}, {"speaker": "שותף א", "text_he": "אני מנהל את כל הייצור. בלעדי אין מה למכור.", "text_ru": "Я управляю всем производством. Без меня нечего продавать."}, {"speaker": "שותף ב", "text_he": "ובלעדי אין מי שיקנה. המכירות שלי הכפילו את ההכנסות.", "text_ru": "А без меня некому покупать. Мои продажи удвоили доходы."}, {"speaker": "מגשר", "text_he": "אז שניכם חשובים. אולי נחלק 55-45 במקום 50-50?", "text_ru": "Значит, оба вы важны. Может, разделим 55-45 вместо 50-50?"}, {"speaker": "שותף א", "text_he": "אני מוכן לנסות. לתקופת ניסיון של חצי שנה.", "text_ru": "Я готов попробовать. На пробный период в полгода."}]', '[{"word": "גישור", "translation": "медиация", "transliteration": "гишУр"}, {"word": "שותף", "translation": "партнёр", "transliteration": "шутАф"}, {"word": "רווחים", "translation": "прибыль", "transliteration": "ревахИм"}, {"word": "ייצור", "translation": "производство", "transliteration": "ицУр"}, {"word": "תקופת ניסיון", "translation": "испытательный срок", "transliteration": "ткуфАт нисайОн"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (207, 3, 'משא ומתן: העלאת שכר', 'Вы просите повышение зарплаты у руководителя.', '[{"speaker": "עובד", "text_he": "רציתי לדבר על המשכורת שלי. אני כאן כבר שנתיים.", "text_ru": "Хотел поговорить о моей зарплате. Я здесь уже два года."}, {"speaker": "מנהלת", "text_he": "כן, אני מכירה את התרומה שלך. מה אתה מציע?", "text_ru": "Да, я ценю ваш вклад. Что вы предлагаете?"}, {"speaker": "עובד", "text_he": "אני חושב שהעלאה של חמישה עשר אחוז הוגנת.", "text_ru": "Я думаю, повышение на пятнадцать процентов справедливо."}, {"speaker": "מנהלת", "text_he": "חמישה עשר זה הרבה. התקציב שלנו מוגבל.", "text_ru": "Пятнадцать — это много. Наш бюджет ограничен."}, {"speaker": "עובד", "text_he": "אבל המחירים עלו. וקיבלתי הצעה ממקום אחר.", "text_ru": "Но цены выросли. И я получил предложение из другого места."}, {"speaker": "מנהלת", "text_he": "אני מבינה. אוכל להציע עשרה אחוז ועוד יום חופש.", "text_ru": "Понимаю. Могу предложить десять процентов и ещё один выходной день."}, {"speaker": "עובד", "text_he": "שתים עשרה אחוז ויום חופש — ויש עסקה.", "text_ru": "Двенадцать процентов и выходной — и есть сделка."}, {"speaker": "מנהלת", "text_he": "מוסכם. מהחודש הבא.", "text_ru": "Согласовано. С следующего месяца."}]', '[{"word": "משא ומתן", "translation": "переговоры", "transliteration": "масА уматАн"}, {"word": "העלאה", "translation": "повышение", "transliteration": "хаалаА"}, {"word": "אחוז", "translation": "процент", "transliteration": "ахУз"}, {"word": "תקציב", "translation": "бюджет", "transliteration": "такцИв"}, {"word": "הוגן", "translation": "справедливый", "transliteration": "огЕн"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (208, 3, 'דיון בכיתה: לימוד חובה', 'Дискуссия в классе: нужно ли обязательное изучение арабского языка.', '[{"speaker": "מורה", "text_he": "הנושא: האם צריך ללמד ערבית בכל בתי הספר? מי בעד?", "text_ru": "Тема: нужно ли преподавать арабский во всех школах? Кто за?"}, {"speaker": "תלמיד א", "text_he": "אני בעד! אנחנו חיים ליד דוברי ערבית. חשוב להבין אותם.", "text_ru": "Я за! Мы живём рядом с носителями арабского. Важно их понимать."}, {"speaker": "תלמידה ב", "text_he": "אני נגד. יש יותר מדי מקצועות. אנגלית חשובה יותר.", "text_ru": "Я против. Слишком много предметов. Английский важнее."}, {"speaker": "תלמיד ג", "text_he": "למה לא שניהם? ערבית ואנגלית.", "text_ru": "Почему не оба? И арабский, и английский."}, {"speaker": "תלמידה ב", "text_he": "כי אין מספיק שעות! והתלמידים עמוסים.", "text_ru": "Потому что не хватает часов! И ученики перегружены."}, {"speaker": "תלמיד א", "text_he": "שפה זה לא רק מקצוע. זה גשר בין עמים.", "text_ru": "Язык — это не просто предмет. Это мост между народами."}, {"speaker": "מורה", "text_he": "נקודות מעניינות. בואו נצביע: מי בעד לימוד חובה?", "text_ru": "Интересные аргументы. Давайте проголосуем: кто за обязательное изучение?"}]', '[{"word": "לימוד חובה", "translation": "обязательное изучение", "transliteration": "лимУд ховА"}, {"word": "מקצוע", "translation": "предмет/профессия", "transliteration": "микцОа"}, {"word": "גשר", "translation": "мост", "transliteration": "гЕшер"}, {"word": "להצביע", "translation": "голосовать", "transliteration": "лехацбИа"}, {"word": "עמוס", "translation": "нагруженный", "transliteration": "амУс"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (209, 3, 'ראיון לכתבה: שף ישראלי', 'Журналист берёт интервью у израильского шеф-повара для статьи.', '[{"speaker": "עיתונאי", "text_he": "ספר לי על המסעדה החדשה שלך.", "text_ru": "Расскажите о вашем новом ресторане."}, {"speaker": "שף", "text_he": "פתחנו לפני חודשיים. התפריט מבוסס על מטבח ים-תיכוני.", "text_ru": "Открылись два месяца назад. Меню основано на средиземноморской кухне."}, {"speaker": "עיתונאי", "text_he": "מה מיוחד במטבח שלך?", "text_ru": "Что особенного в вашей кухне?"}, {"speaker": "שף", "text_he": "אני משתמש רק בחומרי גלם מקומיים. מהשוק של היום.", "text_ru": "Я использую только местные продукты. С сегодняшнего рынка."}, {"speaker": "עיתונאי", "text_he": "מה המנה הכי פופולרית?", "text_ru": "Какое блюдо самое популярное?"}, {"speaker": "שף", "text_he": "הדג עם הטחינה. אנשים מגיעים בשביל זה מכל הארץ.", "text_ru": "Рыба с тхиной. Люди приезжают ради этого со всей страны."}, {"speaker": "עיתונאי", "text_he": "מה החלום שלך?", "text_ru": "О чём вы мечтаете?"}, {"speaker": "שף", "text_he": "לפתוח מסעדה בפריז. להראות לעולם את המטבח הישראלי.", "text_ru": "Открыть ресторан в Париже. Показать миру израильскую кухню."}]', '[{"word": "שף", "translation": "шеф-повар", "transliteration": "шеф"}, {"word": "תפריט", "translation": "меню", "transliteration": "тафрИт"}, {"word": "חומרי גלם", "translation": "сырьё/продукты", "transliteration": "хомрЕй гЕлем"}, {"word": "מנה", "translation": "блюдо/порция", "transliteration": "манА"}, {"word": "טחינה", "translation": "тхина", "transliteration": "тхинА"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (210, 3, 'בשידור חי: תוכנית רדיו', 'Ведущий радио беседует со слушателем, позвонившим в прямой эфир.', '[{"speaker": "מנחה", "text_he": "שלום למאזין הבא! מה שמך ומאיפה אתה?", "text_ru": "Привет следующему слушателю! Как вас зовут и откуда вы?"}, {"speaker": "מאזין", "text_he": "שלום! אני רמי מבאר שבע.", "text_ru": "Привет! Я Рами из Беер-Шевы."}, {"speaker": "מנחה", "text_he": "אהלן רמי! על מה רצית לדבר?", "text_ru": "Привет, Рами! О чём хотели поговорить?"}, {"speaker": "מאזין", "text_he": "על הפריפריה. אנחנו תמיד שוכחים את הדרום.", "text_ru": "О периферии. Южные районы всё время забывают."}, {"speaker": "מנחה", "text_he": "מה הבעיה הכי גדולה?", "text_ru": "Какая самая большая проблема?"}, {"speaker": "מאזין", "text_he": "תחבורה ציבורית. אין אוטובוסים בלילה. וחינוך — חסרים מורים.", "text_ru": "Общественный транспорт. Нет автобусов ночью. И образование — не хватает учителей."}, {"speaker": "מנחה", "text_he": "נקודות חשובות. תודה רבה, רמי!", "text_ru": "Важные замечания. Большое спасибо, Рами!"}, {"speaker": "מאזין", "text_he": "תודה שנתתם לי במה!", "text_ru": "Спасибо, что дали мне трибуну!"}]', '[{"word": "שידור חי", "translation": "прямой эфир", "transliteration": "шидУр хай"}, {"word": "מנחה", "translation": "ведущий", "transliteration": "манхЕ"}, {"word": "מאזין", "translation": "слушатель", "transliteration": "маазИн"}, {"word": "פריפריה", "translation": "периферия", "transliteration": "периферийА"}, {"word": "תחבורה ציבורית", "translation": "общественный транспорт", "transliteration": "тахбурА цибурИт"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (211, 4, 'דיון אקדמי: מחקר חדש', 'Два преподавателя обсуждают результаты нового исследования.', '[{"speaker": "פרופ׳ לוי", "text_he": "קראת את המאמר החדש של כהן על השפעת הרשתות החברתיות?", "text_ru": "Вы читали новую статью Коэна о влиянии социальных сетей?"}, {"speaker": "ד״ר שגב", "text_he": "כן. המתודולוגיה מעניינת, אבל המדגם קטן מדי.", "text_ru": "Да. Методология интересная, но выборка слишком мала."}, {"speaker": "פרופ׳ לוי", "text_he": "מסכים. עם שלוש מאות נבדקים אי אפשר להכליל.", "text_ru": "Согласен. С тремя сотнями испытуемых нельзя обобщать."}, {"speaker": "ד״ר שגב", "text_he": "מצד שני, הממצאים על חרדה בקרב מתבגרים מטרידים.", "text_ru": "С другой стороны, результаты о тревожности у подростков тревожат."}, {"speaker": "פרופ׳ לוי", "text_he": "נכון. שבעים אחוז דיווחו על ירידה בדימוי העצמי.", "text_ru": "Верно. Семьдесят процентов сообщили о снижении самооценки."}, {"speaker": "ד״ר שגב", "text_he": "צריך מחקר אורך. לעקוב אחרי אותם נבדקים לאורך שנים.", "text_ru": "Нужно лонгитюдное исследование. Следить за теми же испытуемыми в течение лет."}, {"speaker": "פרופ׳ לוי", "text_he": "בדיוק. נציע מחקר משותף לקרן המדע?", "text_ru": "Именно. Предложим совместное исследование Научному фонду?"}, {"speaker": "ד״ר שגב", "text_he": "רעיון מצוין. אכין טיוטה לשבוע הבא.", "text_ru": "Отличная идея. Подготовлю черновик к следующей неделе."}]', '[{"word": "מאמר", "translation": "статья (научная)", "transliteration": "маамАр"}, {"word": "מתודולוגיה", "translation": "методология", "transliteration": "методолОгия"}, {"word": "מדגם", "translation": "выборка", "transliteration": "мидгАм"}, {"word": "ממצאים", "translation": "результаты/находки", "transliteration": "мимцаИм"}, {"word": "דימוי עצמי", "translation": "самооценка", "transliteration": "димУй ацмИ"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (212, 4, 'ייעוץ משפטי: פיטורים', 'Адвокат консультирует клиента, которого незаконно уволили.', '[{"speaker": "לקוח", "text_he": "פיטרו אותי בלי שימוע. זה חוקי?", "text_ru": "Меня уволили без слушания. Это законно?"}, {"speaker": "עו״ד", "text_he": "לא. לפי חוק, חייבים לערוך שימוע לפני פיטורים.", "text_ru": "Нет. По закону, обязаны провести слушание перед увольнением."}, {"speaker": "לקוח", "text_he": "אמרו שזה בגלל צמצומים, אבל גייסו מישהו חדש.", "text_ru": "Сказали, что из-за сокращений, но наняли кого-то нового."}, {"speaker": "עו״ד", "text_he": "זה מחזק את הטענה שלך. יש לך מסמכים?", "text_ru": "Это укрепляет ваш иск. У вас есть документы?"}, {"speaker": "לקוח", "text_he": "כן. מכתב הפיטורים והודעות מייל.", "text_ru": "Да. Письмо об увольнении и электронные письма."}, {"speaker": "עו״ד", "text_he": "מצוין. נגיש תביעה לבית הדין לעבודה. יש סיכוי טוב לפיצויים.", "text_ru": "Отлично. Подадим иск в Трудовой суд. Хорошие шансы на компенсацию."}, {"speaker": "לקוח", "text_he": "כמה זמן ייקח?", "text_ru": "Сколько времени это займёт?"}, {"speaker": "עו״ד", "text_he": "שישה חודשים עד שנה. לפעמים מגיעים לפשרה מהר יותר.", "text_ru": "Шесть месяцев до года. Иногда достигают мирового соглашения быстрее."}]', '[{"word": "פיטורים", "translation": "увольнение", "transliteration": "питурИм"}, {"word": "שימוע", "translation": "слушание (перед увольнением)", "transliteration": "шимУа"}, {"word": "תביעה", "translation": "иск", "transliteration": "твиА"}, {"word": "פיצויים", "translation": "компенсация", "transliteration": "пицуйИм"}, {"word": "פשרה", "translation": "мировое соглашение", "transliteration": "пшарА"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (213, 4, 'התייעצות רפואית: טיפול מורכב', 'Два врача обсуждают план лечения сложного пациента.', '[{"speaker": "ד״ר כהן", "text_he": "המטופל בן שישים, סוכרתי, עם בעיות לב.", "text_ru": "Пациенту шестьдесят, диабетик, с проблемами с сердцем."}, {"speaker": "ד״ר עמר", "text_he": "מה תוצאות הבדיקות האחרונות?", "text_ru": "Каковы результаты последних анализов?"}, {"speaker": "ד״ר כהן", "text_he": "הסוכר גבוה, והלחץ לא מאוזן למרות התרופות.", "text_ru": "Сахар высокий, и давление не стабилизируется, несмотря на лекарства."}, {"speaker": "ד״ר עמר", "text_he": "צריך לשנות את הפרוטוקול. אני ממליץ על צנתור אבחנתי.", "text_ru": "Нужно изменить протокол. Я рекомендую диагностическую катетеризацию."}, {"speaker": "ד״ר כהן", "text_he": "הסיכונים?", "text_ru": "Риски?"}, {"speaker": "ד״ר עמר", "text_he": "נמוכים יחסית, אבל צריך להסביר למטופל ולמשפחה.", "text_ru": "Относительно низкие, но нужно объяснить пациенту и семье."}, {"speaker": "ד״ר כהן", "text_he": "מסכימה. נקבע פגישה עם המשפחה מחר.", "text_ru": "Согласна. Назначим встречу с семьёй завтра."}]', '[{"word": "סוכרת", "translation": "диабет", "transliteration": "сукЕрет"}, {"word": "לחץ דם", "translation": "давление", "transliteration": "лАхац дам"}, {"word": "צנתור", "translation": "катетеризация", "transliteration": "цинтУр"}, {"word": "פרוטוקול", "translation": "протокол", "transliteration": "протокОль"}, {"word": "אבחנה", "translation": "диагностика", "transliteration": "авханА"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (214, 4, 'ישיבת ועדה: תקציב שנתי', 'Заседание комитета по утверждению годового бюджета.', '[{"speaker": "יו״ר", "text_he": "נפתח את הדיון על התקציב. מי רוצה להתחיל?", "text_ru": "Открываем обсуждение бюджета. Кто хочет начать?"}, {"speaker": "חבר ועדה א", "text_he": "אני מציע להגדיל את התקציב לחינוך בעשרים אחוז.", "text_ru": "Я предлагаю увеличить бюджет на образование на двадцать процентов."}, {"speaker": "חברת ועדה ב", "text_he": "מאיפה הכסף? התקציב הכולל לא גדל.", "text_ru": "Откуда деньги? Общий бюджет не вырос."}, {"speaker": "חבר ועדה א", "text_he": "נקצץ בהוצאות ייצוג ובפרויקטים לא חיוניים.", "text_ru": "Урежем расходы на представительство и несущественные проекты."}, {"speaker": "יו״ר", "text_he": "יש התנגדות?", "text_ru": "Есть возражения?"}, {"speaker": "חברת ועדה ב", "text_he": "כן. הפרויקטים האלה יוצרים הכנסה עתידית.", "text_ru": "Да. Эти проекты создают будущий доход."}, {"speaker": "יו״ר", "text_he": "בואו נצביע. מי בעד ההצעה?", "text_ru": "Давайте проголосуем. Кто за предложение?"}, {"speaker": "חבר ועדה א", "text_he": "שלושה בעד, שניים נגד. ההצעה עוברת.", "text_ru": "Трое за, двое против. Предложение принято."}]', '[{"word": "ועדה", "translation": "комитет", "transliteration": "ваадА"}, {"word": "תקציב", "translation": "бюджет", "transliteration": "такцИв"}, {"word": "לקצץ", "translation": "урезать", "transliteration": "лекацЕц"}, {"word": "הצעה", "translation": "предложение", "transliteration": "хацаА"}, {"word": "התנגדות", "translation": "возражение", "transliteration": "хитнагдУт"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (215, 4, 'משא ומתן עסקי: מיזוג חברות', 'Переговоры о слиянии двух компаний.', '[{"speaker": "מנכ״ל א", "text_he": "אנחנו מאמינים שהמיזוג ייצור סינרגיה משמעותית.", "text_ru": "Мы верим, что слияние создаст значительную синергию."}, {"speaker": "מנכ״ל ב", "text_he": "עקרונית מסכים, אבל מה לגבי שווי החברות?", "text_ru": "В принципе согласен, но что насчёт оценки компаний?"}, {"speaker": "מנכ״ל א", "text_he": "הצענו חלוקה של שישים-ארבעים. אנחנו גדולים יותר.", "text_ru": "Мы предложили разделение шестьдесят-сорок. Мы крупнее."}, {"speaker": "מנכ״ל ב", "text_he": "חמישים חמישים. הטכנולוגיה שלנו שווה יותר ממה שהנתונים מראים.", "text_ru": "Пятьдесят на пятьдесят. Наша технология стоит больше, чем показывают данные."}, {"speaker": "מנכ״ל א", "text_he": "נצטרך לעשות הערכת שווי בלתי תלויה.", "text_ru": "Нам нужна независимая оценка стоимости."}, {"speaker": "מנכ״ל ב", "text_he": "מסכים. ומה עם העובדים? אנחנו לא רוצים פיטורים.", "text_ru": "Согласен. А что с сотрудниками? Мы не хотим увольнений."}, {"speaker": "מנכ״ל א", "text_he": "גם אנחנו. נתחייב לתקופת יציבות של שנה.", "text_ru": "Мы тоже. Обязуемся на период стабильности в один год."}, {"speaker": "מנכ״ל ב", "text_he": "יופי. נחתום על מזכר הבנות ונמשיך משם.", "text_ru": "Хорошо. Подпишем меморандум о взаимопонимании и продолжим оттуда."}]', '[{"word": "מיזוג", "translation": "слияние", "transliteration": "мизУг"}, {"word": "סינרגיה", "translation": "синергия", "transliteration": "синЕргия"}, {"word": "הערכת שווי", "translation": "оценка стоимости", "transliteration": "хаарахАт шавИ"}, {"word": "מזכר הבנות", "translation": "меморандум о взаимопонимании", "transliteration": "мизкАр аванОт"}, {"word": "יציבות", "translation": "стабильность", "transliteration": "йецивУт"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (216, 4, 'סכסוך משפחתי: בחירת מקצוע', 'Родители не согласны с выбором профессии дочери.', '[{"speaker": "אבא", "text_he": "אומנות?! מאיפה תתפרנסי?", "text_ru": "Искусство?! Чем ты будешь зарабатывать?"}, {"speaker": "בת", "text_he": "אבא, אני רוצה ללמוד מה שאני אוהבת.", "text_ru": "Папа, я хочу учить то, что люблю."}, {"speaker": "אמא", "text_he": "אנחנו רק דואגים לעתיד שלך, מותק.", "text_ru": "Мы просто беспокоимся о твоём будущем, милая."}, {"speaker": "בת", "text_he": "אני יודעת, אבל זה החלום שלי. ויש עבודות באומנות!", "text_ru": "Я знаю, но это моя мечта. И есть работа в искусстве!"}, {"speaker": "אבא", "text_he": "עבודות עם משכורת מינימום. תלמדי משהו יציב.", "text_ru": "Работа с минимальной зарплатой. Учи что-нибудь стабильное."}, {"speaker": "בת", "text_he": "משה שיין לומד מוזיקה ומרוויח יפה. לא כולם מרוויחים מעט.", "text_ru": "Моше Шейн учился музыке и хорошо зарабатывает. Не все мало получают."}, {"speaker": "אמא", "text_he": "אולי תלמדי תואר כפול? אומנות ועוד משהו?", "text_ru": "Может, получишь двойной диплом? Искусство плюс что-нибудь?"}, {"speaker": "בת", "text_he": "זה רעיון לא רע. אומנות ועיצוב גרפי. מה דעתכם?", "text_ru": "Неплохая идея. Искусство и графический дизайн. Как вам?"}, {"speaker": "אבא", "text_he": "עם זה אני יכול לחיות.", "text_ru": "С этим я могу смириться."}]', '[{"word": "להתפרנס", "translation": "зарабатывать на жизнь", "transliteration": "лехитпарнЕс"}, {"word": "עתיד", "translation": "будущее", "transliteration": "атИд"}, {"word": "תואר כפול", "translation": "двойной диплом", "transliteration": "тОар кафУль"}, {"word": "עיצוב", "translation": "дизайн", "transliteration": "ицУв"}, {"word": "יציב", "translation": "стабильный", "transliteration": "яцИв"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (217, 4, 'דיון דתי-חילוני: שבת', 'Религиозный и светский коллеги спорят о работе по субботам.', '[{"speaker": "אלי", "text_he": "אי אפשר לפתוח את החנות בשבת. זה נגד ההלכה.", "text_ru": "Нельзя открывать магазин в субботу. Это против Халахи."}, {"speaker": "דנית", "text_he": "אבל אנחנו מדינה דמוקרטית, לא תיאוקרטית.", "text_ru": "Но мы демократическое государство, не теократическое."}, {"speaker": "אלי", "text_he": "שבת היא חלק מהזהות היהודית. גם של חילונים.", "text_ru": "Суббота — часть еврейской идентичности. Даже светских людей."}, {"speaker": "דנית", "text_he": "אני מכבדת את השבת שלך, אבל אל תכפה עליי.", "text_ru": "Я уважаю твою субботу, но не навязывай мне."}, {"speaker": "אלי", "text_he": "זו לא כפייה, זו שמירה על אופי המדינה.", "text_ru": "Это не навязывание, это сохранение характера государства."}, {"speaker": "דנית", "text_he": "בתל אביב הכל פתוח בשבת, ושם הכי הרבה ישראלים.", "text_ru": "В Тель-Авиве всё открыто в субботу, и там больше всего израильтян."}, {"speaker": "אלי", "text_he": "נצטרך למצוא פשרה שמכבדת את כולם.", "text_ru": "Нам придётся найти компромисс, уважающий всех."}, {"speaker": "דנית", "text_he": "על זה אני מסכימה.", "text_ru": "С этим я согласна."}]', '[{"word": "הלכה", "translation": "Халаха (еврейский закон)", "transliteration": "халахА"}, {"word": "חילוני", "translation": "светский", "transliteration": "хилонИ"}, {"word": "דתי", "translation": "религиозный", "transliteration": "датИ"}, {"word": "כפייה", "translation": "принуждение", "transliteration": "кфийА"}, {"word": "זהות", "translation": "идентичность", "transliteration": "зехУт"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (218, 4, 'אקטיביזם ירוק: מחאה סביבתית', 'Экоактивисты обсуждают стратегию протеста против загрязнения.', '[{"speaker": "פעילה", "text_he": "המפעל ממשיך לזהם את הנחל. צריך לפעול.", "text_ru": "Завод продолжает загрязнять ручей. Нужно действовать."}, {"speaker": "פעיל", "text_he": "הגשנו עתירה לבית המשפט, אבל זה לוקח זמן.", "text_ru": "Мы подали петицию в суд, но это занимает время."}, {"speaker": "פעילה", "text_he": "בינתיים הדגים מתים. צריך גם מחאה ציבורית.", "text_ru": "А пока рыбы гибнут. Нужен и общественный протест."}, {"speaker": "פעיל", "text_he": "הפגנה מול המפעל? או קמפיין ברשתות?", "text_ru": "Демонстрация у завода? Или кампания в соцсетях?"}, {"speaker": "פעילה", "text_he": "שניהם. ונזמין עיתונאים לראות את הזיהום בעיניים.", "text_ru": "Оба. И пригласим журналистов увидеть загрязнение своими глазами."}, {"speaker": "פעיל", "text_he": "רעיון טוב. לחץ תקשורתי עוזר.", "text_ru": "Хорошая идея. Медийное давление помогает."}, {"speaker": "פעילה", "text_he": "הסביבה שלנו. האחריות שלנו.", "text_ru": "Наша среда. Наша ответственность."}]', '[{"word": "זיהום", "translation": "загрязнение", "transliteration": "зихУм"}, {"word": "נחל", "translation": "ручей", "transliteration": "нАхаль"}, {"word": "עתירה", "translation": "петиция", "transliteration": "атирА"}, {"word": "הפגנה", "translation": "демонстрация", "transliteration": "хафганА"}, {"word": "סביבה", "translation": "среда/окружение", "transliteration": "свивА"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (219, 4, 'פיץ׳ סטארט-אפ: אפליקציית בריאות', 'Основатель стартапа презентует приложение инвестору.', '[{"speaker": "יזם", "text_he": "האפליקציה שלנו מנתחת תזונה באמצעות בינה מלאכותית.", "text_ru": "Наше приложение анализирует питание с помощью ИИ."}, {"speaker": "משקיע", "text_he": "מעניין. מה שונה מהמתחרים?", "text_ru": "Интересно. Чем вы отличаетесь от конкурентов?"}, {"speaker": "יזם", "text_he": "אנחנו משתמשים בצילום — מצלמים את האוכל ומקבלים ניתוח מלא.", "text_ru": "Мы используем фотографию — фотографируете еду и получаете полный анализ."}, {"speaker": "משקיע", "text_he": "כמה משתמשים יש לכם?", "text_ru": "Сколько у вас пользователей?"}, {"speaker": "יזם", "text_he": "חמישים אלף. צמחנו שלוש מאות אחוז בחצי שנה.", "text_ru": "Пятьдесят тысяч. Выросли на триста процентов за полгода."}, {"speaker": "משקיע", "text_he": "מרשים. מה מודל ההכנסה?", "text_ru": "Впечатляет. Какая модель дохода?"}, {"speaker": "יזם", "text_he": "מנוי חודשי, שלושים שקלים. ויש גם גרסה חינמית בסיסית.", "text_ru": "Ежемесячная подписка, тридцать шекелей. И есть базовая бесплатная версия."}, {"speaker": "משקיע", "text_he": "כמה אתם מחפשים?", "text_ru": "Сколько вы ищете?"}, {"speaker": "יזם", "text_he": "חמישה מיליון שקלים. סבב A.", "text_ru": "Пять миллионов шекелей. Раунд A."}]', '[{"word": "יזם", "translation": "предприниматель", "transliteration": "язАм"}, {"word": "משקיע", "translation": "инвестор", "transliteration": "машкИа"}, {"word": "מנוי", "translation": "подписка", "transliteration": "мануЙ"}, {"word": "מתחרים", "translation": "конкуренты", "transliteration": "митхарИм"}, {"word": "מודל הכנסה", "translation": "модель дохода", "transliteration": "модЕль хахнасА"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (220, 4, 'אצל הפסיכולוגית: לחץ בעבודה', 'Пациент обсуждает рабочий стресс с психологом.', '[{"speaker": "מטופל", "text_he": "אני מרגיש שהכל מתפורר. אין לי כוח.", "text_ru": "Я чувствую, что всё рушится. У меня нет сил."}, {"speaker": "פסיכולוגית", "text_he": "ספר לי מה קורה. מתי זה התחיל?", "text_ru": "Расскажите, что происходит. Когда это началось?"}, {"speaker": "מטופל", "text_he": "לפני שלושה חודשים. קיבלתי קידום והלחץ עלה.", "text_ru": "Три месяца назад. Получил повышение, и давление возросло."}, {"speaker": "פסיכולוגית", "text_he": "הלחץ גורם לך לא לישון?", "text_ru": "Стресс мешает вам спать?"}, {"speaker": "מטופל", "text_he": "כן. אני קם בשלוש בלילה וחושב על העבודה.", "text_ru": "Да. Я просыпаюсь в три ночи и думаю о работе."}, {"speaker": "פסיכולוגית", "text_he": "חשוב לזהות את הגבולות שלך. לא חייבים להיות מושלמים.", "text_ru": "Важно осознавать свои границы. Не обязательно быть совершенным."}, {"speaker": "מטופל", "text_he": "אני יודע, אבל קשה לי לוותר על שליטה.", "text_ru": "Я знаю, но мне трудно отпустить контроль."}, {"speaker": "פסיכולוגית", "text_he": "זה משהו שנעבוד עליו יחד. נפגש שוב בשבוע הבא?", "text_ru": "Это то, над чем мы будем работать вместе. Встретимся снова на следующей неделе?"}]', '[{"word": "פסיכולוגית", "translation": "психолог (ж.)", "transliteration": "психолОгит"}, {"word": "לחץ", "translation": "стресс/давление", "transliteration": "лАхац"}, {"word": "קידום", "translation": "повышение", "transliteration": "кидУм"}, {"word": "גבולות", "translation": "границы", "transliteration": "гвулОт"}, {"word": "שליטה", "translation": "контроль", "transliteration": "шлитА"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (221, 5, 'דיספוט פילוסופי: חופש הרצון', 'Два философа спорят о свободе воли на академическом семинаре.', '[{"speaker": "פרופ׳ ברק", "text_he": "אם כל פעולה נקבעת מראש על ידי חוקי הטבע, האם יש משמעות למוסר?", "text_ru": "Если каждое действие предопределено законами природы, есть ли смысл в морали?"}, {"speaker": "ד״ר אורן", "text_he": "הדטרמיניזם אינו שולל אחריות מוסרית. הוא רק מגדיר אותה אחרת.", "text_ru": "Детерминизм не отрицает моральную ответственность. Он лишь определяет её иначе."}, {"speaker": "פרופ׳ ברק", "text_he": "כיצד? אם לא יכולתי לבחור אחרת, במה אני אשם?", "text_ru": "Каким образом? Если я не мог выбрать иначе, в чём моя вина?"}, {"speaker": "ד״ר אורן", "text_he": "הקומפטיביליזם של פרנקפורט מציע שחופש אינו היעדר סיבתיות, אלא פעולה מתוך רצון פנימי.", "text_ru": "Компатибилизм Франкфурта предполагает, что свобода — не отсутствие причинности, а действие из внутреннего желания."}, {"speaker": "פרופ׳ ברק", "text_he": "אבל גם הרצון הפנימי נקבע על ידי גורמים שאינם בשליטתנו.", "text_ru": "Но и внутреннее желание определяется факторами, не находящимися под нашим контролем."}, {"speaker": "ד״ר אורן", "text_he": "זו הנסיגה האינסופית הקלאסית. אבל בפועל אנחנו חווים בחירה.", "text_ru": "Это классический бесконечный регресс. Но на практике мы переживаем выбор."}, {"speaker": "פרופ׳ ברק", "text_he": "החוויה אינה הוכחה. גם אשליות נחוות כמציאות.", "text_ru": "Переживание — не доказательство. И иллюзии переживаются как реальность."}, {"speaker": "ד״ר אורן", "text_he": "אם חופש הרצון הוא אשליה, אז גם הדיון הזה חסר משמעות — ואני לא מוכן לקבל את זה.", "text_ru": "Если свобода воли — иллюзия, то и эта дискуссия бессмысленна — а я не готов это принять."}]', '[{"word": "חופש הרצון", "translation": "свобода воли", "transliteration": "хОфеш харацОн"}, {"word": "דטרמיניזם", "translation": "детерминизм", "transliteration": "детерминИзм"}, {"word": "סיבתיות", "translation": "причинность", "transliteration": "сибатиЮт"}, {"word": "נסיגה אינסופית", "translation": "бесконечный регресс", "transliteration": "несигА эйнсофИт"}, {"word": "אשליה", "translation": "иллюзия", "transliteration": "ашлайА"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (222, 5, 'ניתוח שיר: רחל המשוררת', 'Преподаватель и студент анализируют стихотворение поэтессы Рахели.', '[{"speaker": "מרצה", "text_he": "נתחיל בשיר \"רק על עצמי\" של רחל. מה הרושם הראשוני?", "text_ru": "Начнём со стихотворения «Только о себе» Рахели. Какое первое впечатление?"}, {"speaker": "סטודנט", "text_he": "השיר כואב. היא כותבת על בדידות, על דרך צרה.", "text_ru": "Стихотворение болезненное. Она пишет об одиночестве, об узком пути."}, {"speaker": "מרצה", "text_he": "\"דרכי צרה\" — שימי לב למילה. בעברית זה גם \"צרה\" כמו בעיה.", "text_ru": "«Узкий путь» — обратите внимание на слово. На иврите это также «цара» — беда."}, {"speaker": "סטודנט", "text_he": "כפל משמעות מעניין! ומה לגבי \"לא כיבשתי את הפסגות\"?", "text_ru": "Интересная многозначность! А что насчёт «я не покорила вершин»?"}, {"speaker": "מרצה", "text_he": "רחל מנגידה את עצמה לדמויות גדולות. היא מקבלת את הקטנות שלה — וזו גדלות.", "text_ru": "Рахель противопоставляет себя великим. Она принимает свою малость — и в этом величие."}, {"speaker": "סטודנט", "text_he": "המקצב גם חשוב. כל שורה קצרה, כמו נשימה קטועה.", "text_ru": "Ритм тоже важен. Каждая строка короткая, как прерывистое дыхание."}, {"speaker": "מרצה", "text_he": "מצוין! הצורה משרתת את התוכן. הצמצום הוא חלק מהמסר.", "text_ru": "Отлично! Форма служит содержанию. Лаконичность — часть послания."}, {"speaker": "סטודנט", "text_he": "ועכשיו אני מבין למה היא אחת המשוררות האהובות ביותר בישראל.", "text_ru": "И теперь я понимаю, почему она одна из самых любимых поэтесс Израиля."}]', '[{"word": "משוררת", "translation": "поэтесса", "transliteration": "мешорЕрет"}, {"word": "כפל משמעות", "translation": "двойной смысл", "transliteration": "кЕфель машмаУт"}, {"word": "מקצב", "translation": "ритм", "transliteration": "микцАв"}, {"word": "פסגה", "translation": "вершина", "transliteration": "писгА"}, {"word": "צמצום", "translation": "лаконичность/сжатие", "transliteration": "цимцУм"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (223, 5, 'דיון על פסיקת בג״ץ: חופש הביטוי', 'Юристы обсуждают решение Верховного суда о свободе слова.', '[{"speaker": "עו״ד רוזן", "text_he": "פסיקת בג\"ץ בעניין השלטים חריגה. בית המשפט הרחיב את חופש הביטוי.", "text_ru": "Решение БАГАЦа по делу о плакатах необычно. Суд расширил свободу слова."}, {"speaker": "עו״ד מזרחי", "text_he": "אבל הוא גם קבע שחופש הביטוי אינו מוחלט. יש גבולות.", "text_ru": "Но он также установил, что свобода слова не абсолютна. Есть границы."}, {"speaker": "עו״ד רוזן", "text_he": "הגבולות נקבעו לפי מבחן המידתיות: האם הפגיעה בחופש הביטוי מוצדקת?", "text_ru": "Границы установлены по критерию соразмерности: оправдано ли ограничение свободы слова?"}, {"speaker": "עו״ד מזרחי", "text_he": "השופטת חיות כתבה חוות דעת מרתקת על האיזון בין ביטוי לכבוד.", "text_ru": "Судья Хают написала захватывающее мнение о балансе между высказыванием и достоинством."}, {"speaker": "עו״ד רוזן", "text_he": "היא הסתמכה על הפסיקה האמריקאית, אבל הלכה רחוק יותר.", "text_ru": "Она опиралась на американскую практику, но пошла дальше."}, {"speaker": "עו״ד מזרחי", "text_he": "בישראל אין תיקון ראשון. אנחנו מאזנים אחרת.", "text_ru": "В Израиле нет Первой поправки. Мы балансируем иначе."}, {"speaker": "עו״ד רוזן", "text_he": "בדיוק. וזו הייחודיות של המשפט הישראלי — פרגמטיזם ערכי.", "text_ru": "Именно. И в этом уникальность израильского права — ценностный прагматизм."}]', '[{"word": "בג״ץ", "translation": "БАГАЦ (Верховный суд)", "transliteration": "бАгац"}, {"word": "חופש הביטוי", "translation": "свобода слова", "transliteration": "хОфеш хабитУй"}, {"word": "מידתיות", "translation": "соразмерность", "transliteration": "мидатиЮт"}, {"word": "חוות דעת", "translation": "мнение (юр.)", "transliteration": "хавАт дАат"}, {"word": "פרגמטיזם", "translation": "прагматизм", "transliteration": "прагматИзм"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (224, 5, 'ניתוח ספרותי: אצל עגנון', 'Семинар по литературе: анализ рассказа Агнона.', '[{"speaker": "מרצה", "text_he": "ב\"תמול שלשום\" עגנון משתמש בכלב בלק כסמל. למה של מה?", "text_ru": "В «Вчера-позавчера» Агнон использует пса Балака как символ. Чего?"}, {"speaker": "סטודנטית", "text_he": "הכלב מייצג את הגורל — כוח עיוור שרודף את הגיבור.", "text_ru": "Пёс олицетворяет судьбу — слепую силу, преследующую героя."}, {"speaker": "מרצה", "text_he": "אפשרות אחת. אבל יש קריאות אחרות. מישהו?", "text_ru": "Один вариант. Но есть и другие прочтения. Кто-нибудь?"}, {"speaker": "סטודנט", "text_he": "הכלב מייצג את המצפון. הכיתוב על גבו — \"כלב משוגע\" — זו הסטיגמה.", "text_ru": "Пёс олицетворяет совесть. Надпись на его спине — «бешеный пёс» — это стигма."}, {"speaker": "מרצה", "text_he": "יפה! עגנון יוצר אלגוריה רב-שכבתית. הטקסט לא נסגר על פירוש אחד.", "text_ru": "Прекрасно! Агнон создаёт многослойную аллегорию. Текст не замыкается на одной интерпретации."}, {"speaker": "סטודנטית", "text_he": "ומה לגבי השפה? הוא כותב כאילו בתמימות, אבל מתחת — אירוניה.", "text_ru": "А что насчёт языка? Он пишет как бы простодушно, но под этим — ирония."}, {"speaker": "מרצה", "text_he": "גרשון שקד קרא לזה \"דובר אמין שאינו אמין\". זו ההבחנה המרכזית.", "text_ru": "Гершон Шакед назвал это «надёжный ненадёжный рассказчик». Это ключевое различие."}, {"speaker": "סטודנט", "text_he": "כלומר, צריך לקרוא את עגנון תמיד בחשד?", "text_ru": "То есть, Агнона надо всегда читать с подозрением?"}, {"speaker": "מרצה", "text_he": "בדיוק! כל משפט צופן יותר ממה שנראה על פני השטח.", "text_ru": "Именно! Каждое предложение скрывает больше, чем кажется на поверхности."}]', '[{"word": "אלגוריה", "translation": "аллегория", "transliteration": "алегОрия"}, {"word": "רב-שכבתי", "translation": "многослойный", "transliteration": "рав-шихватИ"}, {"word": "סטיגמה", "translation": "стигма", "transliteration": "стИгма"}, {"word": "מצפון", "translation": "совесть", "transliteration": "мацпУн"}, {"word": "פירוש", "translation": "интерпретация", "transliteration": "перУш"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (225, 5, 'גישור קהילתי: שכונה מעורבת', 'Медиатор помогает разрешить конфликт между еврейскими и арабскими жителями района.', '[{"speaker": "מגשרת", "text_he": "תודה שבאתם. המטרה שלנו היום — לשמוע אחד את השני.", "text_ru": "Спасибо, что пришли. Наша цель сегодня — выслушать друг друга."}, {"speaker": "תושב א", "text_he": "אנחנו מרגישים שלא רואים אותנו. הצרכים שלנו מתעלמים.", "text_ru": "Мы чувствуем, что нас не замечают. Наши нужды игнорируются."}, {"speaker": "תושבת ב", "text_he": "גם לנו יש תלונות. הרעש מהמסגד בחמש בבוקר מפריע.", "text_ru": "У нас тоже есть жалобы. Шум из мечети в пять утра мешает."}, {"speaker": "תושב א", "text_he": "זו מסורת של מאות שנים! אתם לא יכולים לבטל את זה.", "text_ru": "Это традиция сотен лет! Вы не можете это отменить."}, {"speaker": "מגשרת", "text_he": "רגע. אנחנו כאן לא כדי לבטל, אלא כדי למצוא פתרון שמכבד את כולם.", "text_ru": "Подождите. Мы здесь не чтобы отменять, а чтобы найти решение, уважающее всех."}, {"speaker": "תושבת ב", "text_he": "אולי אפשר להנמיך את הרמקולים? אנחנו לא מתנגדים לתפילה.", "text_ru": "Может, можно уменьшить громкость динамиков? Мы не против молитвы."}, {"speaker": "תושב א", "text_he": "אם גם בית הכנסת יקפיד על שעות שקטות.", "text_ru": "Если и синагога будет соблюдать тихие часы."}, {"speaker": "מגשרת", "text_he": "הנה! זו התחלה. הדדיות היא הבסיס לדו-קיום.", "text_ru": "Вот! Это начало. Взаимность — основа сосуществования."}]', '[{"word": "גישור", "translation": "медиация", "transliteration": "гишУр"}, {"word": "דו-קיום", "translation": "сосуществование", "transliteration": "ду-киЮм"}, {"word": "הדדיות", "translation": "взаимность", "transliteration": "хададиЮт"}, {"word": "תושב", "translation": "житель", "transliteration": "тошАв"}, {"word": "מסורת", "translation": "традиция", "transliteration": "масОрет"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (234, 6, 'סלון פילוסופי: לוינס ובובר', 'Философский салон: сравнение диалогической философии Левинаса и Бубера.', '[{"speaker": "מנחה", "text_he": "גם בובר וגם לוינס מדברים על מפגש עם האחר. מה ההבדל?", "text_ru": "И Бубер, и Левинас говорят о встрече с Другим. В чём различие?"}, {"speaker": "משתתפת", "text_he": "אצל בובר — היחס סימטרי. \"אני-אתה\" הוא הדדי.", "text_ru": "У Бубера — отношение симметрично. «Я-Ты» взаимно."}, {"speaker": "משתתף", "text_he": "ואצל לוינס — אסימטרי לחלוטין. אני חייב לאחר יותר ממה שהוא חייב לי.", "text_ru": "А у Левинаса — полностью асимметрично. Я обязан Другому больше, чем он мне."}, {"speaker": "מנחה", "text_he": "למה לוינס דורש אסימטריה? מה השורש של זה?", "text_ru": "Почему Левинас требует асимметрии? В чём её корень?"}, {"speaker": "משתתפת", "text_he": "הפנים של האחר קוראות \"לא תרצח\". זו קריאה שאי אפשר לסרב לה.", "text_ru": "Лицо Другого взывает «не убий». Это призыв, которому невозможно отказать."}, {"speaker": "משתתף", "text_he": "דרידה שאל: אם האחריות אינסופית, האם היא בכלל אפשרית?", "text_ru": "Деррида спрашивал: если ответственность бесконечна, возможна ли она вообще?"}, {"speaker": "מנחה", "text_he": "ובובר היה אומר: מספיק להיות נוכח ברגע. לא צריך אינסוף.", "text_ru": "А Бубер бы сказал: достаточно быть присутствующим в моменте. Не нужна бесконечность."}, {"speaker": "משתתפת", "text_he": "אולי ההבדל הוא בין אתיקה יהודית לאתיקה אוניברסלית.", "text_ru": "Может, различие — между еврейской этикой и универсальной."}]', '[{"word": "סימטרי", "translation": "симметричный", "transliteration": "симЕтри"}, {"word": "אסימטרי", "translation": "асимметричный", "transliteration": "асимЕтри"}, {"word": "אחריות", "translation": "ответственность", "transliteration": "ахраЮт"}, {"word": "נוכח", "translation": "присутствующий", "transliteration": "нохЕах"}, {"word": "אתיקה", "translation": "этика", "transliteration": "Этика"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (226, 5, 'הגנה על תזה: סוציולוגיה', 'Студент защищает магистерскую диссертацию по социологии.', '[{"speaker": "מנחה", "text_he": "תציג בבקשה את ממצאי המחקר בקצרה.", "text_ru": "Пожалуйста, кратко представьте результаты исследования."}, {"speaker": "תלמיד", "text_he": "חקרתי את ההשפעה של רשתות חברתיות על הפרדה עדתית בישראל.", "text_ru": "Я исследовал влияние социальных сетей на этническую сегрегацию в Израиле."}, {"speaker": "בוחנת", "text_he": "איך הגדרת \"הפרדה עדתית\" באופן אופרטיבי?", "text_ru": "Как вы операционально определили «этническую сегрегацию»?"}, {"speaker": "תלמיד", "text_he": "מדדתי את ההומוגניות של רשתות החברים — כמה מהחברים שייכים לאותה קבוצה.", "text_ru": "Измерял гомогенность сетей друзей — сколько друзей принадлежат к той же группе."}, {"speaker": "בוחנת", "text_he": "והממצא המפתיע?", "text_ru": "И неожиданный результат?"}, {"speaker": "תלמיד", "text_he": "הרשתות דווקא מגבירות הפרדה. האלגוריתם מציג תוכן דומה, לא שונה.", "text_ru": "Сети как раз усиливают сегрегацию. Алгоритм показывает похожий контент, не различный."}, {"speaker": "מנחה", "text_he": "מה המשמעות המעשית? מה אתה ממליץ?", "text_ru": "Каков практический смысл? Что вы рекомендуете?"}, {"speaker": "תלמיד", "text_he": "תכניות חינוך דיגיטלי שמעודדות חשיפה למגוון קולות.", "text_ru": "Программы цифрового образования, поощряющие знакомство с разнообразием голосов."}]', '[{"word": "תזה", "translation": "диссертация", "transliteration": "тЕза"}, {"word": "ממצאים", "translation": "результаты/находки", "transliteration": "мимцаИм"}, {"word": "הפרדה", "translation": "сегрегация", "transliteration": "хафрадА"}, {"word": "עדתי", "translation": "этнический/общинный", "transliteration": "адатИ"}, {"word": "הומוגניות", "translation": "гомогенность", "transliteration": "хомогениЮт"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (227, 5, 'משא ומתן דיפלומטי: הסכם מים', 'Дипломаты Израиля и Иордании обсуждают соглашение о водных ресурсах.', '[{"speaker": "נציג ישראלי", "text_he": "המשבר מחייב שיתוף פעולה. שני הצדדים סובלים ממחסור.", "text_ru": "Кризис обязывает к сотрудничеству. Обе стороны страдают от дефицита."}, {"speaker": "נציג ירדני", "text_he": "אנחנו מסכימים. אבל החלוקה צריכה להיות הוגנת.", "text_ru": "Мы согласны. Но распределение должно быть справедливым."}, {"speaker": "נציג ישראלי", "text_he": "אנחנו מציעים מתקן התפלה משותף בים המלח.", "text_ru": "Мы предлагаем совместную опреснительную установку на Мёртвом море."}, {"speaker": "נציג ירדני", "text_he": "מי ימן את הפרויקט?", "text_ru": "Кто финансирует проект?"}, {"speaker": "נציג ישראלי", "text_he": "חלוקה שווה, עם סיוע בינלאומי. הבנק העולמי הביע עניין.", "text_ru": "Равное разделение, с международной помощью. Всемирный банк выразил интерес."}, {"speaker": "נציג ירדני", "text_he": "ומה לגבי הטכנולוגיה? ישראל מובילה בהתפלה.", "text_ru": "А что насчёт технологии? Израиль лидирует в опреснении."}, {"speaker": "נציג ישראלי", "text_he": "נעביר את הידע. זה אינטרס משותף — מים הם ביטחון.", "text_ru": "Мы передадим знания. Это общий интерес — вода — это безопасность."}, {"speaker": "נציג ירדני", "text_he": "מוסכם. נתחיל בצוות מקצועי משותף.", "text_ru": "Договорились. Начнём с совместной рабочей группы."}]', '[{"word": "דיפלומטיה", "translation": "дипломатия", "transliteration": "дипломАтия"}, {"word": "התפלה", "translation": "опреснение", "transliteration": "хатпалА"}, {"word": "מחסור", "translation": "дефицит/нехватка", "transliteration": "махсОр"}, {"word": "סיוע", "translation": "помощь", "transliteration": "сиЮа"}, {"word": "אינטרס משותף", "translation": "общий интерес", "transliteration": "интерЕс мешутАф"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (228, 5, 'ראיון עם סופרת: ספרה החדש', 'Журналист берёт интервью у израильской писательницы о новом романе.', '[{"speaker": "מראיין", "text_he": "הספר החדש שלך עוסק בעלייה מאתיופיה. למה דווקא הנושא הזה?", "text_ru": "Ваша новая книга посвящена репатриации из Эфиопии. Почему именно эта тема?"}, {"speaker": "סופרת", "text_he": "כי זה סיפור שלא סופר מספיק. ההיסטוריה הישראלית מספרת בעיקר נרטיב אשכנזי.", "text_ru": "Потому что это история, которую недостаточно рассказывали. Израильская история рассказывает в основном ашкеназский нарратив."}, {"speaker": "מראיין", "text_he": "הגיבורה — ילדה בת שתים עשרה. למה דרך עיני ילדה?", "text_ru": "Героиня — двенадцатилетняя девочка. Почему через глаза ребёнка?"}, {"speaker": "סופרת", "text_he": "ילד רואה את העולם בלי פילטרים. הוא לא יודע מה \"אמור\" להרגיש. הוא פשוט מרגיש.", "text_ru": "Ребёнок видит мир без фильтров. Он не знает, что «должен» чувствовать. Он просто чувствует."}, {"speaker": "מראיין", "text_he": "הביקורות היו מעורבות. יש שטענו שאת \"מנכסת\" סיפור שאינו שלך.", "text_ru": "Отзывы были смешанными. Некоторые утверждали, что вы «присваиваете» чужую историю."}, {"speaker": "סופרת", "text_he": "שמעתי. ואני מבינה את הטענה. אבל אם רק מי שחווה יכול לכתוב — הספרות תמות.", "text_ru": "Слышала. И я понимаю претензию. Но если писать может только тот, кто пережил, — литература умрёт."}, {"speaker": "מראיין", "text_he": "מה היית רוצה שהקורא ייקח מהספר?", "text_ru": "Что бы вы хотели, чтобы читатель вынес из книги?"}, {"speaker": "סופרת", "text_he": "אמפתיה. היכולת לראות את העולם דרך עיניים אחרות.", "text_ru": "Эмпатию. Способность увидеть мир чужими глазами."}]', '[{"word": "סופרת", "translation": "писательница", "transliteration": "софЕрет"}, {"word": "נרטיב", "translation": "нарратив", "transliteration": "наратИв"}, {"word": "לנכס", "translation": "присваивать", "transliteration": "ленакЕс"}, {"word": "אמפתיה", "translation": "эмпатия", "transliteration": "эмпАтия"}, {"word": "ביקורות", "translation": "рецензии/отзывы", "transliteration": "бикорОт"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (229, 5, 'דיון בכנסת: רפורמה בחינוך', 'Дебаты в Кнессете о реформе образования.', '[{"speaker": "ח״כ כהן", "text_he": "הרפורמה תבטיח לימודי ליבה בכל המגזרים — כולל החרדי.", "text_ru": "Реформа обеспечит базовые предметы во всех секторах — включая ультраортодоксальный."}, {"speaker": "ח״כ פרידמן", "text_he": "זו פגיעה בחופש החינוך! אתם רוצים לכפות תרבות אחידה.", "text_ru": "Это посягательство на свободу образования! Вы хотите навязать единую культуру."}, {"speaker": "ח״כ כהן", "text_he": "חופש חינוך אינו חופש מבורות. ילדים צריכים מתמטיקה ואנגלית.", "text_ru": "Свобода образования — не свобода от невежества. Детям нужны математика и английский."}, {"speaker": "ח״כ פרידמן", "text_he": "ומה עם לימודי תורה? הם לא חשובים?", "text_ru": "А что с изучением Торы? Оно не важно?"}, {"speaker": "ח״כ כהן", "text_he": "חשובים! אבל לא על חשבון הכנה לשוק העבודה.", "text_ru": "Важно! Но не за счёт подготовки к рынку труда."}, {"speaker": "יו״ר", "text_he": "סדר! הנושא יועבר להצבעה בוועדת החינוך.", "text_ru": "Порядок! Вопрос передаётся на голосование в комиссию по образованию."}]', '[{"word": "רפורמה", "translation": "реформа", "transliteration": "рефОрма"}, {"word": "לימודי ליבה", "translation": "базовые предметы", "transliteration": "лимудЕй либА"}, {"word": "מגזר", "translation": "сектор", "transliteration": "мигзАр"}, {"word": "לכפות", "translation": "навязывать", "transliteration": "лихпОт"}, {"word": "הצבעה", "translation": "голосование", "transliteration": "хацбаА"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (230, 5, 'דיאלוג היסטורי: בן-גוריון וז׳בוטינסקי', 'Реконструкция воображаемого диалога между Бен-Гурионом и Жаботинским.', '[{"speaker": "בן-גוריון", "text_he": "המדינה צריכה מעמד פועלים חזק. בלי עובדים — אין מדינה.", "text_ru": "Государству нужен сильный рабочий класс. Без рабочих — нет государства."}, {"speaker": "ז׳בוטינסקי", "text_he": "לפני מעמד פועלים צריך ריבונות. בלי צבא — אין חופש.", "text_ru": "Прежде рабочего класса нужен суверенитет. Без армии — нет свободы."}, {"speaker": "בן-גוריון", "text_he": "את הריבונות בונים עובדה בשטח — התיישבות, קרקעות, מוסדות.", "text_ru": "Суверенитет строят фактами на земле — поселениями, землями, институтами."}, {"speaker": "ז׳בוטינסקי", "text_he": "עובדות בשטח ללא כוח צבאי הן בית על החול.", "text_ru": "Факты на земле без военной силы — это дом на песке."}, {"speaker": "בן-גוריון", "text_he": "ואני אומר שכוח צבאי ללא בסיס חברתי הוא מיליטריזם ריק.", "text_ru": "А я говорю, что военная сила без социальной базы — пустой милитаризм."}, {"speaker": "ז׳בוטינסקי", "text_he": "שנינו רוצים אותו דבר — מדינה יהודית. רק הדרך שונה.", "text_ru": "Мы оба хотим одного — еврейского государства. Лишь путь различен."}, {"speaker": "בן-גוריון", "text_he": "ההיסטוריה תשפוט מי צדק.", "text_ru": "История рассудит, кто прав."}, {"speaker": "ז׳בוטינסקי", "text_he": "ואולי שנינו צדקנו — כל אחד בדרכו.", "text_ru": "А может, мы оба правы — каждый по-своему."}]', '[{"word": "ריבונות", "translation": "суверенитет", "transliteration": "рибонУт"}, {"word": "התיישבות", "translation": "поселенчество", "transliteration": "хитъяшвУт"}, {"word": "מיליטריזם", "translation": "милитаризм", "transliteration": "милитарИзм"}, {"word": "מעמד פועלים", "translation": "рабочий класс", "transliteration": "маамАд поалИм"}, {"word": "עובדה בשטח", "translation": "факт на земле", "transliteration": "увдА башЕтах"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (231, 6, 'סוגיה תלמודית: בבא מציעא', 'Два учёных дискутируют о талмудическом споре о найденном предмете.', '[{"speaker": "רב א", "text_he": "\"שניים אוחזין בטלית\" — כל אחד טוען שהיא שלו. מה הדין?", "text_ru": "«Двое держатся за плащ» — каждый утверждает, что он его. Каков закон?"}, {"speaker": "רב ב", "text_he": "לפי המשנה, כל אחד נשבע שאין לו פחות מחצי, וחולקים.", "text_ru": "По Мишне, каждый клянётся, что ему принадлежит не менее половины, и делят."}, {"speaker": "רב א", "text_he": "אבל הגמרא שואלת: ולמה לא ניתן הכל למוחזק?", "text_ru": "Но Гемара спрашивает: а почему не отдать всё тому, кто владеет?"}, {"speaker": "רב ב", "text_he": "כי שניהם מוחזקים! שניהם אוחזים. זה ייחוד הסוגיה.", "text_ru": "Потому что оба владеют! Оба держат. В этом уникальность дискуссии."}, {"speaker": "רב א", "text_he": "רש\"י מפרש שהשבועה נועדה למנוע רמאות. בלעדיה — כל אחד יטען.", "text_ru": "Раши толкует, что клятва нужна для предотвращения обмана. Без неё — каждый будет заявлять."}, {"speaker": "רב ב", "text_he": "ותוספות חולקים: השבועה היא מדרבנן, לא מדאורייתא.", "text_ru": "А Тосафот возражают: клятва раввинская, не из Торы."}, {"speaker": "רב א", "text_he": "ההבחנה הזו משמעותית: היא קובעת את רמת החיוב.", "text_ru": "Это различие существенно: оно определяет уровень обязательства."}, {"speaker": "רב ב", "text_he": "כמו תמיד בתלמוד — שאלה אחת פותחת עשר.", "text_ru": "Как всегда в Талмуде — один вопрос открывает десять."}]', '[{"word": "סוגיה", "translation": "тема/дискуссия (талмуд.)", "transliteration": "сугийА"}, {"word": "מוחזק", "translation": "владелец/держатель", "transliteration": "мухзАк"}, {"word": "שבועה", "translation": "клятва", "transliteration": "швуА"}, {"word": "מדרבנן", "translation": "раввинский закон", "transliteration": "мидерабанАн"}, {"word": "מדאורייתא", "translation": "закон Торы", "transliteration": "медорАйта"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (232, 6, 'סמינר: פסקת ההתגברות', 'Семинар юрфака: дискуссия о праве парламента отменять решения суда.', '[{"speaker": "פרופ׳", "text_he": "פסקת ההתגברות מאפשרת לכנסת לחוקק מחדש חוק שנפסל בבג\"ץ. מה דעתכם?", "text_ru": "Оговорка о преодолении позволяет Кнессету заново принять закон, отменённый БАГАЦем. Ваше мнение?"}, {"speaker": "סטודנט א", "text_he": "זה הכרחי. הריבונות שייכת לעם, לא לשופטים שלא נבחרו.", "text_ru": "Это необходимо. Суверенитет принадлежит народу, а не неизбранным судьям."}, {"speaker": "סטודנטית ב", "text_he": "אבל בלי ביקורת שיפוטית — הרוב יכול לרמוס את המיעוט.", "text_ru": "Но без судебного контроля — большинство может растоптать меньшинство."}, {"speaker": "סטודנט א", "text_he": "גם בקנדה ובבריטניה יש מנגנוני התגברות. זה לא חריג.", "text_ru": "И в Канаде, и в Британии есть механизмы преодоления. Это не исключение."}, {"speaker": "סטודנטית ב", "text_he": "אבל שם יש חוקה מלאה ומגילת זכויות מושרשת. אצלנו — אין.", "text_ru": "Но там есть полная конституция и укоренённый билль о правах. У нас — нет."}, {"speaker": "פרופ׳", "text_he": "נקודה מצוינת. ההקשר המוסדי משנה את המשמעות.", "text_ru": "Отличное замечание. Институциональный контекст меняет значение."}, {"speaker": "סטודנט א", "text_he": "אז אולי הפתרון הוא קודם לכתוב חוקה, ואז לדון בהתגברות.", "text_ru": "Тогда, может, решение — сначала написать конституцию, а потом обсуждать преодоление."}, {"speaker": "פרופ׳", "text_he": "זו בדיוק הדילמה הישראלית: לא הסכמנו על הכללים לפני שהתחלנו לשחק.", "text_ru": "Это и есть израильская дилемма: мы не договорились о правилах до начала игры."}]', '[{"word": "פסקת התגברות", "translation": "оговорка о преодолении", "transliteration": "пискАт хитгабрУт"}, {"word": "ביקורת שיפוטית", "translation": "судебный контроль", "transliteration": "бикОрет шифутИт"}, {"word": "ריבונות", "translation": "суверенитет", "transliteration": "рибонУт"}, {"word": "מגילת זכויות", "translation": "билль о правах", "transliteration": "мегилАт зхуйОт"}, {"word": "מוסדי", "translation": "институциональный", "transliteration": "мосадИ"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (233, 6, 'ביקורת ספרותית: על יצירת עוז', 'Литературный критик и учёный обсуждают прозу Амоса Оза.', '[{"speaker": "מבקרת", "text_he": "עוז כותב את הסכסוך הלאומי דרך המיקרוקוסמוס של המשפחה.", "text_ru": "Оз пишет о национальном конфликте через микрокосм семьи."}, {"speaker": "חוקר", "text_he": "\"סיפור על אהבה וחושך\" הוא הדוגמה המובהקת. כל משפחה היא מדינה.", "text_ru": "«Повесть о любви и тьме» — ярчайший пример. Каждая семья — государство."}, {"speaker": "מבקרת", "text_he": "אבל יש ביקורת פמיניסטית: הנשים אצל עוז תמיד נעלמות או מתות.", "text_ru": "Но есть феминистская критика: женщины у Оза всегда исчезают или умирают."}, {"speaker": "חוקר", "text_he": "זה חלק מהטראומה האוטוביוגרפית. אמו התאבדה.", "text_ru": "Это часть автобиографической травмы. Его мать покончила с собой."}, {"speaker": "מבקרת", "text_he": "נכון, אבל האם הטראומה מצדיקה דפוס חוזר של השתקת הקול הנשי?", "text_ru": "Верно, но оправдывает ли травма повторяющийся паттерн замалчивания женского голоса?"}, {"speaker": "חוקר", "text_he": "שאלה לגיטימית. מצד שני, פניה בקולשיצקי כתבה שהנשים אצל עוז דווקא חתרניות.", "text_ru": "Легитимный вопрос. С другой стороны, Пнина Баршицки писала, что женщины у Оза как раз подрывные."}, {"speaker": "מבקרת", "text_he": "כנראה שהטקסט הטוב מכיל יותר ממה שהמחבר התכוון.", "text_ru": "Видимо, хороший текст содержит больше, чем намеревался автор."}]', '[{"word": "ביקורת ספרותית", "translation": "литературная критика", "transliteration": "бикОрет сифрутИт"}, {"word": "מיקרוקוסמוס", "translation": "микрокосм", "transliteration": "микрокОсмос"}, {"word": "חתרני", "translation": "подрывной", "transliteration": "хатранИ"}, {"word": "טראומה", "translation": "травма", "transliteration": "трАума"}, {"word": "דפוס", "translation": "паттерн/шаблон", "transliteration": "дфУс"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (235, 6, 'הרצאה: הדמוקרטיה הישראלית בסכנה?', 'Лекция и дискуссия: находится ли израильская демократия в опасности?', '[{"speaker": "מרצה", "text_he": "ישראל היא דמוקרטיה ללא חוקה, ללא הפרדת דת ומדינה, עם כיבוש מתמשך. האם זו עדיין דמוקרטיה?", "text_ru": "Израиль — демократия без конституции, без отделения религии от государства, с продолжающейся оккупацией. Это всё ещё демократия?"}, {"speaker": "סטודנטית", "text_he": "לפי הגדרה פרוצדורלית — כן. יש בחירות חופשיות.", "text_ru": "По процедурному определению — да. Есть свободные выборы."}, {"speaker": "סטודנט", "text_he": "אבל לפי הגדרה סובסטנטיבית — יש בעיה. לא כל התושבים שווים.", "text_ru": "Но по субстантивному определению — есть проблема. Не все жители равны."}, {"speaker": "מרצה", "text_he": "את מי אתה כולל? אזרחים ערבים? תושבי השטחים?", "text_ru": "Кого вы имеете в виду? Арабских граждан? Жителей территорий?"}, {"speaker": "סטודנט", "text_he": "את שניהם. אזרחים ערבים סובלים מאפליה מוסדית, והכיבוש מבטל זכויות בסיסיות.", "text_ru": "И тех, и тех. Арабские граждане страдают от институциональной дискриминации, а оккупация отменяет базовые права."}, {"speaker": "סטודנטית", "text_he": "יש גם צד שני: ישראל היא הדמוקרטיה היחידה במזרח התיכון.", "text_ru": "Есть и другая сторона: Израиль — единственная демократия на Ближнем Востоке."}, {"speaker": "מרצה", "text_he": "ה\"יחידה\" אינה פטור מביקורת. השאלה היא: לאיזו דמוקרטיה אנחנו שואפים?", "text_ru": "«Единственная» не освобождает от критики. Вопрос: к какой демократии мы стремимся?"}]', '[{"word": "פרוצדורלי", "translation": "процедурный", "transliteration": "процедурАли"}, {"word": "סובסטנטיבי", "translation": "субстантивный", "transliteration": "субстантИви"}, {"word": "אפליה מוסדית", "translation": "институц. дискриминация", "transliteration": "афлайА мосадИт"}, {"word": "כיבוש", "translation": "оккупация", "transliteration": "кибУш"}, {"word": "ריבונות", "translation": "суверенитет", "transliteration": "рибонУт"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (236, 6, 'פרשנות מקראית: עקדת יצחק', 'Академический семинар: разные интерпретации жертвоприношения Исаака.', '[{"speaker": "מרצה", "text_he": "\"קח נא את בנך את יחידך אשר אהבת את יצחק\" — למה כל ההדגשות?", "text_ru": "«Возьми сына твоего, единственного, которого ты любишь, Исаака» — зачем все эти уточнения?"}, {"speaker": "סטודנט", "text_he": "רש\"י אומר: כדי שלא תהיה טעות. כל מילה מצמצמת את הזיהוי.", "text_ru": "Раши говорит: чтобы не было ошибки. Каждое слово сужает идентификацию."}, {"speaker": "סטודנטית", "text_he": "אבל קירקגור ראה כאן מבחן אבסורדי — אמונה מעבר לתבונה.", "text_ru": "Но Кьеркегор видел здесь абсурдное испытание — веру за пределами разума."}, {"speaker": "מרצה", "text_he": "ולוינס? הוא הציע שהקול השני — \"אל תשלח ידך\" — הוא האתי.", "text_ru": "А Левинас? Он предположил, что второй голос — «не простирай руки» — является этическим."}, {"speaker": "סטודנטית", "text_he": "כלומר, הציות לאלוהים אינו מבטל את האחריות המוסרית.", "text_ru": "То есть, послушание Богу не отменяет моральной ответственности."}, {"speaker": "סטודנט", "text_he": "זה עומד בניגוד לקירקגור. אצלו — האמונה גוברת על המוסר.", "text_ru": "Это противоречит Кьеркегору. У него — вера превышает мораль."}, {"speaker": "מרצה", "text_he": "ובמסורת היהודית? המדרש אומר שאברהם בכה. הוא לא היה עיוור.", "text_ru": "А в еврейской традиции? Мидраш говорит, что Авраам плакал. Он не был слеп."}, {"speaker": "סטודנטית", "text_he": "הטקסט המקראי שותק ברגעים הכי כואבים. והשתיקה מדברת.", "text_ru": "Библейский текст молчит в самые болезненные моменты. И молчание говорит."}]', '[{"word": "עקדה", "translation": "жертвоприношение/связывание", "transliteration": "акедА"}, {"word": "פרשנות", "translation": "экзегеза/толкование", "transliteration": "паршанУт"}, {"word": "אבסורדי", "translation": "абсурдный", "transliteration": "абсУрди"}, {"word": "ציות", "translation": "послушание", "transliteration": "циЮт"}, {"word": "מדרש", "translation": "мидраш", "transliteration": "мидрАш"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (237, 6, 'ועדת אתיקה: ניסוי גנטי', 'Комитет по этике обсуждает разрешение на генетический эксперимент.', '[{"speaker": "יו״ר", "text_he": "לפנינו בקשה לאשר ניסוי בעריכה גנטית של עוברים. הדעות?", "text_ru": "Перед нами заявка на разрешение эксперимента по генному редактированию эмбрионов. Мнения?"}, {"speaker": "רופאה", "text_he": "הטכנולוגיה יכולה למנוע מחלות תורשתיות קשות. אי אפשר להתעלם מהפוטנציאל.", "text_ru": "Технология может предотвратить тяжёлые наследственные заболевания. Нельзя игнорировать потенциал."}, {"speaker": "פילוסוף", "text_he": "אבל איפה הגבול? היום מחלות, מחר עיניים כחולות.", "text_ru": "Но где граница? Сегодня болезни, завтра голубые глаза."}, {"speaker": "רופאה", "text_he": "הפרוטוקול מגביל לגנים הקשורים למחלות חמורות בלבד.", "text_ru": "Протокол ограничивает только генами, связанными с тяжёлыми заболеваниями."}, {"speaker": "רב", "text_he": "מנקודת מבט הלכתית, יש חובה לרפא. \"לא תעמוד על דם רעך\".", "text_ru": "С точки зрения Халахи, есть обязанность лечить. «Не стой на крови ближнего»."}, {"speaker": "פילוסוף", "text_he": "וחנה ארנדט הזהירה מפני \"ייצור\" בני אדם. זה מבטל את הנתינוּת — ההפתעה של מי שנולד.", "text_ru": "А Ханна Арендт предостерегала от «производства» людей. Это уничтожает нативность — сюрприз того, кто рождается."}, {"speaker": "יו״ר", "text_he": "אני מציע לאשר בתנאים מחמירים ובפיקוח רציף.", "text_ru": "Я предлагаю одобрить на строгих условиях и с постоянным контролем."}]', '[{"word": "עריכה גנטית", "translation": "генное редактирование", "transliteration": "арихА генЕтит"}, {"word": "עוברים", "translation": "эмбрионы", "transliteration": "уварИм"}, {"word": "תורשתי", "translation": "наследственный", "transliteration": "торашатИ"}, {"word": "נתינוּת", "translation": "нативность (рождённость)", "transliteration": "натинУт"}, {"word": "פיקוח", "translation": "контроль/надзор", "transliteration": "пикУах"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (238, 6, 'דיון בבית המשפט העליון: חופש הפגנה', 'Слушание в Верховном суде по вопросу ограничения демонстраций.', '[{"speaker": "שופטת", "text_he": "השאלה: האם המשטרה רשאית לאסור הפגנה בשל סיכון ביטחוני?", "text_ru": "Вопрос: вправе ли полиция запретить демонстрацию из-за угрозы безопасности?"}, {"speaker": "עו״ד עותר", "text_he": "חופש ההפגנה הוא זכות יסוד. האיסור חייב לעמוד במבחן המידתיות.", "text_ru": "Свобода демонстраций — основное право. Запрет должен выдержать тест на соразмерность."}, {"speaker": "פרקליט מדינה", "text_he": "שירותי הביטחון העריכו שיש סכנה ממשית לאלימות.", "text_ru": "Службы безопасности оценили, что существует реальная угроза насилия."}, {"speaker": "עו״ד עותר", "text_he": "\"סכנה ממשית\" היא טענה רחבה מדי. אפשר לטעון אותה תמיד.", "text_ru": "«Реальная угроза» — слишком широкое утверждение. Его можно выдвигать всегда."}, {"speaker": "שופטת", "text_he": "האם בדקתם אמצעי חלופי — למשל, העברת ההפגנה למקום אחר?", "text_ru": "Рассматривали ли вы альтернативное средство — например, перенос демонстрации?"}, {"speaker": "פרקליט מדינה", "text_he": "הוצעו חלופות, אך העותרים סירבו.", "text_ru": "Альтернативы были предложены, но заявители отказались."}, {"speaker": "עו״ד עותר", "text_he": "כי המקום הוא חלק מהמסר. הפגנה מול הכנסת אינה כהפגנה בפארק.", "text_ru": "Потому что место — часть послания. Демонстрация у Кнессета — не то же, что в парке."}, {"speaker": "שופטת", "text_he": "פסק הדין יינתן בעוד שבוע. תודה לשני הצדדים.", "text_ru": "Решение будет вынесено через неделю. Спасибо обеим сторонам."}]', '[{"word": "בית המשפט העליון", "translation": "Верховный суд", "transliteration": "бейт хамишпАт хаэльйОн"}, {"word": "עותר", "translation": "заявитель (петиционер)", "transliteration": "отЕр"}, {"word": "פרקליט מדינה", "translation": "гос. прокурор", "transliteration": "праклИт мединА"}, {"word": "מידתיות", "translation": "соразмерность", "transliteration": "мидатиЮт"}, {"word": "פסק דין", "translation": "приговор/решение суда", "transliteration": "псАк дин"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (239, 6, 'ביקורת עמיתים: מאמר בהיסטוריה', 'Два историка обсуждают рукопись статьи перед публикацией.', '[{"speaker": "בוחן א", "text_he": "המאמר מציע תזה חדשנית: שהציונות הייתה גם תנועה פוסט-קולוניאלית.", "text_ru": "Статья предлагает новаторский тезис: сионизм был также постколониальным движением."}, {"speaker": "בוחנת ב", "text_he": "מעניין, אבל המקורות חד-צדדיים. חסרים מקורות ערביים ובריטיים.", "text_ru": "Интересно, но источники односторонни. Не хватает арабских и британских источников."}, {"speaker": "בוחן א", "text_he": "מסכים. והפרק על תנועת העבודה חלש מתודולוגית.", "text_ru": "Согласен. И глава о рабочем движении методологически слабая."}, {"speaker": "בוחנת ב", "text_he": "הוא משתמש במושגים אנכרוניסטיים — מיישם מסגרות של 2020 על 1920.", "text_ru": "Он использует анахронистические понятия — применяет рамки 2020 года к 1920-му."}, {"speaker": "בוחן א", "text_he": "זה הסיכון של היסטוריה רוויזיוניסטית: להקרין את ההווה על העבר.", "text_ru": "Это риск ревизионистской истории: проецировать настоящее на прошлое."}, {"speaker": "בוחנת ב", "text_he": "עם זאת, יש כאן תובנות מקוריות. אני ממליצה על תיקונים גדולים ושליחה חוזרת.", "text_ru": "Тем не менее, здесь есть оригинальные инсайты. Я рекомендую серьёзные исправления и повторную подачу."}, {"speaker": "בוחן א", "text_he": "מסכים. המאמר שווה פרסום — אחרי עבודה רצינית.", "text_ru": "Согласен. Статья стоит публикации — после серьёзной доработки."}]', '[{"word": "ביקורת עמיתים", "translation": "рецензирование", "transliteration": "бикОрет амитИм"}, {"word": "תזה", "translation": "тезис", "transliteration": "тЕза"}, {"word": "אנכרוניסטי", "translation": "анахронистический", "transliteration": "анахронИсти"}, {"word": "רוויזיוניסטי", "translation": "ревизионистский", "transliteration": "ревизионИсти"}, {"word": "תובנות", "translation": "инсайты/прозрения", "transliteration": "тованОт"}]', NULL);
INSERT INTO public.dialogues (id, level_id, title, situation_ru, lines_json, vocabulary_json, audio_url) VALUES (240, 6, 'ניתוח בלשני: עברית כשפה חיה', 'Два лингвиста обсуждают особенности современного иврита.', '[{"speaker": "בלשנית", "text_he": "העברית המודרנית היא תופעה ייחודית: שפה שהוחייתה ממוות.", "text_ru": "Современный иврит — уникальный феномен: язык, воскрешённый из мёртвых."}, {"speaker": "בלשן", "text_he": "\"מוות\" זו הגזמה. העברית תמיד הייתה בשימוש — בכתיבה, בתפילה.", "text_ru": "«Смерть» — преувеличение. Иврит всегда использовался — в письме, в молитве."}, {"speaker": "בלשנית", "text_he": "נכון, אבל לא כשפת אם. החידוש של בן-יהודה הוא ההפיכה לשפת יומיום.", "text_ru": "Верно, но не как родной язык. Новшество Бен-Иехуды — превращение в язык повседневности."}, {"speaker": "בלשן", "text_he": "ומה קרה בתהליך? העברית ספגה השפעות מיידיש, מערבית, מרוסית.", "text_ru": "И что произошло в процессе? Иврит впитал влияния идиша, арабского, русского."}, {"speaker": "בלשנית", "text_he": "המבנה נשאר שמי, אבל הפרוזודיה — אירופית. הנגינה אינדו-אירופית.", "text_ru": "Структура осталась семитской, но просодия — европейская. Интонация индоевропейская."}, {"speaker": "בלשן", "text_he": "גדעון גולדנברג טען שהעברית החדשה היא \"שפה מעורבת\" — גוף שמי, נשמה אירופית.", "text_ru": "Гидеон Гольденберг утверждал, что новый иврит — «смешанный язык» — семитское тело, европейская душа."}, {"speaker": "בלשנית", "text_he": "ודווקא זה מה שעושה אותה כל כך מעניינת. היא מעבדה חיה של שינוי לשוני.", "text_ru": "И именно это делает его таким интересным. Он — живая лаборатория языковых изменений."}]', '[{"word": "בלשנות", "translation": "лингвистика", "transliteration": "балшанУт"}, {"word": "פרוזודיה", "translation": "просодия", "transliteration": "прозОдия"}, {"word": "שמי", "translation": "семитский", "transliteration": "шемИ"}, {"word": "שפת אם", "translation": "родной язык", "transliteration": "сфАт эм"}, {"word": "שפה מעורבת", "translation": "смешанный язык", "transliteration": "сафА меурЕвет"}]', NULL);
